-- Poems batch 310
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('c761c8d4-28ee-409a-87bb-a4296a105386','侯灘','沈遼','宋','宋诗','song-poetry','','[]','江流激激過侯灘，更上山頭看打盤。',32,'全唐诗/poet.song.40000.json','["江流激激過侯灘，更上山頭看打盤。", "百歲老人親擊鼓，城中憂樂不相干。"]'),
('e7627240-6a49-4ee7-b250-aa8afa410213','書堂寺','沈遼','宋','宋诗','song-poetry','','[]','蒼山古木書堂寺，北下湘川百餘步。',64,'全唐诗/poet.song.40000.json','["蒼山古木書堂寺，北下湘川百餘步。", "誰云往來傾世界，至今人道安禪處。", "豈無驚蛇與飛鳥，後來那復知其趣。", "我身不知今是不，空記名稱你常住。"]'),
('676eaa78-9578-4d50-ba62-bc02e49f22cd','日道','沈遼','宋','宋诗','song-poetry','','[]','日道纒南復纒北，蓬戶長開少人迹。',32,'全唐诗/poet.song.40000.json','["日道纒南復纒北，蓬戶長開少人迹。", "三噫七哀非我意，我身乃是投荒客。"]'),
('22ad3634-0ae2-46a0-9ebd-430e2e0e7d09','龐公','沈遼','宋','宋诗','song-poetry','','[]','襄陽龐公少檢束，白頭女冠亦不秃。',96,'全唐诗/poet.song.40000.json','["襄陽龐公少檢束，白頭女冠亦不秃。", "世所奔趨我獨棄，我已有餘彼不足。", "鹿門有月樹下行，江漢無風舟上宿。", "不識當時捕魚客，但愛長康畫金粟。", "金粟杜口不復言，龐公爲人不夸俗。", "東西有人問老夫，但道明燈照茆屋。"]'),
('cbe346f6-e4ab-46db-a058-468058a0ed6e','五言','沈遼','宋','宋诗','song-poetry','','[]','五言七言正兒戲，三行五行亦偶爾。',96,'全唐诗/poet.song.40000.json','["五言七言正兒戲，三行五行亦偶爾。", "我性不飲豈解醉，正如春風弄羣卉。", "四十年來目幻事，老去何須别愚智。", "古人不生亦不滅，吾今不作亦不止。", "寄語悠悠世上人，浪生浪死一埃塵。", "洗墨無池筆無塚，時亦作戯怡吾真。"]'),
('1c751151-6f8b-4e46-b8ee-c5bedf642054','種花','沈遼','宋','宋诗','song-poetry','','[]','世事流光同一汙，天涯白髪未還家。',32,'全唐诗/poet.song.40000.json','["世事流光同一汙，天涯白髪未還家。", "慇勤更種庭前草，爲看秋來一似花。"]'),
('521961e0-4dee-4ec0-8dbb-769569d42817','送僧應參禅','沈遼','宋','宋诗','song-poetry','','[]','古寺窮居歲月移，東岡西崦不相知。',64,'全唐诗/poet.song.40000.json','["古寺窮居歲月移，東岡西崦不相知。", "從來但識羣羊讖，不道亦逢獅子兒。", "瀟水葷羶從此隔，雪山消息更何疑。", "明年我過湘西去，問訊山前我爲誰。"]'),
('a2461a52-175c-4177-ba1a-46b082b39b60','花藥塵外亭','沈遼','宋','宋诗','song-poetry','','[]','導師昔示化，靈墟肇開鑿。',120,'全唐诗/poet.song.40000.json','["導師昔示化，靈墟肇開鑿。", "山間百草花，救病皆爲藥。", "爾來三百歲，法音亦間作。", "爲人布福時，随緣四豐樂。", "然師法王嗣，金錫中天落。", "海衆蚤知歸，天龍欣有託。", "鼎新金布地，煙雲助回薄。", "岣嶁對岑寂，瀟湘供盥濯。", "維摩老且病，身世兩無著。", "行期過丈室，爲我探泉壑。"]'),
('d9926bfd-4937-47e9-9d8a-263b8bfeb640','踏盤曲二首  其一','沈遼','宋','宋诗','song-poetry','','[]','湘江東西踏盤去，青煙白霧将軍樹。',64,'全唐诗/poet.song.40000.json','["湘江東西踏盤去，青煙白霧将軍樹。", "社中飲食不要錢，樂神打起長腰鼓。", "女兒带鐶著縵布，歡笑捉郎神作主。", "明年二月近社時，載酒牽牛看父母。"]'),
('f02c58ce-7167-4b3d-871d-c70a05573fdf','踏盤曲二首  其二','沈遼','宋','宋诗','song-poetry','','[]','胡盧笙，不着簧。',64,'全唐诗/poet.song.40000.json','["胡盧笙，不着簧。", "細腰鼓，三尺長。", "吹笙擊鼓山之旁，噭跳宛轉樂盤王。", "盤王死來三千年，古曲舊詞至今傳。", "山祥水氣不斷處，壞木燒作兜婁煙。"]'),
('1198d2b5-54bd-4960-b3eb-53d8a35cc7b6','山西','沈遼','宋','宋诗','song-poetry','','[]','山西誰家桃李樹，半是少年行樂處。',32,'全唐诗/poet.song.40000.json','["山西誰家桃李樹，半是少年行樂處。", "去年花謝今年開，惟有人生不如故。"]'),
('93997be3-07fc-46ef-bfe8-4cd2522f3ed2','庭下','沈遼','宋','宋诗','song-poetry','','[]','庭下亂生春草花，夭紅不稱野人家。',32,'全唐诗/poet.song.40000.json','["庭下亂生春草花，夭紅不稱野人家。", "漫開漫落無人折，留得孤根數寸槎。"]'),
('a01516bc-882a-484b-86e2-8a56e4d0a028','次韻答楚興','沈遼','宋','宋诗','song-poetry','','[]','落莫餘生何可同，正如枯死道邊蓬。',32,'全唐诗/poet.song.40000.json','["落莫餘生何可同，正如枯死道邊蓬。", "随風流轉惟無定，定處由來自性空。"]'),
('1ca0cf40-e664-41e7-b731-84b4bf64ee90','郊外馬嘶','沈遼','宋','宋诗','song-poetry','','[]','春草滿空春水流，土人放馬白蘋洲。',32,'全唐诗/poet.song.40000.json','["春草滿空春水流，土人放馬白蘋洲。", "細風遲日嘶鳴處，遥憶金明池上游。"]'),
('e75affe7-4897-4d33-acb5-04a16b6685c8','景星觀','沈遼','宋','宋诗','song-poetry','','[]','南津古觀已半摧，老松千尺黄蒲開。',64,'全唐诗/poet.song.40000.json','["南津古觀已半摧，老松千尺黄蒲開。", "禮斗層壇故基在，真人一去終不來。", "終不來兮往何許，朝瀛洲兮莫玄圃。", "應笑營營世上人，轉手已爲泉下土。"]'),
('f814d549-1cd4-4620-8f54-697c255c2f44','花殘','沈遼','宋','宋诗','song-poetry','','[]','花發花殘都不知，誰将白髪更題詩。',32,'全唐诗/poet.song.40000.json','["花發花殘都不知，誰将白髪更題詩。", "山西日永無多事，閑看樵夫數局棋。"]'),
('a7983153-81ec-4ebc-8b4a-0aa33e54a565','寒山','沈遼','宋','宋诗','song-poetry','','[]','黄牛巖下水彎彎，葛帔籃輿自往還。',32,'全唐诗/poet.song.40000.json','["黄牛巖下水彎彎，葛帔籃輿自往還。", "不是湘纍莫相問，祗應枯瘁似寒山。"]'),
('c94d8d73-b5f7-4f00-9323-2324a9fb7aa4','過商翁墓','沈遼','宋','宋诗','song-poetry','','[]','征南名地蚤相知，老向瀟湘看立碑。',64,'全唐诗/poet.song.40000.json','["征南名地蚤相知，老向瀟湘看立碑。", "壮節獨馳南嶠事，古風不括故山詩。", "愁煙半鏁黄茅壠，部曲誰尋舊将旗。", "遥矚蕪江想靈氣，孤雲落日不勝悲。"]'),
('1f203ced-cac7-47cb-b273-82eaa734a914','澹山巖','沈遼','宋','宋诗','song-poetry','','[]','昔造陽羡二洞天，我生已當謝人間。',252,'全唐诗/poet.song.40000.json','["昔造陽羡二洞天，我生已當謝人間。", "爾來投裔亦無事，澹山巖下欣躋攀。", "羣峰駕肩來，江水會前灣。", "靈氣縚洞口，夐如寶陁山。", "輦道轉西升，斗入初無艱。", "翡翠鑿穹廬，略與天相彎。", "寛廣容萬席，清潤非人寰。", "東南豁陽明，仰視如含環。", "青蘿傅喬木，亦有敗葉黫。", "造化遺玉像，其人清且閑。", "巧工或可爲，誰能陟巔顔。", "秦時隱君去成仙，空留石床水雲般。", "藥爐不復九霞覆，唯餘渥赭繁茅菅。", "至行禅師化巨蟒，好事太守驅羣頑。", "崇壇峭罅皆可躡，三穴旁出門無關。", "壁間玉乳化爲石，何術可煮完衰孱。", "恨無仙骨空盤桓，欲留未可終當還。", "僕夫告余趣歸馭，落日西下雲斑斑。"]'),
('eaccc354-69ec-45cc-8881-72314b50f341','愚溪','沈遼','宋','宋诗','song-poetry','','[]','榜舟下瀟江，泛泛入愚溪。',168,'全唐诗/poet.song.40000.json','["榜舟下瀟江，泛泛入愚溪。", "昔人不復見，秋草空萋萋。", "委蛇望僧園，雲屋倦攀躋。", "林髙日氣薄，磔磔鳴山雞。", "倒景相吐呑，清明合致犂。", "昔人悵投裔，感事多悲悽。", "北邙一抔土，榮辱方今齊。", "人生無百年，外物安可迷。", "谿水瀉石間，喧喧如鼓鼙。", "了無人世想，粗可休天倪。", "吾亦被黯黮，東山飽蒿藜。", "二年已數至，屐齒連山溪。", "行亦歸三吳，孤猿安故棲。", "它年若有夢，邂逅識江西。"]'),
('ccd24b4b-942d-49ae-8361-27833e205a33','石角山','沈遼','宋','宋诗','song-poetry','','[]','步屐出東津，遥跂石角山。',132,'全唐诗/poet.song.40000.json','["步屐出東津，遥跂石角山。", "山迴道亦轉，卓犖煙雲間。", "何人峻重閣，三休直孱顔。", "吾想造化功，爲此肅神姦。", "嵌巖或中穴，特立氣甚頑。", "此角誰可折，寧當混塵寰。", "游士何足知，但剥苔蘚斑。", "西首望城闉，羣山合如環。", "下臨有鼻道，落日行人還。", "楓葉秋欲丹，蕪江逗潺潺。", "重游何用戒，蓬户初無關。"]'),
('ce11e7f8-1a8f-4b67-ad36-8b62b49179b8','湘中宿臺步寺','沈遼','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','湘源初甚微，屢挹不滿缸。',96,'全唐诗/poet.song.40000.json','["湘源初甚微，屢挹不滿缸。", "比至臺步虚，泛泛爲長江。", "虚頭市初集，魚豆皆成樁。", "夷獠不識人，笑鬻彘與厖。", "綠荷竭苞苴，人散誰復撞。", "鷗鳥亦來下，酒斾停空杠。", "我來憩桑門，竹户映蓬窗。", "夜寢那可寐，江流正淙淙。"]'),
('8ac700e7-18ab-4a67-ba7a-9a28550d3522','泛舟上湘口館','沈遼','宋','宋诗','song-poetry','','[]','瀟水漫南來，湘川趣東下。',96,'全唐诗/poet.song.40000.json','["瀟水漫南來，湘川趣東下。", "二水始相會，清豪不相藉。", "山迴石瀬出，木老脩煙嫁。", "泛泛白蘋洲，林風媚如畫。", "宿昔感騷憤，幽興遥相借。", "不謂垂老年，覉孤窮山舍。", "潮來刺舟去，孤月臨清夜。", "安得跨鯨魚，不復人間化。"]'),
('2e198e8d-3a45-4bb6-b551-e3a8d193edce','法華石門','沈遼','宋','宋诗','song-poetry','','[]','窮居謝世故，久厭夷落喧。',96,'全唐诗/poet.song.40000.json','["窮居謝世故，久厭夷落喧。", "出亦何所適，往往傲石門。", "石門在山腰，東西列祇園。", "崈崖三折上，蒼壁煙嵐昏。", "松下閴無人，唯有風中幡。", "安得嵇阮流，相與抗玄言。", "羣鶚感余顙，日暮噪陰樊。", "吾衰那復辨，孤吹拂歸軒。"]'),
('23e28fc7-4285-4475-8cce-5547306bccab','禅僧巖','沈遼','宋','宋诗','song-poetry','','[]','瀟湘山水窮欲偏，最後乃得禅僧巖。',192,'全唐诗/poet.song.40000.json','["瀟湘山水窮欲偏，最後乃得禅僧巖。", "禅僧成道久已化，獨有崖崿青巉巉。", "降身入洞不甚險，突兀三室誰彫劖。", "東西有道若蛇竇，白雲羃羃門無緘。", "持火旁行不知際，七穿八竅遥相銜。", "涓涓乳泉白如雪，由來此地殊仙凡。", "主人引我復深入，行指岰穴尤嵌巖。", "中間石鼓有異響，擊拊想可參韶咸。", "吾身久病苦下溼，復畏神怪來邀攙。", "直趣出洞上南巘，豁若巨海張雲帆。", "山花斕斑出竹杪，亦有禽鳥聲諵諵。", "欲還未可復小駐，日脚已過東岡杉。"]'),
('212282fd-e5fd-4f47-a0cb-0188e32796dd','奉謝上官令詩卷','沈遼','宋','宋诗','song-poetry','','[]','一軸新詩錦不如，何爲輕易贈狂夫。',32,'全唐诗/poet.song.40000.json','["一軸新詩錦不如，何爲輕易贈狂夫。", "巴山楚水無窮勝，不必王維更畫圖。"]'),
('ae65c79a-6fbf-44be-8e89-9460e6e12bcf','贈别子瞻','沈遼','宋','宋诗','song-poetry','','[]','平生雅游眉陽客，五年不見鬚已白。',160,'全唐诗/poet.song.40000.json','["平生雅游眉陽客，五年不見鬚已白。", "借田東坡在江北，芟夷蓬蒿自種麥。", "相逢不盡一樽酒，故態那復論歡戚。", "手抱阿武勸餘瀝，維摩老夫失定力。", "老夫寂寂出三湘，更欲卜居池水陽。", "薄田止須數十畝，田上更樹麻與桑。", "老來正苦迫生事，清明雖近猶可秧。", "罷亞若可博乾麨，以無易有遥相望。", "我舟即行不可駐，欲卜後會誠茫茫。", "他時有信若可寄，不用辛苦爲詩章。"]'),
('89345551-dfca-47e4-87e7-c2a49ef04f49','題子瞻雪堂即次前韻','沈遼','宋','宋诗','song-poetry','','[]','眉陽先生齊安客，雪中作堂愛雪白。',128,'全唐诗/poet.song.40000.json','["眉陽先生齊安客，雪中作堂愛雪白。", "堂下佳蔬已數畦，堂東更種連坡麥。", "不能下帷學董相，何暇悲歌如寗戚。", "布裘藜杖自來往，山禽幽弄均春力。", "桉上詩書羅縑緗，爐中燒藥笑王陽。", "晨炊且糴北倉粟，冬服已指山前桑。", "南岡差髙多種橘，迤北漸下宜栽秧。", "北鄰亦有放達士，道路壺榼常相望。"]'),
('dbaf9c7f-704a-410c-86ea-e29ddfe5ba74','德相送荆公三詩用元韻戯爲之','沈遼','宋','宋诗','song-poetry','','[]','幽居卧山間，不與世相接。',288,'全唐诗/poet.song.40000.json','["幽居卧山間，不與世相接。", "餘生委蒲柳，滯想遺空劫。", "德相蚤相親，顧我情未厭。", "數枉南堤步，更引青谿艓。", "相見亦何事，坐對羣峰疊。", "春陽始萌動，煙嵐森劍鋏。", "亷纖數日雨，萬里浮塵浥。", "赤白未殘花，修穠半敷葉。", "行招老僧語，遥瞩東田饁。", "窮崖歷可造，峻流誰敢涉。", "衰齡易生倦，幽巖就調攝。", "德相知我憊，雙眸困垂睫。", "髙詠楚公作，欲引維摩箑。", "初聞未甚解，静聽疑可獵。", "有如太華峰，跛躄豈易躡。", "不知泛滄海，何力施舟楫。", "遥窺土山勝，昔乃文靖業。", "二公雖異時，名德遠相躐。", "山川若有待，風物增悲惵。", "未知蔡侯履，孰與支郎蹀。", "勝遊可概見，筆力方峨嶪。", "更紓别後情，琅琅鋪簡牒。", "倡髙必和寡，排比安且帖。", "簫竽合古律，宫商自諧協。"]'),
('b8e0e07a-2589-4b0c-a891-a202feb96582','德相所示論書聊復戯酬','沈遼','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','野舍老餘生，雅尚今已愜。',288,'全唐诗/poet.song.40000.json','["野舍老餘生，雅尚今已愜。", "不逃世憂患，餘事寄巾蹀。", "行尋青山轉，坐對青山疊。", "欲随白雲去，儻與幽人接。", "盤桓太清洞，悵望長江艓。", "昔時古錦嚢，今還白羽箑。", "不復叔夜煆，真得孫登攝。", "九華一枯藜，青溪一孤楫。", "得喪苟自達，死生安足惵。", "朱顔久不駐，白髪何爲鑷。", "羣物自流轉，吾生寄天燮。", "德相屡相過，老夫寧足躡。", "由來廢井水，不如長劍鋏。", "往往論書法，軒軒兩目睫。", "中郎石經在，元常表軍捷。", "漢魏多傳人，至宋有遺帖。", "唐室初最盛，漸衰自中葉。", "歐虞緬誰嗣，顔桞何足躐。", "篆籕昔難工，草聖誰敢輙。", "巨山作散隸，雄古掀龍鬛。", "貞觀喜飛白，凌厲騰春蝶。", "豈特豁神觀，直可祛鬼魘。", "古人有所寓，天性難必協。", "所志有小大，其材有勇怯。"]'),
('48f1f535-53cb-44bf-94b6-a8e8c2803e6c','德相惠新茶復次前韻奉謝','沈遼','宋','宋诗','song-poetry','','[]','暑雨闇窮山，道滑不可躡。',288,'全唐诗/poet.song.40000.json','["暑雨闇窮山，道滑不可躡。", "隱几念投老，葛衣坐揺箑。", "林端使者至，乃得德相帖。", "佳惠致新茗，遠來自閩笈。", "吾聞北苑勝，不與羣山接。", "山下幾千家，以此爲生業。", "新陽一日至，東風方獵獵。", "百草尚勾甲，靈芽已先捷。", "所採僅毛髪，厥工巧烹燮。", "甘泉列盎釜，熾炭浩旁疊。", "修竹爲之規，黄金爲之梜。", "形摹各臻妙，製作易妥帖。", "至尊所虚佇，守臣方惕懾。", "其上爲虬龍，蜿蜒奮鱗鬛。", "稍降乃交鳯，文翼相盤跕。", "函封趣北道，驛使互防挾。", "四方老金玉，擬議誰敢輙。", "屹屹健士儋，飄飄迅溪艓。", "穀雨不及潤，權門已盈篋。", "带𩊓體正方，葵華角仍擪。", "始傳盛王鄭，後来止游葉。", "大爲權勢迫，小或盗賊刼。", "其間起鬭奪，亦數冒刑槢。", "南夷出重購，不憚浮海楫。"]'),
('d3f1286e-587f-4167-9107-51ea1c9351d7','與德相遊雲光','沈遼','宋','宋诗','song-poetry','','[]','方駕出齊山，五月未甚暑。',144,'全唐诗/poet.song.40000.json','["方駕出齊山，五月未甚暑。", "遥瞻六峰道，修烟莽如禇。", "浮屠在山半，卜築氣象古。", "松風下石竇，陰泉鳴竹塢。", "堂堂老禪子，遊方遍中土。", "十年不下山，不及朝市語。", "拂雲有幽步，凌空開峻宇。", "登山復望山，六峰艶如舞。", "時當一陰候，陽氣驕且舞。", "龍蛇伏草莽，往往暴爲雨。", "由兹向揺落，流光不足數。", "籃輿當復來，相與同支許。"]'),
('35faecd6-5ea7-43a9-92c1-3462a96b63e0','送夏八赴南陵','沈遼','宋','宋诗','song-poetry','','[]','老夫久客三湘水，歸來喜食江南鮆。',192,'全唐诗/poet.song.40000.json','["老夫久客三湘水，歸來喜食江南鮆。", "白雲猶識舊山川，青眼多慚老兄弟。", "當時親友半不在，中表相存如夢寐。", "公酉冡上春草生，白眉始與君相際。", "髙堂老人八十一，不間衰微論末契。", "招我卜宅居其旁，自顧麋鹿何由係。", "春風引我齊山行，穿雲踏石構巢橧。", "相見常無一樽酒，山中枯淡令人憎。", "凉風未至正苦熱，君忽佩印臨南陵。", "南陵相去五舍近，馬蹄車轍常相仍。", "安輿綵衣得榮飬，況有大舸如飛鵬。", "步上南山一延首，江風浩浩雲騰騰。"]'),
('7077847c-cfc7-4091-aff1-699e114a6c3f','青谿','沈遼','宋','宋诗','song-poetry','','["\u897f\u6e56"]','青谿八月老菰蒲，孤吹修煙出水隅。',32,'全唐诗/poet.song.40000.json','["青谿八月老菰蒲，孤吹修煙出水隅。", "誰問西湖少年樂，閑将世事捋蒼鬚。"]'),
('12d758a1-3f82-42ed-b0e0-566655e4a643','初創二山','沈遼','宋','宋诗','song-poetry','','[]','左山叢古木，縈带多美竹。',288,'全唐诗/poet.song.40000.json','["左山叢古木，縈带多美竹。", "右山少平地，硱磳斷蒼玉。", "於此豈無竹，蕭疏倚巖谷。", "上參九頂道，俯浸青谿澳。", "於彼豈無石，嵌崖大如屋。", "景業讀書處，基構有遺躅。", "始吾購二山，何爲不相属。", "中間古蘭若，臺觀當山腹。", "巖洞九十七，龍蛇所潛伏。", "昔人作軒榭，髙深寄林麓。", "我乃巢西崦，手自親鋤斸。", "青溪漫無際，島嶼相重複。", "雨餘山更佳，春流漲平峪。", "下矙池陽市，修煙弄芬馥。", "大江天上來，淮山點眉綠。", "老夫豈無意，落日傲鴻鵠。", "東嶺亦誅茆，小庵粗容足。", "六峰引南睇，九華勢相續。", "白雲與誰期，千載媚平陸。", "清曠無俗韻，修明資遠目。", "去秋已種麥，今春復栽粟。", "野老豈余欺，東坡幸膏沐。", "二山誰與適，最與枯藤熟。", "相見詎無人，顧我真麋鹿。"]'),
('0c87da17-3aa5-4325-95bf-3ed0d862b6d5','奉贈芝師參總禪師','沈遼','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','欲識東林路，匡廬第一山。',48,'全唐诗/poet.song.40000.json','["欲識東林路，匡廬第一山。", "昔人開勝地，大士啟禪關。", "鷲嶺不遺法，虎谿誰敢攀。", "因師訪消息，爲寄九峰間。"]'),
('05f5e084-47ee-45e4-93a8-0220a2329088','奉贈行師參慎禪師','沈遼','宋','宋诗','song-poetry','','[]','觀音二十五圓通，止在禪師一指中。',32,'全唐诗/poet.song.40000.json','["觀音二十五圓通，止在禪師一指中。", "金鉢直随流水去，不須芒屩更西東。"]'),
('29eab65d-d74d-4064-be4f-4ffe7c372210','初泊磁湖','沈遼','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','歸舟不解洞庭帆，舟上騷人雪滿簪。',32,'全唐诗/poet.song.40000.json','["歸舟不解洞庭帆，舟上騷人雪滿簪。", "小駐武昌江北岸，春風今夜泊江南。"]'),
('823613b8-d881-42f5-8a93-104cbed9881e','感昔游','沈遼','宋','宋诗','song-poetry','','[]','江南二月春水生，不如春草滿山青。',64,'全唐诗/poet.song.40000.json','["江南二月春水生，不如春草滿山青。", "江南故人半不在，不如春水似有情。", "三年放逐三湘客，今日歸來頭欲白。", "欲尋舊游心更懶，青山閉門長寂寂。"]'),
('9dd17c27-7284-4666-8af5-2595cb994f23','無生','沈遼','宋','宋诗','song-poetry','','[]','昔别江南去，三湘多煙霧。',48,'全唐诗/poet.song.40000.json','["昔别江南去，三湘多煙霧。", "今從三湘歸，江南正如故。", "不須下照水，還驚我非汝。", "白髪如秋蓬，已得無生路。"]'),
('cfc0975b-b446-469e-a5f7-82f10dc40d8a','五言贈别博明二古','沈遼','宋','宋诗','song-poetry','','[]','三年客零陵，所得惟二古。',192,'全唐诗/poet.song.40000.json','["三年客零陵，所得惟二古。", "彼室雖屢空，髙誼詒先矩。", "顧我被遷斥，數過南山塢。", "攘臂豈無人，久要何足數。", "君無一樽酒，我無一柈黍。", "相見動移晷，不及市朝語。", "博古練世故，黑白誰敢侮。", "明古喜方術，虚懷安疾苦。", "古人處其道，足以察臧否。", "何用輕薄兒，口舌賣州府。", "度直始詩書，襟靈各翹楚。", "陰德有陽報，終當大門户。", "老夫趣北歸，顧予求所處。", "昏悖何可言，愧汗欲如雨。", "詩人慎加飡，斯意亦可取。", "不忘雙鯉魚，遥想瀟湘渚。"]'),
('9f988f96-d7e3-4967-8e2c-92075e6b6627','七言奉送潤守之永静','沈遼','宋','宋诗','song-poetry','','[]','昔年持檄向朔方，九月踏冰渡河梁。',256,'全唐诗/poet.song.40000.json','["昔年持檄向朔方，九月踏冰渡河梁。", "夜入銅臺天欲雪，北風慘淡沙塵黄。", "今年江南秋已半，出送車騎江之陽。", "江邊賓從坐揮汗，赤日掛木鳴蜩螗。", "欲知朔南氣候異，由來道路山川長。", "使君腰組上北道，一亭一堠遥相望。", "出近入勞豈知遠，方舟結駟本不忙。", "往時尊公帥陜右，名姓久已威戎羌。", "想聞公子千騎出，北部應已逃名王。", "青榆白柳千里肅，誰敢牧馬来邊疆。", "當時公子面如月，爾來使君鬚带霜。", "明年朔方春雪凍，爲憶江南梅萼芳。", "平居秋浦釣赬鯉，何如榆關封白羊。", "朝廷太平四方静，聖武神功由廟堂。", "三年瓜期當受代，指麾舍人催治装。", "疏公欲向九華老，野夫相望齊山旁。"]'),
('6fad4b02-ca23-4d7b-8f1d-4dd9dccb659a','寄博古','沈遼','宋','宋诗','song-poetry','','[]','齊山落景覆青谿，谿上幽人半病羸。',32,'全唐诗/poet.song.40000.json','["齊山落景覆青谿，谿上幽人半病羸。", "曾作瀟湘江上客，水風山月合相知。"]'),
('a62a741e-87cc-453b-8ee6-e26086b94f53','送超禪師','沈遼','宋','宋诗','song-poetry','','[]','老夫結庵南山前，此生終不蹈世緣。',128,'全唐诗/poet.song.40000.json','["老夫結庵南山前，此生終不蹈世緣。", "邂逅雲門亦何言，白雲無心媚青天。", "禪師来自廬江壖，一住秋浦逾十年。", "不露鋒角常坦然，四方禪客芒屩穿。", "朝来擊鼓登法筵，一鉢出置行路邊。", "笑謝大衆如雲連，欲以此身老林泉。", "秋風飄飄江上船，想見玄沙扣船舷。", "諸方有人問病孱，爲道如今不參禪。"]'),
('1935678d-7d96-49f7-b10f-1200ee836762','居雲巢','沈遼','宋','宋诗','song-poetry','','[]','我昔泛歸艇，逍遥下湘川。',168,'全唐诗/poet.song.40000.json','["我昔泛歸艇，逍遥下湘川。", "願言覿開士，爲我斷攀緣。", "不識達摩老，誰将言句傳。", "幽林得邂逅，故步空囂然。", "邇来齊山下，乃在青谿邊。", "一徑雖甚微，松竹上參天。", "白雲本無迹，作巢類烏鳶。", "上下絕人籟，由來在山顛。", "朝炊一盂飯，夕寄一榻眠。", "委羸豈無事，亦爇爐中烟。", "久已淨諸業，自然忘盖纒。", "此身與此世，影響寄餘年。", "時有佳客至，相與傲林泉。", "客去後孤坐，隱隱風中絃。"]'),
('6eecc7bf-3617-42e6-9f1e-771a77c5c54b','奉送李大夫歸長沙','沈遼','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','秋潮夜落江爲墟，青谿茁茁生菰蒲。',224,'全唐诗/poet.song.40000.json','["秋潮夜落江爲墟，青谿茁茁生菰蒲。", "舟舫逍遥賓從疏，誰識長沙李大夫。", "十年持節使江吳，轉入七閩将漕車。", "道上狂賊未伏誅，少壮瘡痍官吏逋。", "公方疾驅布威德，朝廷發兵趣捕賊。", "兵多賊少即日降，公獨至今爲失職。", "白首飄然歸故國，由來仕宦終無極。", "借令得意任公卿，年迫桑榆心更惜。", "昔時柴車一束書，今日朱門百口食。", "大夫月奉三萬錢，何必要凃争埶力。", "野人結庵齊山傍，早歳曾爲門下客。", "不遺簪履惠相訪，顧我青山唯四壁。", "野人適自三湘來，布衣猶带湘山碧。", "公舟少駐洞庭下，盡洗都城塵土迹。"]'),
('cf14bfd7-51e7-4400-8aca-42b397a4918f','奉送世美歸陽羡','沈遼','宋','宋诗','song-poetry','','["\u957f\u6c5f", "\u592a\u6e56"]','我昔求爲陽羡令，輕舟已有鴟夷興。',192,'全唐诗/poet.song.40000.json','["我昔求爲陽羡令，輕舟已有鴟夷興。", "最愛銅棺山峻極，自結籃輿陟雲徑。", "銅棺山插南斗魁，下視羣峰如突犀。", "太湖千里在眉睫，髙深從此窮攀隮。", "欣然有意即獨往，眀月夜夜眠荆谿。", "當時便可跨黄鵠，何意人間同木雞。", "飄飄數年如一夢，爾來卜室齊山西。", "故人多謝姚夫子，數枉車馬來山蹊。", "秋風忽指陽羡去，欲脱黄綬躬鋤犁。", "人生衣食苟自足，何爲卑辱趣塵泥。", "田間九月白酒熟，鱸魚正肥多置篦。", "老夫爲君更破戒，臨風引領長江堤。"]'),
('5d089620-7403-494b-a5eb-2b0a64a0f92f','奉送次翁','沈遼','宋','宋诗','song-poetry','','[]','君爲秋浦令，我迺老遷客。',120,'全唐诗/poet.song.40000.json','["君爲秋浦令，我迺老遷客。", "相見雖不數，臨風若相得。", "老病捐世故，茆茨寄山脊。", "不識河陽花，豈有澹臺跡。", "山前逢野叟，人能頌休德。", "惠利春陽敷，清泠秋月白。", "前日解墨綬，青雲振鵬翼。", "枉駕一笑别，迴首幽林隔。", "人生幸逢時，功名不遺力。", "不煩别後問，我若南岡石。"]'),
('be36eb77-ce34-409d-ad84-f880da78536f','奉送眀雅師','沈遼','宋','宋诗','song-poetry','','[]','天竺山前十畝園，老夫久種彼土緣。',240,'全唐诗/poet.song.40000.json','["天竺山前十畝園，老夫久種彼土緣。", "草堂和尚指初禪，辯淨二士立我前。", "光明琉璃真金仙，修持內外常湛然。", "此心不轉今十年，手中一炷紫檀煙。", "孤峰飛來自西天，山間花木非世妍。", "彼諸佛子忘盖纒，吾知此地爲敬田。", "師子血乳如流泉，老夫廢斥去湘川。", "歸來江南已華顛，邂逅道人雙足纒。", "歷訪名山不憚煩，始自赤城滄海邊。", "一带復濟揚子川，直上鍾山長榻眠。", "南來不下涇溪船，步至秋浦方息肩。", "将窮祖山上淮壖，廬峰勝遊想翩翩。", "頂上終不巢烏鳶，亦不教觀談偏圓。", "公卿貴人喜相延，三尺枯木揮朱絃。", "人問佛意如何彈，此曲寂寥少人傳。"]'),
('e0559b6a-9830-4050-8062-a500884d8b18','清泠臺二絕句  其一','沈遼','宋','宋诗','song-poetry','','[]','山前繚繞白雲飛，山下溪流那復迴。',32,'全唐诗/poet.song.40000.json','["山前繚繞白雲飛，山下溪流那復迴。", "不向此間休歇去，寧将白髪汙塵埃。"]'),
('8d8a96c6-a4a5-4895-b7ea-d116dd4ec733','清泠臺二絕句  其二','沈遼','宋','宋诗','song-poetry','','[]','落日欲下清泠臺，月華已破東岡来。',32,'全唐诗/poet.song.40000.json','["落日欲下清泠臺，月華已破東岡来。", "誰道幽人得幽趣，老夫病眼不曾開。"]'),
('c9c45b54-a460-4524-9cd7-67bf6877e58d','奉送殊師利','沈遼','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','道人壮年曳長裾，挾策負藝西入都。',240,'全唐诗/poet.song.40000.json','["道人壮年曳長裾，挾策負藝西入都。", "欲步青雲不得途，不如濯足歸江湖。", "轉出淮山一麻襦，天柱峰前眀月孤。", "調御丈夫真我師，不復飲食形不枯。", "歸來故土弃妻孥，金玉百萬初若無。", "四十削髪入浮屠，有如浮雲飛太虚。", "達摩壁觀聊自娱，飲光苦行誰復如。", "河西将軍氣貌麤，一見猶如水中魚。", "南陽侍郎說詩書，爲築小庵即朝晡。", "諸漏已盡無復餘，此生安得爲世拘。", "不持一鉢上匡廬，秋風有意入三吴。", "天竺二山佛子居，赤城更在滄海隅。", "彼土觀緣小踟躇，何時復来尋老夫。", "清泠臺下茆已誅，爲留一榻待跏趺。", "不辭更貯一斛蜜，山間老境任蘧蘧。"]'),
('5836bc19-d52c-44d1-87e8-0a568bed70ba','伯翔父挽歌  其一','沈遼','宋','宋诗','song-poetry','','[]','平日並游客，老來相見稀。',48,'全唐诗/poet.song.40000.json','["平日並游客，老來相見稀。", "窮山忘我日，丹旐愴君歸。", "雲水野情在，風埃人事非。", "不知九泉下，誰與欵談圍。"]'),
('ab31d3fa-7e6c-4242-86ad-f242bb2c3eee','伯翔父挽歌  其二','沈遼','宋','宋诗','song-poetry','','[]','君向番禺去，何心瘴霧間。',48,'全唐诗/poet.song.40000.json','["君向番禺去，何心瘴霧間。", "雖能脱世網，恨不到鍾山。", "雅裁誰復見，幽尋步可攀。", "蒼茫大江上，應與月明還。"]'),
('609409fa-5d71-4ce3-9082-f286931884a9','左史洞','沈遼','宋','宋诗','song-poetry','','[]','萬古齊山石，誰開左史洞。',144,'全唐诗/poet.song.40000.json','["萬古齊山石，誰開左史洞。", "左史今何在，蒼崖本不動。", "履嶮下重壑，幽深鬼神總。", "石門絕世路，久爲塵泥擁。", "青天十畝地，巑岏如覆瓮。", "琬琰鑿屋壁，煙霞列梁棟。", "崕間不死藥，必非近時種。", "人去境常在，境與人爲重。", "欲觀疇昔意，幽禽發清哢。", "吾方寄淵寂，無礙亦無縱。", "手自翦荆棘，結茆當石空。", "長與麋鹿遊，不復人間夢。"]'),
('2e431837-ed54-4366-bfc9-b53441434bb7','寄老石','沈遼','宋','宋诗','song-poetry','','[]','老不在髪白，此態漸自迫。',96,'全唐诗/poet.song.40000.json','["老不在髪白，此態漸自迫。", "唯老不在我，寄老山前石。", "朝來石上坐，雲氣濕衣襞。", "夜就石上眠，月影照巖壁。", "何爲市南老，一歡復一戚。", "嘖嘖恨身老，更以身爲役。", "人言老且死，老死何足惜。", "昔人有至言，人命在一息。"]'),
('89fc0b39-c259-4381-bbc0-4a2a8528afcf','清泠臺','沈遼','宋','宋诗','song-poetry','','[]','清泠不在境，石嶠乃天成。',96,'全唐诗/poet.song.40000.json','["清泠不在境，石嶠乃天成。", "我無卜築功，爲臺亦強名。", "南山豈不佳，不見浮雲生。", "青谿淡無緒，何處賓鴻聲。", "誰云飲酒樂，正欲亂其眀。", "不知彈琴士，何用物外平。", "清冷亦強名，指象真砰砰。", "落落晞白髪，身世秋毫輕。"]'),
('d386206c-8087-429e-9e33-80096b028ca1','初耕東坡','沈遼','宋','宋诗','song-poetry','','[]','觀田東坡去，春事日已掲。',48,'全唐诗/poet.song.40000.json','["觀田東坡去，春事日已掲。", "耕破嶺上雲，鑿開巖下月。", "種我十畝粟，中有薇與蕨。", "優游卒歲事，山前梳秃髪。"]'),
('dc77bd5d-f27d-4f3c-b9fb-cb92bb0a398e','走筆酬亨甫所示二篇次韻和之  其一','沈遼','宋','宋诗','song-poetry','','[]','邯郸一夢黄粱熟，人生正如水中木。',160,'全唐诗/poet.song.40000.json','["邯郸一夢黄粱熟，人生正如水中木。", "不向黄塵瞠病目，悽悽猶寄一椽屋。", "物外日月無淹速，苟能自達萬事足。", "清眀神觀何可凟，不在文章夸滿腹。", "少壮已往誰能逐，此身正如車軑轂。", "始来齊山秋正肅，山間于于太古俗。", "穿雲作巢倚山麓，白髪老人誰檢束。", "山松森森半天綠，松下石色如蒼玉。", "古人清風那可續，夫子知我心所欲。", "飲光一衲隱窮谷，不復區區論往躅。"]'),
('fc701470-809f-4a6e-8475-26e8833d993f','走筆酬亨甫所示二篇次韻和之  其二','沈遼','宋','宋诗','song-poetry','','[]','老去不爲世網縈，我爲清冷亦假名。',160,'全唐诗/poet.song.40000.json','["老去不爲世網縈，我爲清冷亦假名。", "不識丹臺與赤城，此間寂寂無人聲。", "下視千里山川平，其間隱顯自晦眀。", "稽康作樂知未精，莊周能寧何用攖。", "有動不在彈與枰，至静何爲論攙槍。", "大飲不復論缸罌，一醉寧復更解酲。", "當如美璞含其英，不如不琢鳴琤琤。", "一去一來寄死生，寵辱外事何足驚。", "髙篇琅琅示我情，久已喪魄今載營。", "呼奴擁篲掃柴荆，當有佳客來此行。"]'),
('608c8073-68e7-4085-a2da-8f83b11973a8','送曾處善赴寶應尉','沈遼','宋','宋诗','song-poetry','','[]','我初隱身治蓬藟，餘生不復人間世。',272,'全唐诗/poet.song.40000.json','["我初隱身治蓬藟，餘生不復人間世。", "左山右山白雲上，一動一静浮塵外。", "齊山山上老夫庵，青谿谿南侍中第。", "朱顔公子不易識，短衣款段来相際。", "長堤相望雖甚遠，有意即行終不計。", "東鄰竹閣長夏熱，我構雲巢方自蔽。", "斕斑石臺始一眺，寂静庵基猶未薙。", "随雲步訪胡矮老，放懷止得殊師利。", "石橋寺前夜月冷，金雞峰下秋霖霽。", "君恃馬足下憚遠，我駕藍輿随處稅。", "六峰老師氣軒豁，九華雌山苦陰晦。", "庵前菜茹常不厭，城裏羊肩難數置。", "漫天風雪一暢目，滿榻春陽欣炙背。", "裴休自參黄蘗禪，梅福豈是南昌尉。", "相見終年已解空，分襟一别那成滯。", "拍江春水浮鷁首，萬里青天運鵬翅。", "順風莫寄南來書，老夫柴門多自閉。"]'),
('2eda6606-01a0-4336-a1a6-becf4fd8a1ad','五葉松','沈遼','宋','宋诗','song-poetry','','[]','在昔金池藏，遠自朝鮮來。',96,'全唐诗/poet.song.40000.json','["在昔金池藏，遠自朝鮮來。", "鉢中黄松實，散向庵前裁。", "迨今幾百年，已出白雲堆。", "瑩潤孔翠質，夭矯蒼龍媒。", "五岐媚夭葩，繁日半山開。", "秋風黄莆拆，玉粒謝徂徠。", "我語九華人，爲我乞條枚。", "還令古師意，長對清冷臺。"]'),
('044a4b42-1ff3-4f05-8e37-55baf57bf6fa','保寧太君挽詞  其一','沈遼','宋','宋诗','song-poetry','','[]','自適田閭樂，不随華寵移。',48,'全唐诗/poet.song.40000.json','["自適田閭樂，不随華寵移。", "龐恩開大邑，懿德鏤豐碑。", "古澤浩東注，仙山安不隳。", "髙門有孝嗣，巨痛感風枝。"]'),
('1db230af-16fb-4ab5-93ec-aa9c591096b5','保寧太君挽詞  其二','沈遼','宋','宋诗','song-poetry','','[]','繼奉荀門好，欽聞孟母賢。',48,'全唐诗/poet.song.40000.json','["繼奉荀門好，欽聞孟母賢。", "鳯雛持漢節，鶴壽享天年。", "丹旐映落日，新松含夕煙。", "正應黄壌下，稽首奉金仙。"]'),
('24cab816-9fcc-4ad3-955c-75686b31fc06','七言奉寄三衢趙少師','沈遼','宋','宋诗','song-poetry','','[]','浮石山前十里松，逍遥誰在白雲中。',64,'全唐诗/poet.song.40000.json','["浮石山前十里松，逍遥誰在白雲中。", "孔光蚤上三公印，衛武終爲百歲翁。", "禪客方談無上道，史官空記太平功。", "昔年翹館青衫客，非佛非心江水東。"]'),
('b0cc45c8-0002-442a-93c5-efd2639175e7','臺下  其一','沈遼','宋','宋诗','song-poetry','','[]','石梅落落欲黄時，細兩濛濛暗不開。',32,'全唐诗/poet.song.40000.json','["石梅落落欲黄時，細兩濛濛暗不開。", "數日不行臺下路，不知江水過山來。"]'),
('04b0b4b4-8ca4-4648-99bb-0de7eb52f3ea','臺下  其二','沈遼','宋','宋诗','song-poetry','','[]','石臺竹徑自天成，細草芳花随地生。',32,'全唐诗/poet.song.40000.json','["石臺竹徑自天成，細草芳花随地生。", "白髪老人無是處，一枝枯竹伴經行。"]'),
('7951e41f-23a8-492a-a281-89815e646d7a','江水二首  其一','沈遼','宋','宋诗','song-poetry','','[]','江水入谿來，無復故谿處。',72,'全唐诗/poet.song.40000.json','["江水入谿來，無復故谿處。", "山前浮大艑，前日行人路。", "遥堤半滅木，茅舍馴鷗鷺。", "始知南山遠，欲往不昜渡。", "世事寧有定，吾生若朝露。", "大海爲陸陵，昔人非大悟。"]'),
('a96b2235-f6ce-45c1-9d1d-d91bc429bf1f','江水二首  其二','沈遼','宋','宋诗','song-poetry','','[]','江水何漫漫，青山眇無畔。',72,'全唐诗/poet.song.40000.json','["江水何漫漫，青山眇無畔。", "欲尋青谿源，魚龍路已斷。", "今年刈麥早，無復爲人患。", "獨憐行路子，束馬髙山半。", "暑雨未當止，浮雲漭不散。", "行聽瀑泉鳴，葛帽臨幽澗。"]'),
('e1d525b2-6748-4020-a3e2-2164b03a475b','太古師彈琴示道輔','沈遼','宋','宋诗','song-poetry','','[]','我卧南山正如夢，朝来欲過左史洞。',160,'全唐诗/poet.song.40000.json','["我卧南山正如夢，朝来欲過左史洞。", "陽羡羽人惠相訪，三尺焦桐行自從。", "山上赤日烈如火，洞裏石泉凝作凍。", "揮手一奏離騷曲，促軫重作髙山弄。", "巖下隱隱白雲生，松風泠泠幽鳥哢。", "誰識襄陽魏夫子，緇衣遠來自崤雍。", "身出重圍戰不死，振翼江南若孤鳯。", "數日相從甘淡薄，不與人間同倥偬。", "夫子能知琴中趣，不叱老夫無世用。", "三人出洞日已斜，青山茫茫煙瞢瞢。"]'),
('8de09b00-161d-4877-8848-336cd7df2f00','寄題野翁無悶堂','沈遼','宋','宋诗','song-poetry','','[]','餘不衣冠故吾里，上下三吳一谿水。',224,'全唐诗/poet.song.40000.json','["餘不衣冠故吾里，上下三吳一谿水。", "方山峨峨出清泚，野翁卜築當山趾。", "春氣來自楊桞始，不待葩華著桃李。", "蓮生半卷未猒眼，已在紅蕖明鏡裏。", "秋風瑟瑟最先至，千里蒼煙接山起。", "車聲馬足不得到，無悶主人方隱几。", "想見野翁形氣古，少年詞華奮瓌瑋。", "春秋八十尚不倦，一篇一詠無餘晷。", "有材無用古所嘆，知命不憂方可喜。", "神完貌固得所養，從來軒冕如糠粃。", "嗟余跋疐亦可鄙，老向江南治蓬藟。", "隱身齊山絕人跡，獨與白雲同作止。", "白雲無心歸故山，故山自與野翁閑。", "聊上南岡一引領，落日已在桑榆間。"]'),
('c277223c-3832-4cbc-827b-35272db704df','奉酬巴陵令','沈遼','宋','宋诗','song-poetry','','["\u957f\u6c5f", "\u6d1e\u5ead\u6e56"]','身世不相若，孤卧南山雲。',96,'全唐诗/poet.song.40000.json','["身世不相若，孤卧南山雲。", "忽枉故人問，乃是巴陵君。", "君治最瀟灑，洞庭天下聞。", "髙材有餘暇，壮觀誰能羣。", "子賤不彈琴，河陽自工文。", "大軸寫麗句，瓊華襲蘭薫。", "贈我豈無意，我衰何足云。", "三復不知報，悵望長江濆。"]'),
('9ab621d7-81be-4255-9964-813a162b66de','奉寄持平兄弟','沈遼','宋','宋诗','song-poetry','','[]','平昔相從三十年，白雲唯識皖公山。',32,'全唐诗/poet.song.40000.json','["平昔相從三十年，白雲唯識皖公山。", "當時肺腑半黄壌，何用枯槁留人間。"]'),
('8c92a0bc-1c11-4616-9c10-a5fa70d5f3bf','寄處善不動庵','沈遼','宋','宋诗','song-poetry','','[]','莫笑當年梅子真，區區吏事走風塵。',32,'全唐诗/poet.song.40000.json','["莫笑當年梅子真，區區吏事走風塵。", "風塵自是南昌事，誰識庵中不動人。"]'),
('4e39e6f4-d75c-4768-a2d2-fb4cd860c0ca','次韻元章見寄  其一','沈遼','宋','宋诗','song-poetry','','[]','錢塘故都麗，府寺雲中分。',48,'全唐诗/poet.song.40000.json','["錢塘故都麗，府寺雲中分。", "往往得佳客，翩翩多好文。", "自余去湘水，無復瞻吴雲。", "披尋二篇意，豈减鮑參軍。"]'),
('9bb51d02-756a-49ca-b3a8-2a5abeb038bc','次韻元章見寄  其二','沈遼','宋','宋诗','song-poetry','','[]','西渚菰蒲老，南岡梅柳芳。',48,'全唐诗/poet.song.40000.json','["西渚菰蒲老，南岡梅柳芳。", "當時有佳意，十載尚餘香。", "投老甘寂寞，歸期殊渺茫。", "君能斵句麗，幽眇得張皇。"]'),
('1d02d9d4-c549-4696-ab99-6d2a184222af','奉酬楊聖咨','沈遼','宋','宋诗','song-poetry','','[]','霜林不障北山青，淮北江南一畫屏。',64,'全唐诗/poet.song.40000.json','["霜林不障北山青，淮北江南一畫屏。", "草舍久無年少夢，故人猶記詠歸亭。", "當時皖皖同朝露，不計星星向暮齡。", "千里相望一驩笑，北風浩浩水泠泠。"]'),
('2b48d8eb-1197-45b7-bd08-71854c010032','次韻伯成見贈','沈遼','宋','宋诗','song-poetry','','[]','水上浮雲斷不還，松間幽石自斑斑。',64,'全唐诗/poet.song.40000.json','["水上浮雲斷不還，松間幽石自斑斑。", "柴門不接紅塵路，滿座長将白日閑。", "往解誰能尋赤軸，無情還自愛青山。", "清冷臺下無多路，斷葛枯藤不足扳。"]'),
('13046c47-44cb-45a7-a3c5-412d90dae2d5','永壽太君挽詞  其一','沈遼','宋','宋诗','song-poetry','','[]','帝命方優渥，仙屏去杳冥。',48,'全唐诗/poet.song.40000.json','["帝命方優渥，仙屏去杳冥。", "松筠傳懿行，金石勒新銘。", "雙闕不復望，三山依舊青。", "慈祥豈無報，獨不享遐齡。"]'),
('110a2751-73a5-4ccf-97db-6020d5b95ba5','永壽太君挽詞  其二','沈遼','宋','宋诗','song-poetry','','[]','身謝漢廷路，神遊湘水歸。',48,'全唐诗/poet.song.40000.json','["身謝漢廷路，神遊湘水歸。", "山川想如昔，鄰里欲誰依。", "夢幻久已寤，悲歡今是非。", "最傷芸閣彦，無復老萊衣。"]'),
('6b453e5f-7c16-4ab2-beb9-692d1b0008ba','子固挽詞  其一','沈遼','宋','宋诗','song-poetry','','[]','江左老儒宗，鴻名五紀中。',48,'全唐诗/poet.song.40000.json','["江左老儒宗，鴻名五紀中。", "晚方參法從，久已冠羣公。", "纕服始去位，仙丹浩無功。", "古人稱不朽，終不愧軻雄。"]'),
('21c21612-cecd-4959-8c9a-2a672b5fac7c','子固挽詞  其二','沈遼','宋','宋诗','song-poetry','','[]','典學蚤名世，緒餘爲史師。',48,'全唐诗/poet.song.40000.json','["典學蚤名世，緒餘爲史師。", "剛嚴終不倚，亮直欲誰欺。", "疾惡太阿刃，立言黄絹辭。", "平生游舊意，流涕向豐碑。"]'),
('28a7891f-b009-454f-8567-f7721e23be60','走筆奉酬伯昌示瀟湘煙竹圖','沈遼','宋','宋诗','song-poetry','','[]','三年瀟湘客，不厭瀟湘游。',218,'全唐诗/poet.song.40000.json','["三年瀟湘客，不厭瀟湘游。", "二水相會處，下有白蘋洲。", "洲上多美竹，出沒清淺流。", "森森百頃青，玉簳長與修煙浮。", "歲久無人採，往往半折古岸頭。", "坡陁上下不知際，直接九疑千古愁。", "當時古人相會處，至今作亭在林幽。", "最愛苦雨時，吾甞棹輕舟。", "樂與漁人相往返，其意豈在網與鈎。", "由來古人能放達，何必傲王侯。", "洛陽公子有佳致，落筆直與造化侔。", "方拏抨圖止數尺，寫出瀟湘千里秋。", "南山老夫謝世故，一榻静卧如浮漚。", "遣使持書遠相示，欲與老夫醒病眸。", "老夫困瘁不知報，世上誰爲王子猷。"]'),
('fbde2d68-d58c-4e2b-81bd-e4dfe1aa5a52','奉贈善果師','沈遼','宋','宋诗','song-poetry','','[]','大士隱精藍，不踐白衣舍。',96,'全唐诗/poet.song.40000.json','["大士隱精藍，不踐白衣舍。", "老夫厭世紛，屏迹南山下。", "經時不相見，道味遥相借。", "豈是困煩溽，蕭然雨閑暇。", "白雲等無心，幽林媚如畫。", "常恨簡寂履，不入東林社。", "還疑松山老，怕答龐公話。", "吾庵朝暮成，莫向人間化。"]'),
('38afdb56-65da-46b8-bd9c-08a7eafa2662','奉酬通叟社日','沈遼','宋','宋诗','song-poetry','','[]','秋入瀟湘拍江水，夷人社會秋聲喜。',64,'全唐诗/poet.song.40000.json','["秋入瀟湘拍江水，夷人社會秋聲喜。", "山城寂寞無人行，白醪赤鮮追閭里。", "窮客閉門食無魚，雖有士子半屠沽。", "與君俱爲投荒客，落日怊悵臨城隅。"]'),
('88c33ef8-cb43-4330-b92b-c4310991871d','白蘋花','沈遼','宋','宋诗','song-poetry','','[]','白蘋花，生水中。',32,'全唐诗/poet.song.40000.json','["白蘋花，生水中。", "綠葉牽紫莖，浩蕩向西風。", "西風日夜冷，落日河洲靜。"]'),
('22fb4d5d-81ef-4878-a2c4-b0b99ac526c9','與善果師遊石堵','沈遼','宋','宋诗','song-poetry','','[]','秋風日已佳，幽尋欲誰與。',144,'全唐诗/poet.song.40000.json','["秋風日已佳，幽尋欲誰與。", "邂逅得佛子，逍遥臨石堵。", "江南氣候晚，九月始無暑。", "木葉乍隕霜，川原新濯雨。", "喬松轉山路，中天掲華宇。", "由來安禪寂，不當混泥土。", "侵尋得幽步，周旋聞密語。", "芥蔕同一生，天地同一旅。", "歡戚自流轉，悠悠意何補。", "倦羽息深林，游魚依夕渚。", "吾生幸無事，陶然知所處。", "日晏坐北軒，何用論今古。"]'),
('a177489a-7770-4b4f-aa91-bd6d4fca4328','雲巢醮上清冷臺','沈遼','宋','宋诗','song-poetry','','[]','太清朕無形，歷歷縣衆星。',144,'全唐诗/poet.song.40000.json','["太清朕無形，歷歷縣衆星。", "北斗横天中，衆星朝帝廷。", "顧余草芥士，於此寄餘齡。", "崇壇設香火，秘笈開真經。", "仙客七八人，步虚上清冥。", "再拜致勤懇，肸蠻參神靈。", "願言枯朽骨，清净老巖扃。", "石臺峻重崖，四山合如屏。", "夜寂天更髙，松風響泠泠。", "列炬如長虹，隱映春林青。", "久已謝世故，何心混羶腥。", "齋心肅不寢，已聞朝露零。"]'),
('37c6084e-1268-40ec-ac16-9191992a113b','清泠臺初夏一首寄上翟舅','沈遼','宋','宋诗','song-poetry','','[]','清泠竹樹暗成陰，漸有溪流過此岑。',64,'全唐诗/poet.song.40000.json','["清泠竹樹暗成陰，漸有溪流過此岑。", "草草作巢方寄老，愔愔設榻本無心。", "松門不隔紅塵路，月疊初無俗物侵。", "欲向人間訪消息，渭陽應有遠遊吟。"]'),
('888c263c-73e2-4c6a-ab44-557e4d5183a0','暑雨二首  其一','沈遼','宋','宋诗','song-poetry','','[]','暑濕卧南窗，将夕暴雨作。',48,'全唐诗/poet.song.40000.json','["暑濕卧南窗，将夕暴雨作。", "綠樹暗濛濛，流泉鳴鑿鑿。", "黔突苟幸足，心静本無樂。", "夜半長風號，江流應更惡。"]'),
('49c679ea-e4f6-4383-bee4-ce115a69f08a','暑雨二首  其二','沈遼','宋','宋诗','song-poetry','','[]','委蛇白水來，恍若煙中素。',48,'全唐诗/poet.song.40000.json','["委蛇白水來，恍若煙中素。", "始驚孤渚失，已轉前山去。", "清光照白壁，悍勢衝雲樹。", "吾欲棹輕舟，正畏驚湍怒。"]'),
('222ac0cc-a56d-48ca-b771-d17c4c196b60','白石爛望齊山','沈遼','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','西江水過南山來，青莎白砂一半摧。',128,'全唐诗/poet.song.40000.json','["西江水過南山來，青莎白砂一半摧。", "夜來雨猛山谷溢，平昔夷余安在哉。", "拏舟欲過白石爛，江風激激無纖埃。", "古來白石亦可怪，狂湍蕩潏終不頽。", "南山經春草木王，羣峰委曲青雲堆。", "江中落景若圖畫，山翁住處無崔嵬。", "山翁憔悴如槁木，不與世俗同樽罍。", "江邊山下人不識，斜日獨上清泠臺。"]'),
('db3eba26-9392-4535-a72e-3b5dcb5fd13d','婆娑亭','沈遼','宋','宋诗','song-poetry','','[]','老不爲白髪，老態自婆娑。',48,'全唐诗/poet.song.40000.json','["老不爲白髪，老態自婆娑。", "風力日已鑠，流光能幾何。", "憫憫去世網，蘧蘧寄巖阿。", "無令後生笑，隱几學商那。"]'),
('17ca546f-8467-433f-b4cc-c846ac9154fe','奉贈仲益南上','沈遼','宋','宋诗','song-poetry','','[]','昔日錢塘布衣客，畫舸揺揺出淮北。',144,'全唐诗/poet.song.40000.json','["昔日錢塘布衣客，畫舸揺揺出淮北。", "腰間新佩青銅章，行著綠衣歸故國。", "漢水西流雲夢澤，髙堂老人頭未白。", "兄弟頻年收美科，公卿要途聲寂寂。", "公車薦章動盈束，萬里青雲不遺力。", "老夫在吳始相得，惠停髙車踐荆棘。", "相見怱怱如夢寐，爾來無復人間迹。", "子方策名在清時，霜天正可摶鵬翼。", "遥知後會不可期，吾心已作南山石。"]'),
('9a5596f3-501b-4da9-96c5-e4403ec4bff2','奉送志國赴舉','沈遼','宋','宋诗','song-poetry','','[]','青谿八月菰蒲老，山城飄瀟秋氣早。',128,'全唐诗/poet.song.40000.json','["青谿八月菰蒲老，山城飄瀟秋氣早。", "弄水亭前萬斛船，一帆直上青雲杪。", "沄川公子久論討，筦庫卑棲欲輕矯。", "阿閣鳯雛誰不知，渥洼龍種人間少。", "拔薦當如頷下髭，收科真探懷中寶。", "人生得意須自奮，何用米鹽長擾擾。", "齊山病夫樂枯槁，相見清歡慚老倒。", "它時不忘金玉音，爲記雲巢髙縹緲。"]'),
('b824ab17-1c4b-49f6-a56f-a9ec620ce193','題熙怡亭','沈遼','宋','宋诗','song-poetry','','[]','齊山翠微青天外，西鄰還雲脩竹裏。',96,'全唐诗/poet.song.40000.json','["齊山翠微青天外，西鄰還雲脩竹裏。", "不如道人熙怡亭，巍然迥出青溪水。", "云誰窮髙視千里，亦不沮洳埋蓬藟。", "清晨門外千家供，落日香銷一禪几。", "欲知道人熙怡樂，泛舟偏向江淮艤。", "遊人莫問老夫名，聊詠春紅與秋紫。"]'),
('7e61bac1-ac26-4bd2-ae0b-68581b4ca0f8','開北山望白石爛','沈遼','宋','宋诗','song-poetry','','[]','欲尋白石爛，故開北山路。',48,'全唐诗/poet.song.40000.json','["欲尋白石爛，故開北山路。", "所向雖似殊，吾真得孤嶼。", "容與水上雲，娑羅月中樹。", "勝意已自適，何必方舟渡。"]'),
('7cff8f50-5fd6-4691-889b-2e5a1f4fc08f','奉送孝續歸九江','沈遼','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','池陽决曹竇君掾，三年勾釘煩指呼。',208,'全唐诗/poet.song.40000.json','["池陽决曹竇君掾，三年勾釘煩指呼。", "朝来脱去如敝屣，華舟泛泛歸匡廬。", "君家世吏二千石，緣飾儒雅窮詩書。", "昔歲先君使湖外，特薦尊府聞公車。", "廷尉于公有陰德，翩翩青紫登華塗。", "江城僻院本無事，窮山培塿多荒蕪。", "中間葉侯久無政，顧遇僚吏無精粗。", "狴犴縲囚常數百，小大往往多非辜。", "不知滯獄困寒暑，直疑爲吏憂妻孥。", "惟君不茹亦不吐，獨自垂釣來南湖。", "使者交章任爲令，從此平步青雲衢。", "香爐峰前木葉落，樽壘好在黄家壚。", "此來行李有佳句，莫忘齊山黧老夫。"]'),
('a257606e-655e-4c8a-b668-8e3a4386c150','奉送太古歸舊隱','沈遼','宋','宋诗','song-poetry','','[]','前年姚令下陽羡，老夫爲賦銅官山。',160,'全唐诗/poet.song.40000.json','["前年姚令下陽羡，老夫爲賦銅官山。", "飄飄道人今復往，有如孤雲誰可攀。", "三尺古琴膝上彈，一杯龍水刀無環。", "藥嚢空空何所有，獨抱冲氣參人寰。", "人生富貴無金丹，須臾白骨凋朱顔。", "何爲愁苦強作樂，逍遥不去烟霞間。", "吾昔東遊豈無意，腰下銅章初不關。", "至今山水尚可想，斷夢時向荆谿還。", "安得此身如白鶴，飛與道人天外閑。", "路逢仙友若相問，爲道綠髪今斕斑。"]'),
('191d31a8-ca65-4fbd-8644-afafcca410de','以沉香拄杖奉寄總老戯呈句偈','沈遼','宋','宋诗','song-poetry','','[]','七尺潜虬出海汙，久同病士御三車。',64,'全唐诗/poet.song.40000.json','["七尺潜虬出海汙，久同病士御三車。", "旃檀彫斷終非相，薝蔔芬芳漫散花。", "絕是離非參妙用，穿雲涉水伴生涯。", "東林大士還知否，止此無言是作家。"]'),
('5e57a8cb-3171-4946-9793-f61a79332ad9','與公詡遊西禪新閣','沈遼','宋','宋诗','song-poetry','','[]','清谿水浮青油幕，漾漾輕舟上西郭。',160,'全唐诗/poet.song.40000.json','["清谿水浮青油幕，漾漾輕舟上西郭。", "髙林參天轉山脚，山上黄葉山前落。", "西禪道人屹重閣，松風泠泠半天作。", "左江右湖若可酌，青山四圍走巘崿。", "道逢支遁躡禪屩，方水幽尋同一噱。", "世事區區爲名縛，生死去來一丘貉。", "不如林間寄冲漠，笑傲髙明秋氣索。", "日斜回舟興不薄，有意重來何用約。", "吾歸南岡若孤鶴，新月纖纖下簾箔。", "坐想行臺夜更樂，橋下水聲鳴鑿鑿。"]'),
('6598bfc0-587f-4b86-b3a1-a4b1428b2d80','次韻奉酬公詡短句','沈遼','宋','宋诗','song-poetry','','[]','紅葉飄蕭下石臺，掃除山徑半天開。',32,'全唐诗/poet.song.40000.json','["紅葉飄蕭下石臺，掃除山徑半天開。", "百年老木和煙斫，萬頃晴天看月來。"]'),
('8ba344bf-8754-46db-baca-3ecdddbe3b6e','奉送安行弟赴愽羅守','沈遼','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','愽羅四十雪上鬚，前年将兵出髙奴。',336,'全唐诗/poet.song.40000.json','["愽羅四十雪上鬚，前年将兵出髙奴。", "直取金湯癿名帳，卷旗夜過烏波涂。", "黠羌倉惶不暇戰，即時破蕩禽作俘。", "槖馳牛馬以萬計，白米青鹽歸我儲。", "朝廷下令趣軍賞，丹砂書檄黄金書。", "愽羅解甲入帥府，歸功老成爲後圖。", "漢兵百萬若虓虎，弓劍勁利無全胡。", "不知黠羌欲送死，夭樂給事先六軀。", "羣帥無功坐待命，天子神聖貸不誅。", "愽羅奮髯笑呼盧，黄綬却參朝士裾。", "踰年都城困塵土，乞得一麾南海隅。", "江外山川舊遊好，擊鼓鳴笳聯舳艫。", "秋風翻浪白如雪，美酒滿船誰要酤。", "齊山老翁謝世故，不知門外賢與愚。", "相見欣然拂棋局，不妨遊戯爲歡娱。", "灊山金丹久已就，仙夫道友來相呼。", "愽羅俯首竊自笑，薄命若爾何爲乎。", "圖形不止凌煙閣，迅步扶我青雲衢。", "豈如小邦苟廪祿，畫諾足以嬉朝晡。", "嗣宗已卜匡山宅，雙林工簏青谿魚。", "子歸當在十載外，老境共寄江南墟。"]'),
('d379a83f-4d62-40af-b241-d327cdd9e497','次韻悟師見寄  其一','沈遼','宋','宋诗','song-poetry','','[]','一裘一葛謝時人，似與孤雲老鶴親。',32,'全唐诗/poet.song.40000.json','["一裘一葛謝時人，似與孤雲老鶴親。", "峭石山前静無事，桃花零落幾經春。"]'),
('b5f15382-d06e-4fa1-9df5-761e31007682','次韻悟師見寄  其二','沈遼','宋','宋诗','song-poetry','','[]','不将大辯擬天親，終愧西來面壁人。',32,'全唐诗/poet.song.40000.json','["不将大辯擬天親，終愧西來面壁人。", "無是無非從此去，不同多刼一微塵。"]'),
('964c3c3f-78dc-4555-a134-fe4213b4932c','奉寄零陵太平禪師','沈遼','宋','宋诗','song-poetry','','[]','昔住東江不計年，青松白竹望瀟川。',64,'全唐诗/poet.song.40000.json','["昔住東江不計年，青松白竹望瀟川。", "先知大士當行化，故卜幽棲爲結緣。", "五姓香花瞻法坐，六時清磬會諸天。", "山前耆舊如相見，應坐維摩老病禪。"]'),
('fb67157b-cb74-4bcf-8c84-e6e04949ce79','戯贈石堵二師','沈遼','宋','宋诗','song-poetry','','[]','青山古木隱禪扃，一炷清香數卷經。',32,'全唐诗/poet.song.40000.json','["青山古木隱禪扃，一炷清香數卷經。", "却笑擔嚢南北客，強尋言語學無生。"]'),
('40a55ca5-d065-4a18-b42c-94e2c697459c','偶寄林夫','沈遼','宋','宋诗','song-poetry','','[]','南山雪未消，秋浦春太早。',48,'全唐诗/poet.song.40000.json','["南山雪未消，秋浦春太早。", "桞萼爲誰開，梅花同我老。", "少年薄遊意，落日晴空杳。", "林下寂無人，煙外啼幽鳥。"]'),
('d0df394c-0f9c-4569-99b7-6df0d009037a','奉送醇老','沈遼','宋','宋诗','song-poetry','','[]','近世考吏師，誰如李荆州。',180,'全唐诗/poet.song.40000.json','["近世考吏師，誰如李荆州。", "斯人不可作，伊洛青松丘。", "江上逢故客，揚名談舊遊。", "蚤被北海薦，不向龍門羞。", "三年州從事，利刀無全牛。", "毁譽豈無人，春夢空悠悠。", "乃知雲臺棟，當向華岱求。", "潢汙一尺水，豈能縱呑舟。", "老夫卧山野，自将麋鹿儔。", "雖云相見晚，笑語欣相投。", "曠不入州府，何由接綢繆。", "江南二月春，坐想潁水流。", "適當及瓜代，哂笑豈不優。", "它年青雲路，六翮固已修。", "嵩杪有髙士，爲記南山幽。"]'),
('f604bedf-a65c-4043-ab9b-ac0ba3b0e86d','蘇武歸漢圖一首','沈遼','宋','宋诗','song-poetry','','[]','蘇武不辱漢廷節，生辭匈奴歸北闕。',240,'全唐诗/poet.song.40000.json','["蘇武不辱漢廷節，生辭匈奴歸北闕。", "胡服椎髻李将軍，反袂悲號與武别。", "陰山茫茫天将雪，北風吹旗旗欲裂。", "金瓶釃酒具未設，胡兒解鞍沙上歇。", "使者左驂黄金玦，紫騮白顛推奇骨。", "山前牧羊原野濶，漢日正斜發未發。", "從官揮涕不敢謁，摻袪欲究胸中說。", "青海厄窮十九年，來時壮強今白髪。", "同行吏士半物故，韜中節旄盡落脱。", "将軍鷙忿不可奪，老母已誅族已滅。", "心知罪惡上通天，甘死胡塵同斷枿。", "功名逆順雖不類，胡漢死生從此决。", "夙昔遺芳在圖史，追想山川一騷屑。", "巧工寓意在恍惚，墨妙筆精世稱絕。", "唯有千秋不斷情，至今亭亭隴頭月。"]'),
('ddd387ac-e716-4fc3-9c02-438f56849b4d','西禪新閣','沈遼','宋','宋诗','song-poetry','','[]','秋浦千萬山，蒼煙媚髙木。',192,'全唐诗/poet.song.40000.json','["秋浦千萬山，蒼煙媚髙木。", "流髟落浦中，泓澄一川渌。", "江南佳麗地，六代多遺躅。", "不見石城人，空餘瓊樹曲。", "長圍山勢壮，不駐如車轂。", "道人敞重閣，却倚山陽麓。", "西江瀉軒外，雪浪髙如屋。", "未若秋浦佳，平鋪紺文縠。", "水中白石爛，汎汎如孤鶩。", "天外九蕖蓉，突兀揺蒼玉。", "太白一杯酒，杜郎滿頭菊。", "千載忽已空，白骨埋荒谷。", "齊山皓髪客，逍遥老松竹。", "拏舟試一眺，時方秋氣肅。", "飄蕭得勝意，遠邇窮幽瞩。", "行當乘月来，置榻山頭宿。"]'),
('a4d931cd-92be-431b-a932-2f1baf425a58','次韻酬余君見贈','沈遼','宋','宋诗','song-poetry','','[]','老来無暗亦無明，寄息深山避世情。',32,'全唐诗/poet.song.40000.json','["老来無暗亦無明，寄息深山避世情。", "夫子暗投珠玉惠，我身正似一毫輕。"]'),
('0134cf5c-e2ab-4e02-9ad8-92e042b26c39','奉酬伯昌志國所示古調','沈遼','宋','宋诗','song-poetry','','[]','餘景避世讙，棲遲在丘壑。',144,'全唐诗/poet.song.40000.json','["餘景避世讙，棲遲在丘壑。", "公子引車騎，相訪南山崿。", "長離舞員嵩，同爲九皐鶴。", "晚節雖殊途，彷彿當年樂。", "間關幽鳥哢，凌亂餘花落。", "春風豈有意，羣生自回薄。", "夙昔欽二妙，聯函得佳作。", "顧予非季子，何足聞古樂。", "葩華玩洒藻，銀鈎窺雅愽。", "故知霄鴻意，不爲塵埃鑠。", "吾蚤拙世用，投老更衰索。", "慚無錦繡叚，何由報金錯。"]'),
('a832e2ba-2c4b-4bd8-a47f-2d8671b9483f','齊山偶題三首  其一','沈遼','宋','宋诗','song-poetry','','[]','杜子風情春水波，至今詩句使人夸。',32,'全唐诗/poet.song.40000.json','["杜子風情春水波，至今詩句使人夸。", "不知朽骨猶存否，山上年年黄菊花。"]'),
('720b0413-7704-4533-ac11-47b08054baba','齊山偶題三首  其二','沈遼','宋','宋诗','song-poetry','','[]','朝雲未散白笴陂，落日已過銅陵西。',32,'全唐诗/poet.song.40000.json','["朝雲未散白笴陂，落日已過銅陵西。", "不向人間生皓髪，直尋仙客上青谿。"]'),
('07333bb2-4869-47b5-b6b1-271a1cf52bce','齊山偶題三首  其三','沈遼','宋','宋诗','song-poetry','','[]','山腰嵌巖山頂平，此下直眺池陽城。',32,'全唐诗/poet.song.40000.json','["山腰嵌巖山頂平，此下直眺池陽城。", "城中歡戚自流轉，不似山石都無情。"]'),
('d2b03556-4c77-47cf-bb05-fa1c088bd044','寄道輔','沈遼','宋','宋诗','song-poetry','','[]','髯弟南來白髪垂，襄陽夫子最相知。',64,'全唐诗/poet.song.40000.json','["髯弟南來白髪垂，襄陽夫子最相知。", "倉惶河外元戎客，冷落江南夜半棋。", "雲外渺瀰帆信隔，秋山重疊驛書遲。", "何緣得與君相會，共醉山前白玉巵。"]'),
('fff02d14-a1ba-4743-af1b-f474ba00cf64','代人上杭守趙資政生辰詩','沈遼','宋','宋诗','song-poetry','','[]','盛世君臣會，功成在太平。',96,'全唐诗/poet.song.40000.json','["盛世君臣會，功成在太平。", "一陽迎律至，元老應時生。", "直道升烏府，仁風擁使旌。", "猷爲安廟社，惠愛及民氓。", "帖泰三朝事，光華萬古名。", "至誠無隱蔽，妙識造圓明。", "愛日恩光佈，流泉句偈清。", "邦人祝公壽，龜鶴入蓬瀛。"]'),
('9fb02e0f-02ba-4dd5-b4fd-816f91c5f2ba','無柱亭','沈遼','宋','宋诗','song-poetry','','[]','結茅在何處，爲屋豈無柱。',48,'全唐诗/poet.song.40000.json','["結茅在何處，爲屋豈無柱。", "山前巉巖石，四方適中度。", "誰知屋下人，其心亦無柱。", "悠然寄此間，自得無生路。"]'),
('451a7274-9005-4ce8-97d4-32f0b2bf3f89','南漪堂','沈遼','宋','宋诗','song-poetry','','[]','湖上逍遥避百愁，年来頻向此中休。',64,'全唐诗/poet.song.40000.json','["湖上逍遥避百愁，年来頻向此中休。", "簷前山勢翠相照，床下冰紋清不流。", "縈带夕陽移畫舸，留連眀月卧前洲。", "髙僧會取棲遲意，應有人来悵昔遊。"]'),
('7b8bfa1c-32af-4c79-88c7-43053a524693','寶雲叢翠亭','沈遼','宋','宋诗','song-poetry','','[]','羣山駕肩東南傾，平湖照眼正中明。',64,'全唐诗/poet.song.40000.json','["羣山駕肩東南傾，平湖照眼正中明。", "上人置亭倚絕巘，寶雲拂樹當前楹。", "春陽未徹地先暖，秋景欲下風已清。", "衰才不足道佳景，聊書叢翠爲其名。"]'),
('086e8d9d-38b3-4803-b052-e334129d03a1','遠行','沈遼','宋','宋诗','song-poetry','','[]','少年事遠遊，迢迢指岐路。',72,'全唐诗/poet.song.40000.json','["少年事遠遊，迢迢指岐路。", "遥天值秋晏，煙光澹如素。", "寥落淮南山，影入揚子渡。", "出入三十年，久嗟韋带誤。", "老来感節物，此意誰與喻。", "獨知擁毳坐，無復晨征路。"]'),
('3d38b531-ec07-4707-bff4-efad4487121c','登覧','沈遼','宋','宋诗','song-poetry','','[]','我意欲窮眺，山林蔽四域。',60,'全唐诗/poet.song.40000.json','["我意欲窮眺，山林蔽四域。", "爾来已彫落，萬里情何極。", "古人多悲秋，我念不如默。", "終朝對青山，烟嵐有餘色。", "欲上百尺樓，羸軀恐顛側。"]'),
('d7c2dd1e-b34e-4cb3-8e02-21b92637a77a','雜感','沈遼','宋','宋诗','song-poetry','','[]','咄咄待秋至，秋至安足驚。',48,'全唐诗/poet.song.40000.json','["咄咄待秋至，秋至安足驚。", "年華去如掃，正如寵與榮。", "區區白駒隙，君子慎所行。", "不如陶淵明，超然自歸耕。"]'),
('0040e030-8b63-4baf-8635-c2b10378990d','村舍','沈遼','宋','宋诗','song-poetry','','[]','西山草廬下，古木蔽中園。',48,'全唐诗/poet.song.40000.json','["西山草廬下，古木蔽中園。", "九月罷亞收，流水滿郊原。", "茅茨何所樂，姑無人世喧。", "多謝朝市人，吾方效孤鶱。"]'),
('b0efe2aa-4189-4bba-a696-d9cebfe9a5b6','邊思','沈遼','宋','宋诗','song-poetry','','[]','西風方折膠，戍兵出已屢。',84,'全唐诗/poet.song.40000.json','["西風方折膠，戍兵出已屢。", "赤藏候騎歸，翩翩如鳥羽。", "穹廬舊所居，不遠横山路。", "漢将知爲誰，三軍倚全護。", "上賴天子聖，邊方無鬭捕。", "運籌有餘略，彫弓射狐兔。", "何謝蒼頭公，迴爲兒女顧。"]'),
('87b549e5-1a3d-4fb0-be77-b1e455e16627','感懷','沈遼','宋','宋诗','song-poetry','','[]','秋氣已憀慄，况乃陰雨多。',72,'全唐诗/poet.song.40000.json','["秋氣已憀慄，况乃陰雨多。", "顔色不衰謝，唯有庭前莎。", "幽窗坐讀書，諷古空長哦。", "多謝髙世人，辯口如縣河。", "幹旋白日光，何用魯陽戈。", "念我無術進，憂愁将奈何。"]'),
('2e2a0210-01d5-4d95-be2c-4d8c78a8d30f','山中','沈遼','宋','宋诗','song-poetry','','[]','朝遊白雲裏，夕憩長松邊。',48,'全唐诗/poet.song.40000.json','["朝遊白雲裏，夕憩長松邊。", "俯視世間人，但見萬井煙。", "流轉非一日，正如水潺湲。", "吾方欲髙步，嘉遁休中年。"]'),
('1645f786-d417-40c2-927c-952de1e234f9','宴集','沈遼','宋','宋诗','song-poetry','','[]','袢暑久拘欝，訢然對秋光。',72,'全唐诗/poet.song.40000.json','["袢暑久拘欝，訢然對秋光。", "薄具招友朋，相與娱中堂。", "清觴味雖薄，果蓏具青黄。", "尤愛簷間竹，風来響琳瑯。", "正賴文舉賢，坐客乃其常。", "相歡意氣間，髙韻信軒昂。"]'),
('b5794e42-e98d-4f94-8393-e7bfadb3453c','怨思','沈遼','宋','宋诗','song-poetry','','[]','幽人有幽怨，其意豈爲秋。',72,'全唐诗/poet.song.40000.json','["幽人有幽怨，其意豈爲秋。", "西風多感傷，乃爾增百憂。", "輾轉長夜枕，徘徊千尺樓。", "浮生能幾時，年華亦易遒。", "儻非拳拳志，諒復何所求。", "天道或難平，此理可信不。"]'),
('2546ba6c-ecb9-4b01-89ab-9e20af442cf5','送行','沈遼','宋','宋诗','song-poetry','','[]','昔我來東州，送客滿江郭。',84,'全唐诗/poet.song.40000.json','["昔我來東州，送客滿江郭。", "揮涕望井閭，秋懷寄杯酌。", "泛然千里外，秋来意非薄。", "客舍冷瀟騷，那復事飾雘。", "游宦非我懷，俯仰令人怍。", "何事脱身去，餘生老丘壑。", "親朋永相過，焉能事官爵。"]'),
('16261c82-2a76-4789-a924-72289ed6b98e','陪客遊山','沈遼','宋','宋诗','song-poetry','','[]','相從雲中去，飛盖雲中斜。',48,'全唐诗/poet.song.40000.json','["相從雲中去，飛盖雲中斜。", "峭嶺想員嶠，横溪勝若耶。", "巖通新雨溜，林暗殘春花。", "緬懷武林興，夢寐歸山家。"]'),
('5afd6661-dbb8-4b4a-827b-9809ba44a603','圓明師爲余鼓琴作昭君操因感其意辭以贈之','沈遼','宋','宋诗','song-poetry','','[]','王昭君，漢宮女。',184,'全唐诗/poet.song.40000.json','["王昭君，漢宮女。", "生如桃李花，皖皖託朝露。", "不向春風榮，摧折在泥土。", "恥將黄金市顔色，空得君王一迴顧。", "黄門扶我上車去，遙望漢宮隔煙霧。", "十年簾下學畫眉，不知還被蛾眉誤。", "中間悲怨或易忘，如今羈愁那可論。", "夢中時復作歌舞，滿目異類誰與語。", "胡風日夜驚吹沙，不知春來復秋去。", "一生此恨終難言，獨自援琴傳作譜。", "傳作譜，一曲未終淚如雨。", "我來都城下，黄塵厭羈旅。", "道人爲我試一彈，使我超然爲懷古。"]'),
('f7952b16-34ff-4a7a-8b0b-bf4f0fab2d6f','題靈山寺','劉恕','宋','宋诗','song-poetry','','[]','早晚報衙蜂擾擾，友朋相和鳥關關。',32,'全唐诗/poet.song.40000.json','["早晚報衙蜂擾擾，友朋相和鳥關關。", "餘香滿袖花驚眼，空翠沾巾雨暝山。"]'),
('6b63778b-dcb7-4434-b4c2-c2ba2c4fb2a3','題揚州山光寺','盧秉','宋','宋诗','song-poetry','','[]','馬蹄輕蹙柳花浮，醉入淮南第一州。',32,'全唐诗/poet.song.40000.json','["馬蹄輕蹙柳花浮，醉入淮南第一州。", "不是青樓羞薄幸，自緣無錦作纏頭。"]'),
('28e1e928-bd12-473e-8077-0142047d5280','題傳舍','盧秉','宋','宋诗','song-poetry','','[]','青衫白發病參軍，旋糴黄粱置酒樽。',32,'全唐诗/poet.song.40000.json','["青衫白發病參軍，旋糴黄粱置酒樽。", "但得有錢留客醉，也勝騎馬傍人門。"]'),
('2da812f4-0244-4a0e-bafa-c2c0a18e3939','絕句','盧秉','宋','宋诗','song-poetry','','[]','十月都門風薄衣，搗砧聲重雁南飛。',32,'全唐诗/poet.song.40000.json','["十月都門風薄衣，搗砧聲重雁南飛。", "野人不識長安樂，且趁鱸魚一櫂肥。"]'),
('6ca20787-f696-4090-ad9c-db967ba1fc54','宮詞十首  其一','盧秉','宋','宋诗','song-poetry','','[]','絮撲芙蓉苑，華開太液波。',24,'全唐诗/poet.song.40000.json','["絮撲芙蓉苑，華開太液波。", "黄頭吹月笛，櫂影落天河。"]'),
('e6a8df80-0f75-471f-96a5-1ad41c3b2056','宮詞十首  其二','盧秉','宋','宋诗','song-poetry','','[]','草淺天邊碧，花勻日腳紅。',24,'全唐诗/poet.song.40000.json','["草淺天邊碧，花勻日腳紅。", "須知親帝澤，不必藉春工。"]'),
('c912ba32-bfb2-4e8a-b66c-71d31f52bb48','宮詞十首  其三','盧秉','宋','宋诗','song-poetry','','[]','花萼蜂兒影，簾旗燕子風。',24,'全唐诗/poet.song.40000.json','["花萼蜂兒影，簾旗燕子風。", "遊絲避金葆，吹過紫垣東。"]'),
('623a4104-e48f-4d3e-adf1-6291b7b70587','宮詞十首  其四','盧秉','宋','宋诗','song-poetry','','[]','翠環雙鳳带，小隊五花蹄。',24,'全唐诗/poet.song.40000.json','["翠環雙鳳带，小隊五花蹄。", "十二龍鈎卷，梨花爛漫時。"]'),
('4beb1b74-cb84-4f92-9bfe-52a941dd6dcf','宮詞十首  其五','盧秉','宋','宋诗','song-poetry','','[]','花蔕流金水，知從秘苑來。',24,'全唐诗/poet.song.40000.json','["花蔕流金水，知從秘苑來。", "春風如解意，不敢起纖埃。"]'),
('fa6ecc0e-5dea-40c4-9f79-253bad64ffd9','宮詞十首  其六','盧秉','宋','宋诗','song-poetry','','[]','粉蝶非仙骨，隨風過苑牆。',24,'全唐诗/poet.song.40000.json','["粉蝶非仙骨，隨風過苑牆。", "穿花不敢採，應怯內家香。"]'),
('71bf7d81-dfd6-4827-9254-f6e426ffbe6a','宮詞十首  其七','盧秉','宋','宋诗','song-poetry','','[]','沉沉雨過宮槐綠，寂寂春殘輦路香。',32,'全唐诗/poet.song.40000.json','["沉沉雨過宮槐綠，寂寂春殘輦路香。", "細想人間無此景，夜來魂夢到昭陽。"]'),
('40b248cc-62d2-4609-a96d-d0c3ed4ab2e7','宮詞十首  其八','盧秉','宋','宋诗','song-poetry','','[]','迎春新燕尾纖纖，拂柳穿花掠翠簷。',32,'全唐诗/poet.song.40000.json','["迎春新燕尾纖纖，拂柳穿花掠翠簷。", "問道蕊宮三十六，美人爭爲卷珠簾。"]'),
('72acc516-a43b-4eae-b5af-eff90f2ada5a','宮詞十首  其九','盧秉','宋','宋诗','song-poetry','','[]','蓬萊風蹙水紋班，月甃風廊四百間。',32,'全唐诗/poet.song.40000.json','["蓬萊風蹙水紋班，月甃風廊四百間。", "雲外蹕聲穿嶺去，行宮簇馬望驪山。"]'),
('579754f5-d0f7-4508-8659-4bba579f29ba','宮詞十首  其一○','盧秉','宋','宋诗','song-poetry','','[]','落絮濛濛立夏天，樓前槐影葉初圓。',32,'全唐诗/poet.song.40000.json','["落絮濛濛立夏天，樓前槐影葉初圓。", "傳聞紫殿深深處，便有薰風入舜弦。"]'),
('a54c6ea1-ba39-405c-bc7c-5ebcf2977e11','送中濟侍郎帥慶得乘字','杜純','宋','宋诗','song-poetry','','[]','羌馬軼河西，詔下絕貢聘。',120,'全唐诗/poet.song.40000.json','["羌馬軼河西，詔下絕貢聘。", "自是封疆臣，都俞命彌敬。", "莫如小司徒，欽哉往臨慶。", "貔貅十萬人，大半爵公乘。", "恩將懷其心，威足繫其頸。", "牧無南向塵，指揮罔不定。", "邊氓歌夜耕，更續公劉政。", "今日燕西園，愧接儒林盛。", "陽關斷誰腸，笑把金鍾聽。", "家世本詩書，無勞霍去病。"]'),
('da39ad37-e5a0-42c2-8fa8-f17702bd82b3','慶善寺圓照堂題詠','王兢','宋','宋诗','song-poetry','','[]','佛心開晦瞑，覺竹極融明。',48,'全唐诗/poet.song.40000.json','["佛心開晦瞑，覺竹極融明。", "實相自然見，客塵何處生。", "銅瓶秋水淨，草坐月華清。", "不必曹溪去，穿雲振錫行。"]'),
('16a7a8c3-4453-4e8a-9c79-a09d5d726c98','遊藏春塢用坡韻復題其後','釋了元','宋','宋诗','song-poetry','','[]','門掩青春春自饒，未容取次老僧敲。',32,'全唐诗/poet.song.40000.json','["門掩青春春自饒，未容取次老僧敲。", "輸他蜂蝶無情物，相逐偷香過柳梢。"]'),
('0f5da04c-ce7d-434f-bec0-9cfdc4a245bb','題茶詩與東坡','釋了元','宋','宋诗','song-poetry','','[]','穿雲摘盡社前春，一兩平分半與君。',32,'全唐诗/poet.song.40000.json','["穿雲摘盡社前春，一兩平分半與君。", "遇客不須容易點，點茶須是喫茶人。"]'),
('6dd3b43a-9d19-49e8-afeb-5cc2959a5521','長歌','釋了元','宋','宋诗','song-poetry','','[]','野鳥啼，野鳥啼時時有思。',298,'全唐诗/poet.song.40000.json','["野鳥啼，野鳥啼時時有思。", "有思春氣桃花發，春氣桃花發滿枝。", "滿枝鶯雀相呼喚，鶯雀相呼喚巖畔。", "巖畔花紅似錦屏，花紅似錦屏堪看。", "堪看山，山秀麗，秀麗山前煙霧起。", "山前煙霧起清浮，清浮浪促潺湲水。", "浪促潺湲水景幽，景幽深處好，深處好追遊。", "追遊傍水花，傍水花似雪，似雪梨花光皎潔。", "梨花光皎潔玲瓏，玲瓏似墜銀花折。", "似墜銀花折最好，最好柔茸溪畔草。", "柔茸溪畔草青青，雙雙蝴蝶飛來到。", "蝴蝶飛來列落花，落花林裏鳥啼叫。", "林裏鳥啼叫不休，不休爲憶春光好。", "爲憶春光好楊柳，楊柳枝枝春色秀。", "春色秀時常共飲，時常共飲春濃酒。", "春濃酒似醉，似醉閑行春色裏。", "閑行春色裏相逢，相逢競憶遊山水。", "競憶遊山水心息，心息悠悠歸去來，歸去來休休役役。"]'),
('547a98fe-799a-46fc-aeaf-5c6ffddd2816','答可遵','釋了元','宋','宋诗','song-poetry','','[]','打睡禪和萬萬千，夢中趨利走如楊。',32,'全唐诗/poet.song.40000.json','["打睡禪和萬萬千，夢中趨利走如楊。", "勸君打快修憚定，老境如蠶已再眠。"]'),
('55d13e55-5c36-42b7-8c68-7f877ac9aca8','寄劉凝之中允','釋了元','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','廬山南面落星濱，八十清強致仕人。',64,'全唐诗/poet.song.40000.json','["廬山南面落星濱，八十清強致仕人。", "天下共推爲大老，皇家不得作忠臣。", "雲棲高鎖真空月，竹洞深藏覺苑春。", "莫道神仙便無事，赤心長是念斯民。"]'),
('627d58ba-d083-413e-9122-71d86222f8bb','自爲像贊','釋了元','宋','宋诗','song-poetry','','[]','李公天下石麒麟，傳得雲居道者真。',64,'全唐诗/poet.song.40000.json','["李公天下石麒麟，傳得雲居道者真。", "不爲拈華明人事，等閑開口笑何人。", "泥牛漫向風前嗅，枯木無端雪裏春。", "對現堂堂俱不識，太平時代自由身。"]'),
('4ad74094-93c5-4652-ac47-70edd582d592','偈','釋了元','宋','宋诗','song-poetry','','[]','趙州當日少謙光，不出三門見趙王。',32,'全唐诗/poet.song.40000.json','["趙州當日少謙光，不出三門見趙王。", "爭似金山無量相，大千都是一禪床。"]'),
('60a4e6f1-8fdf-4cfa-a3e5-a1b9ea802b90','戒殺文','釋了元','宋','宋诗','song-poetry','','[]','鱗甲材毛諸品類，衆生與佛心無二。',208,'全唐诗/poet.song.40000.json','["鱗甲材毛諸品類，衆生與佛心無二。", "只爲當時錯用心，致使今生頭角異。", "水中游，林裏戲，何忍將來充日計。", "磨刀着火或研虀，口不能言眼還覷。", "或槌磕，或刀刺，牽入鑊湯深可畏。", "㷟燖毛羽括皮鱗，刮脊剜心猶吐氣。", "美君喉，誇好味，勸子勸妻言俊利。", "只知恣性縱無明，不懼陰司毫髮記。", "命纔終，冤對至，面睹閻王爭敢諱。", "從頭一一報無差，爐戾鑊湯何處避。", "勸賢豪，須戒忌，莫把衆生當容易。", "食他一臠臠還他，古聖留言終不僞。", "戒殺兼能買放生，免入阿鼻無問地。"]'),
('dc76af7a-5b31-4850-8e03-dad0e148f727','頌古聯珠','釋了元','宋','宋诗','song-poetry','','[]','塵中辯主眼分明，特地尋方更點睛。',32,'全唐诗/poet.song.40000.json','["塵中辯主眼分明，特地尋方更點睛。", "堪笑耆婆雖暝眩，至今南北絕人行。"]'),
('85b6ab5f-9f5d-4993-8a5f-9350a0dbc54e','焦山三詔洞','釋了元','宋','宋诗','song-poetry','','[]','疇昔先生此掩關，紫泥三到石房間。',32,'全唐诗/poet.song.40000.json','["疇昔先生此掩關，紫泥三到石房間。", "若教便逐蒲輪起，安得清風鎮海山。"]'),
('456ff39a-91c6-4fba-8ae6-6bac44b49b28','遊雲門','釋了元','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','一陣若邪溪上雨，雨過荷花香滿路。',96,'全唐诗/poet.song.40000.json','["一陣若邪溪上雨，雨過荷花香滿路。", "拖筇縱步入松門，寺在白雲堆裏住。", "老僧卻笑尋茶具，旋汲寒泉煮玉乳。", "睡魔驚散毛骨清，坐看秦峰秋月午。", "月明山鳥亂相呼，松杉竹影半窗戶。", "令人徹曉憶匡廬，作詩先寄江南去。"]'),
('ed586685-253c-4d26-b7c2-3867d748c411','句  其一','釋了元','宋','宋诗','song-poetry','','[]','子瞻船上带家來。',8,'全唐诗/poet.song.40000.json','["子瞻船上带家來。"]'),
('ab70ac01-37cc-46cc-9651-1fb0ffcfdf84','句  其二','釋了元','宋','宋诗','song-poetry','','[]','龍枝已逐風雷變，減卻虛窗半日涼。',16,'全唐诗/poet.song.40000.json','["龍枝已逐風雷變，減卻虛窗半日涼。"]'),
('413daecf-2816-4146-af57-d4e47505e770','句  其三','釋了元','宋','宋诗','song-poetry','','[]','紅裙蘸碧波。',6,'全唐诗/poet.song.40000.json','["紅裙蘸碧波。"]'),
('532eb4aa-d4f7-4581-9645-53587c4778c6','句  其四','釋了元','宋','宋诗','song-poetry','','[]','藕斷鷺鷥飛。',6,'全唐诗/poet.song.40000.json','["藕斷鷺鷥飛。"]'),
('60b6601e-d30e-4cd3-8393-c8f4e29e57f4','句  其五','釋了元','宋','宋诗','song-poetry','','[]','無山得似巫山秀。',8,'全唐诗/poet.song.40000.json','["無山得似巫山秀。"]'),
('2e4a70b8-3eb0-4598-b4b2-e7ff6ccb304b','投韓太祝','釋了元','宋','宋诗','song-poetry','','[]','公子乘閑臥絳幮，白衣老吏慢寒儒。',32,'全唐诗/poet.song.40000.json','["公子乘閑臥絳幮，白衣老吏慢寒儒。", "不知夢見周公否，曾說當時吐哺無。"]'),
('4f3f7a1d-2a18-484a-b8f0-b2abfdae9cee','題江幹初雪圖','釋了元','宋','宋诗','song-poetry','','[]','此身何補一毫芒，三辱清時政事堂。',32,'全唐诗/poet.song.40000.json','["此身何補一毫芒，三辱清時政事堂。", "病骨未爲山下土，尚尋遺墨話存亡。"]'),
('f56e8fc4-a0ce-4a01-84e5-a3394648acdf','沂山龍祠祈雨有應','釋了元','宋','宋诗','song-poetry','','[]','南山高峻嶒，北山亦崷崒，坐看兩山雲出沒。',109,'全唐诗/poet.song.40000.json','["南山高峻嶒，北山亦崷崒，坐看兩山雲出沒。", "行如驅，歸若呼，始覺山中有靈物。", "鬱鬱其焚蘭，覃覃其擊鼓，祝屢云云巫屢舞。", "我民無罪神所憐，一夜雷風三尺雨。", "嶺木兮蒼蒼，溪泉兮央央，決雲散諸峰互明滅。", "東阡西陌農事忙，廟閑山空音響絕。"]'),
('99940451-18d2-4b70-9622-b9e8ea6ba81e','答蘇子由','釋了元','宋','宋诗','song-poetry','','[]','匕飯盤蔬強少留，相逢何物可消憂。',64,'全唐诗/poet.song.40000.json','["匕飯盤蔬強少留，相逢何物可消憂。", "緣君未得酒中趣，與我漫爲方外遊。", "草亂不容移馬跡，山雄全欲逼城樓。", "濟時異日須公等，莫狎翩翩海上鷗。"]'),
('f3a1a7ae-d73d-4f0f-ad42-6f7735f2e546','端午帖子','釋了元','宋','宋诗','song-poetry','','[]','艾葉成人後，榴花結子初。',24,'全唐诗/poet.song.40000.json','["艾葉成人後，榴花結子初。", "江心新得鏡，龍瑞護仙居。"]'),
('b07418e4-7780-4c7f-a07b-2b542e7cea9a','和賜後苑金橘','釋了元','宋','宋诗','song-poetry','','[]','苑臣初摘置琱盤，口敕宣恩賜近官。',64,'全唐诗/poet.song.40000.json','["苑臣初摘置琱盤，口敕宣恩賜近官。", "氣味豈同淮枳變，皮膚不作楚梅酸。", "參差翠葉藏珠琲，錯落黄金鑄彈丸。", "安得一株擎雨露，畫圖傳與世人看。"]'),
('fe1c1927-2bac-41e1-bf25-9b3cf3338288','送劉貢父悴海陵','釋了元','宋','宋诗','song-poetry','','[]','吾儕客京師，晨夕厭歡聒。',252,'全唐诗/poet.song.40000.json','["吾儕客京師，晨夕厭歡聒。", "僦舍八九椽，鬱溽增煩渴。", "有如轍中魚，噞喁不可活。", "百鳥趨高門，䟃𧽼互揮喝。", "論辯苦難裁，氣焰欻相奪。", "所喪或捐軀，所得未易撮。", "我聞江湖間，連山翠如抹。", "山下走滄波，山巔富松栝。", "鳧鴨亂菰蒲，魚黿聚坡堨。", "世事劇飛電，人生真漂沫。", "誰其違樂遊，而此卷顰額。", "君直秘書閣，日趨黄金闥。", "忽思雲水行，飄然誰能遏。", "朝出都門東，襟胸迥披豁。", "放舟下淮楚，天地頓空闊。", "莫苦道路難，暑令怳已末。", "君看日月疾，俯仰換裘葛。", "無謂監州微，孔孟猶短褐。", "時來發光華，春陽奮枯枿。", "惟君飽才術，流輩服穎脫。", "早作歸朝期，豈學弦與筈。"]'),
('fa399216-d2f0-418d-ad21-adb05ae5d227','句  其一','釋了元','宋','宋诗','song-poetry','','[]','紫蟹黄柑新酒熟，夜間船尾唱伊州。',16,'全唐诗/poet.song.40000.json','["紫蟹黄柑新酒熟，夜間船尾唱伊州。"]'),
('213de7a2-4679-4d5a-a627-6f88d01e9636','句  其二','釋了元','宋','宋诗','song-poetry','','[]','正是清澄秋雨夜，空傳玉蕊發春晴。',16,'全唐诗/poet.song.40000.json','["正是清澄秋雨夜，空傳玉蕊發春晴。"]'),
('cc17133c-874a-4c63-b697-8f273308adbf','偈六首  其一','釋淨端','宋','宋诗','song-poetry','','[]','本是瀟湘一釣客，自東自西自南北。',16,'全唐诗/poet.song.40000.json','["本是瀟湘一釣客，自東自西自南北。"]'),
('5baaae99-7ead-41ea-9226-6c76623a5de3','偈六首  其二','釋淨端','宋','宋诗','song-poetry','','[]','章惇章惇，請我看墳。',20,'全唐诗/poet.song.40000.json','["章惇章惇，請我看墳。", "我卻喫素，汝卻喫葷。"]'),
('c2851f27-3307-4b76-94b6-0eb9119b814b','偈六首  其三','釋淨端','宋','宋诗','song-poetry','','[]','章公好學仙，呂公好坐禪。',24,'全唐诗/poet.song.40000.json','["章公好學仙，呂公好坐禪。", "徐六喻簷板，各自見一邊。"]'),
('9ba0c839-9042-401f-8e1e-bfcc9137c967','偈六首  其四','釋淨端','宋','宋诗','song-poetry','','[]','村裏師子村裏弄，眉毛與眼一齊勁。',48,'全唐诗/poet.song.40000.json','["村裏師子村裏弄，眉毛與眼一齊勁。", "開卻口，肚裏直籠統，不愛人取奉。", "直饒弄列帝王宮，也是一場乾打鬨。"]'),
('0a59a17a-980a-4f52-8e9d-7052f7ec8f66','偈六首  其五','釋淨端','宋','宋诗','song-poetry','','[]','天上無雙月，人間只一僧。',24,'全唐诗/poet.song.40000.json','["天上無雙月，人間只一僧。", "一堂風冷淡，千古意分明。"]'),
('8289c747-e083-4f0b-9ce5-ea6c13c0f798','偈六首  其六','釋淨端','宋','宋诗','song-poetry','','[]','端師子，太慵懶，未死牙齒無壞爛。',61,'全唐诗/poet.song.40000.json','["端師子，太慵懶，未死牙齒無壞爛。", "二時伴衆赴堂，粥飯都趕不辦。", "如今得死是便宜，長眠百事皆不管。", "第一不著看官，第二不著喫粥飯。"]'),
('da8e81e9-1bbb-4d61-9dec-0c1ebdd2be71','偈四首  其一','釋淨端','宋','宋诗','song-poetry','','[]','七處徵心心不遂，懵懂阿難不瞥地。',32,'全唐诗/poet.song.40000.json','["七處徵心心不遂，懵懂阿難不瞥地。", "直饒徵得見無心，也是泥中洗土塊。"]'),
('85fbd223-95d9-4d01-8b46-6bfa382d82fa','偈四首  其二','釋淨端','宋','宋诗','song-poetry','','[]','八還之教垂來久，自古宗師各分剖。',32,'全唐诗/poet.song.40000.json','["八還之教垂來久，自古宗師各分剖。", "直饒還得不還時，也是鰕逃不出斗。"]'),
('bc6feea1-f310-4292-953f-052aca557e00','偈四首  其三','釋淨端','宋','宋诗','song-poetry','','[]','點鐵成金易，忠孝兩全難。',41,'全唐诗/poet.song.40000.json','["點鐵成金易，忠孝兩全難。", "子細思量著，不如個湖州長興靈山孝感彈院老松樹下無用野僧閑。"]'),
('34971841-bfad-4cad-b9d1-cbc6a5df382a','偈四首  其四','釋淨端','宋','宋诗','song-poetry','','[]','南無觀世音，說出種種法。',36,'全唐诗/poet.song.40000.json','["南無觀世音，說出種種法。", "衆生業海深，所以難救拔。", "往往沉沒者，聲聲怨菩薩。"]'),
('b95a6437-2b5c-4adc-a197-5d2e3fe56de8','贈吳少卿入山','釋淨端','宋','宋诗','song-poetry','','[]','友人相訪入柴關，雲水寬閑溪澗寒。',32,'全唐诗/poet.song.40000.json','["友人相訪入柴關，雲水寬閑溪澗寒。", "莫道山家無可待，老松修竹任君看。"]'),
('cbd5035a-3581-4208-850c-a7211f4185e7','和友人入山韻','釋淨端','宋','宋诗','song-poetry','','[]','閑來無事對山屏，古澗寒松暢野情。',32,'全唐诗/poet.song.40000.json','["閑來無事對山屏，古澗寒松暢野情。", "是處巖華高下色，幾般幽鳥往來聲。"]'),
('73646beb-1d08-4b31-a00c-04522d950d6d','題歸雲庵壁','釋淨端','宋','宋诗','song-poetry','','[]','老來林下養閑軀，茅屋清虛蚊蚋無。',32,'全唐诗/poet.song.40000.json','["老來林下養閑軀，茅屋清虛蚊蚋無。", "一徑松虱何處起，入松穿竹兩三株。"]'),
('93df6e0d-b2f2-4248-b2a6-920a9200fdff','睡起','釋淨端','宋','宋诗','song-poetry','','[]','石枕藤床一榻低，覺來還自日沈西。',32,'全唐诗/poet.song.40000.json','["石枕藤床一榻低，覺來還自日沈西。", "白雲堆裏翻身轉，一曲漁歌在碧溪。"]'),
('8a44f499-f178-407f-b1e3-e0f111a02321','自述','釋淨端','宋','宋诗','song-poetry','','[]','瀟灑巖居畔，結茅惟一庵。',48,'全唐诗/poet.song.40000.json','["瀟灑巖居畔，結茅惟一庵。", "清風銷暑氣，寂寞少人貪。", "幽有鳥聲碎，禪無衲子參。", "齋餘林下去，華雨落毿毿。"]'),
('a594720f-5989-4f38-8294-75af4d2d0c36','山居','釋淨端','宋','宋诗','song-poetry','','[]','吳山古寺近溪邊，高閣虛堂景象全。',32,'全唐诗/poet.song.40000.json','["吳山古寺近溪邊，高閣虛堂景象全。", "林下寂寥爐火盡，未眠猶聽夜行船。"]'),
('1eaceda3-8b02-4ca2-b4f2-0264ad0ee25b','蘭若雜言  其一','釋淨端','宋','宋诗','song-poetry','','[]','吳山古寺寒松直，老鶴巢居最上頭。',32,'全唐诗/poet.song.40000.json','["吳山古寺寒松直，老鶴巢居最上頭。", "惟愛月明中夜後，一聲清唳滿山愁。"]'),
('69db3590-ad94-4fff-bf99-9a132dd1606f','蘭若雜言  其二','釋淨端','宋','宋诗','song-poetry','','[]','老嫌俗客來相訪，獨泛孤舟溪上游。',32,'全唐诗/poet.song.40000.json','["老嫌俗客來相訪，獨泛孤舟溪上游。", "夜宿蘆華賞明月，應無閑事掛心頭。"]'),
('6ff04205-52d0-4d29-9bd9-1723ebefce27','蘭若雜言  其三','釋淨端','宋','宋诗','song-poetry','','[]','老來無事掩柴扉，林下閑閑何所爲。',32,'全唐诗/poet.song.40000.json','["老來無事掩柴扉，林下閑閑何所爲。", "莫道茅庵無一物，窗前片片白雲飛。"]'),
('ed4159db-e0a9-4a9c-abe0-b01b6e56e562','蘭若雜言  其四','釋淨端','宋','宋诗','song-poetry','','[]','野老欣欣任自然，齋餘無事玩林泉。',32,'全唐诗/poet.song.40000.json','["野老欣欣任自然，齋餘無事玩林泉。", "門前竟日無人到，夜對喬松月在天。"]'),
('b178a3b6-124f-42c2-99b5-f7ce48d023df','蘭若雜言  其五','釋淨端','宋','宋诗','song-poetry','','[]','年老醒醒神更清，夜深幽室誦蓮經。',32,'全唐诗/poet.song.40000.json','["年老醒醒神更清，夜深幽室誦蓮經。", "兒孫睡覺應嫌我，石版時敲四五聲。"]'),
('e9b3b297-a38c-42ee-87a7-eab63e7501a3','蘭若雜言  其六','釋淨端','宋','宋诗','song-poetry','','[]','老拙懶陪塵俗客，茅屋掙坐復安眠。',32,'全唐诗/poet.song.40000.json','["老拙懶陪塵俗客，茅屋掙坐復安眠。", "林間莫道無看待，松竹溪山在目前。"]'),
('8f5d6fd5-7202-4e6c-b01c-a689bb09b0b8','蘭若雜言  其七','釋淨端','宋','宋诗','song-poetry','','[]','巖前松竹兩三株，日炙風吹漸已枯。',32,'全唐诗/poet.song.40000.json','["巖前松竹兩三株，日炙風吹漸已枯。", "葉落縱橫人不掃，清聲猶自響朝晡。"]'),
('ac863854-a59a-498b-89c7-a4f9fb8bb903','蘭若雜言  其八','釋淨端','宋','宋诗','song-poetry','','[]','因觀楊柳垂青眼，始覺人間春到來。',32,'全唐诗/poet.song.40000.json','["因觀楊柳垂青眼，始覺人間春到來。", "遙望南山雪消盡，寒梅猶有一枝開。"]'),
('5b829e10-65a1-4bd7-959f-a7b0046b908d','登慈雲嶺','釋淨端','宋','宋诗','song-poetry','','[]','千古慈雲嶺，諸方南北行。',24,'全唐诗/poet.song.40000.json','["千古慈雲嶺，諸方南北行。", "江波與湖水，極目兩分明。"]'),
('6d32ae53-22b7-4288-a7ff-0edebaa5534d','長興周承事相訪  其一','釋淨端','宋','宋诗','song-poetry','','[]','吳山長碧水長流，水轉山灣路更幽。',32,'全唐诗/poet.song.40000.json','["吳山長碧水長流，水轉山灣路更幽。", "多謝龐公遠相訪，旋燒松火薦茶甌。"]'),
('0b5a1820-096b-4382-abd2-5c930af3d194','長興周承事相訪  其二','釋淨端','宋','宋诗','song-poetry','','[]','漸覺清和四月天，一聲清磬響山川。',32,'全唐诗/poet.song.40000.json','["漸覺清和四月天，一聲清磬響山川。", "心澄氣爽無拘束，留得高人伴夜禪。"]'),
('1e3e1f45-7932-43a7-8af3-94f468a4d4cb','張居士相訪','釋淨端','宋','宋诗','song-poetry','','[]','清河居十別多年，一笑相逢信有緣。',32,'全唐诗/poet.song.40000.json','["清河居十別多年，一笑相逢信有緣。", "莫訝老僧無別話，平常心是祖師禪。"]'),
('f3b4e18e-1b6d-45c0-ae16-8e22b69c5e6b','答陸蒙老韻','釋淨端','宋','宋诗','song-poetry','','[]','枕上浮生過半百，短髮毿毿霜樣白。',128,'全唐诗/poet.song.40000.json','["枕上浮生過半百，短髮毿毿霜樣白。", "西溪河上舊家山，歲歲故鄉歸似客。", "船頭漸進古松門，云是吳筠讀書宅。", "煙雲半嶺望層樓，鰲頂崢嶸蘂宮窄。", "有人掛衲歸盤陀，稜稜瘦骨真維摩。", "幾年面壁舌不動，忽然拍手賡漁歌。", "秋來滿船載明月，俄驚雨笠仍煙蓑。", "黄梅渡口水流急，五湖深處任風波。"]'),
('087b2732-67a2-44fe-b7c0-03ae1bd12402','送客之三衢','釋淨端','宋','宋诗','song-poetry','','[]','今日忽相見，俄然又相別。',24,'全唐诗/poet.song.40000.json','["今日忽相見，俄然又相別。", "三衢山水清，好賞中秋月。"]'),
('556f0ff8-fc3d-491b-9911-71331aa93f8f','題假山石','釋淨端','宋','宋诗','song-poetry','','[]','無用無知頑石頭，天生奇巧世人求。',32,'全唐诗/poet.song.40000.json','["無用無知頑石頭，天生奇巧世人求。", "算來世上無閑物，假使無情不自由。"]'),
('a3afebc1-1453-4da4-a5cf-c2d74afb1af7','會曇老','釋淨端','宋','宋诗','song-poetry','','[]','漁家生計好，終日泛輕舟。',48,'全唐诗/poet.song.40000.json','["漁家生計好，終日泛輕舟。", "剪竹爲竿釣，裁荷作酒甌。", "只知溪上樂，不識世間愁。", "昨夜巖隈下，蓑衣忘卻收。"]'),
('874b31cb-5def-4a54-a955-77fdb7f6af67','祥符寺溪堂','釋淨端','宋','宋诗','song-poetry','','[]','開窗滿日見溪山，霅水東流下嶺灣。',32,'全唐诗/poet.song.40000.json','["開窗滿日見溪山，霅水東流下嶺灣。", "夜月深明漁舫寂，白雲無事到禪關。"]'),
('b0bbb1df-3c10-47e1-964c-9c6bbf553535','述懷','釋淨端','宋','宋诗','song-poetry','','[]','晦跡歸巖塢，僻居人到稀。',72,'全唐诗/poet.song.40000.json','["晦跡歸巖塢，僻居人到稀。", "披衣眠靜榻，策杖遶荆扉。", "遠謝名兼利，能忘是與非。", "松風祛暑薄，山月照螢微。", "烹茗滿甌雪，掬泉半濕衣。", "窮通雲意密，終與世人違。"]'),
('6bcec0b8-bd31-4a38-8a30-96e8b19d2a81','題吉祥寺茶山','釋淨端','宋','宋诗','song-poetry','','[]','吉祥山水與雲連，清韻來聞二十年。',32,'全唐诗/poet.song.40000.json','["吉祥山水與雲連，清韻來聞二十年。", "知道老僧無熟惱，金沙地內不流泉。"]'),
('895f2172-9090-483b-b950-8f989dbc2d38','同蘇饒文宿吉祥寺二首  其一','釋淨端','宋','宋诗','song-poetry','','[]','孤峰峻嶺翠光寒，山勢奔湖去又蟠。',32,'全唐诗/poet.song.40000.json','["孤峰峻嶺翠光寒，山勢奔湖去又蟠。", "今夜虎頭巖下宿，更無歸夢出林巒。"]'),
('c1df886d-c5ba-469a-aa23-b740af0ee419','同蘇饒文宿吉祥寺二首  其二','釋淨端','宋','宋诗','song-poetry','','[]','與公昔作長城別，一去塵埃六七年。',32,'全唐诗/poet.song.40000.json','["與公昔作長城別，一去塵埃六七年。", "夜靜書堂尋舊約，定將生計話林泉。"]'),
('da8e5872-1c90-42fe-bd50-0990fad6437d','送上方亮老','釋淨端','宋','宋诗','song-poetry','','[]','何故無心戀霅溪，鄣南風景白雲齊。',32,'全唐诗/poet.song.40000.json','["何故無心戀霅溪，鄣南風景白雲齊。", "有人若問宗門事，水自東流日自西。"]'),
('5d316eb8-543b-472b-ac4d-0d9fc4be4106','山居  其一','釋淨端','宋','宋诗','song-poetry','','[]','人事悠悠懶更攀，茅堂靜坐白雲閑。',32,'全唐诗/poet.song.40000.json','["人事悠悠懶更攀，茅堂靜坐白雲閑。", "夜觀明月爲高燭，一道清光照萬山。"]'),
('b6d07a6c-b174-4d22-ab26-91922829ad29','山居  其二','釋淨端','宋','宋诗','song-poetry','','[]','水澄山色映青天，靜坐茅堂未欲眠。',32,'全唐诗/poet.song.40000.json','["水澄山色映青天，靜坐茅堂未欲眠。", "好玩巖頭松與月，更聞高柳一聲蟬。"]'),
('dc0f722f-7841-484f-8376-bf92311eec7d','山居  其三','釋淨端','宋','宋诗','song-poetry','','[]','耳聾不聽樓頭鼓，眼暗難看夜半燈。',32,'全唐诗/poet.song.40000.json','["耳聾不聽樓頭鼓，眼暗難看夜半燈。", "一曲漁歌聲盡後，歸雲天外自騰騰。"]'),
('db8e55df-f83a-4d1f-a325-0dd4bf670cce','贈長興王省元','釋淨端','宋','宋诗','song-poetry','','[]','誰測先生意趣難，貧如原憲學宗顔。',32,'全唐诗/poet.song.40000.json','["誰測先生意趣難，貧如原憲學宗顔。", "年年酒債將琴當，歲歲詩狂待月還。"]'),
('8cb687de-2373-4288-ad14-74d900e39c9f','喜子勝仲登第','葛書思','宋','宋诗','song-poetry','','[]','廣場筆陣數千人，喜汝穿楊箭鏃親。',64,'全唐诗/poet.song.40000.json','["廣場筆陣數千人，喜汝穿楊箭鏃親。", "慶緒綿長時幸會，文科興復事還新。", "昔年繼榜熙寧歲，今偶同科紹聖春。", "從此莫教書種斷，孫曾應復值昌辰。"]'),
('495765e5-77c2-43f6-b957-84206fb96295','宿悟空院','葛書思','宋','宋诗','song-poetry','','[]','高枕僧房夜漏深，經窗俄見月華侵。',64,'全唐诗/poet.song.40000.json','["高枕僧房夜漏深，經窗俄見月華侵。", "抗塵走俗成何事，問道參禪徒在心。", "智鏡直須真裏照，機鋒莫向句中尋。", "悟空不見悟空者，漫對寒燈擁鼻吟。"]'),
('ffcb23de-6d7b-4631-9dcd-8c154f43370e','宿廣福寺','葛書思','宋','宋诗','song-poetry','','[]','我非山中人，暫借山中宿。',108,'全唐诗/poet.song.40000.json','["我非山中人，暫借山中宿。", "靈風散微陰，片月出喬木。", "蕙帳棲夕香，古井汲寒淥。", "名緇多夙契，延坐同茗粥。", "況與靜者俱，繕性久已熟。", "清詞麗陶謝，玄談幹身毒。", "所愧形跡拘，無由寄高躅。", "鐘聲殷江島，露氣靄林麓。", "良遇愜素懷，徘徊至天旭。"]'),
('a780eee2-b050-4906-a3f6-9386cdd161c6','解日字謎','呂惠卿','宋','宋诗','song-poetry','','[]','東海有一魚，無頭亦無尾。',24,'全唐诗/poet.song.40000.json','["東海有一魚，無頭亦無尾。", "更除脊樑骨，便是這個謎。"]'),
('87754639-e09c-4ec1-9fb2-449f319b2514','答逢原','呂惠卿','宋','宋诗','song-poetry','','[]','晨出趨長司，跪坐與之言。',288,'全唐诗/poet.song.40000.json','["晨出趨長司，跪坐與之言。", "偶然脫齟齬，相送顔色溫。", "歸舍未休鞍，簿書隨滿門。", "相仍賓客過，攲午僅朝餐。", "平生性懶惰，應接非吾真。", "況乃重戕賊，良氣能幾存。", "就夜甫得息，閱我几上文。", "開卷未及讀，睡思已昏昏。", "自知小人歸，昭昭復何雲。", "每於清夜夢，多見夫子魂。", "側耳聽高議，如飲黄金樽。", "覺來不得往，欲飛無羽翰。", "昨日得子詩，我心子先論。", "怪我詩苦遲，友道宜所敦。", "豈不旦夕思，實苦案牘煩。", "豈無同官賢，未免走與奔。", "相見鞅掌間，有言無暇陳。", "嗟嗟茲世士，無食同所患。", "念我力難任，聞子謀更艱。", "久知爲之天，安能怨窶貧。", "吾聞君子仕，行義而已焉。", "亦將達吾義，豈遂爲利牽。", "東海有滄溟，西極有崑崙。", "古來到者誰，不過數子尊。"]'),
('1865dd74-b892-4b70-a237-fd42c36599e2','戲題風乞兒扇','呂惠卿','宋','宋诗','song-poetry','','[]','無人肯作除非乞，沒藥堪醫最是風。',32,'全唐诗/poet.song.40000.json','["無人肯作除非乞，沒藥堪醫最是風。", "求乞害風都占斷，算來世上少如公。"]'),
('c6ecf5fc-5364-4cc5-af37-42fc182e7abe','留題興安王廟','呂惠卿','宋','宋诗','song-poetry','','[]','翦葉疏封意，歸禾協濟心。',48,'全唐诗/poet.song.40000.json','["翦葉疏封意，歸禾協濟心。", "遺風固唐遠，積德本周深。", "逝水悲興廢，浮雲閱古今。", "祠宮尚翬翼，鳴玉漱松陰。"]'),
('a3f3a50e-4d4e-4e31-b4e1-f448fe009c81','句  其一','呂惠卿','宋','宋诗','song-poetry','','[]','魚出清波庖膾玉，菊含寒露酒浮金。',16,'全唐诗/poet.song.40000.json','["魚出清波庖膾玉，菊含寒露酒浮金。"]'),
('33f196f7-65ab-49ee-9a23-9810607bb385','句  其二','呂惠卿','宋','宋诗','song-poetry','','[]','南北戰爭蝸兩角，占今興廢貉同丘。',16,'全唐诗/poet.song.40000.json','["南北戰爭蝸兩角，占今興廢貉同丘。"]'),
('629d958e-2568-4935-a081-c711d6eeed71','句  其三','呂惠卿','宋','宋诗','song-poetry','','[]','虛心清暑殿，預戒一陰生。',12,'全唐诗/poet.song.40000.json','["虛心清暑殿，預戒一陰生。"]'),
('48b7e907-25a4-4ecb-b862-368a5ccf9c51','贈吉甫侄','呂川','宋','宋诗','song-poetry','','[]','峨眉月浸千秋雪，太華峰搖十丈蓮。',32,'全唐诗/poet.song.40000.json','["峨眉月浸千秋雪，太華峰搖十丈蓮。", "一見升平玉清客，雪蓮聲價頓銷然。"]'),
('21bf4a8b-1aa9-42f9-bffa-ca0e08e9e936','贈致仕郭朝議','呂川','宋','宋诗','song-poetry','','[]','漫道任公釣有神，六鼇無跡海生塵。',32,'全唐诗/poet.song.40000.json','["漫道任公釣有神，六鼇無跡海生塵。", "爭如靜臥南窗下，蘭菊從教秋與春。"]'),
('3366e1d7-0869-40d6-aa7e-414f5acb851c','浯溪','楊冀','宋','宋诗','song-poetry','','[]','長安失馭頌聲沈，作者誰能刻翠岑。',64,'全唐诗/poet.song.40000.json','["長安失馭頌聲沈，作者誰能刻翠岑。", "大業盡歸文老筆，中興還死叛臣心。", "天邊奎壁垂芒冷，溪上龍蛇倒影深。", "當日形容播金石，洋洋千載有遺音。"]'),
('e4f411ec-c600-427a-9da1-8a364425dcfe','送程給事知越州','王靖','宋','宋诗','song-poetry','','[]','蜀道新持使節優，南昌更命按諸侯。',64,'全唐诗/poet.song.40000.json','["蜀道新持使節優，南昌更命按諸侯。", "江山秀入行臺曉，風月吟余澤國秋。", "寬弛茶租吳俗富，興驪渠利晉人謳。", "送將莫訝遲留處，浩穰敲喧訟牒稠。"]'),
('8ed52b04-99ee-48d6-afc7-8293ec5e5ac2','句','王靖','宋','宋诗','song-poetry','','[]','欲往海上吞鯨鯢。',8,'全唐诗/poet.song.40000.json','["欲往海上吞鯨鯢。"]'),
('e8ddc67f-5c8d-440d-875a-54efbf6302f6','和王舉元柏谷山院','韓標','宋','宋诗','song-poetry','','[]','附驥遊僧刹，天清曉色開。',48,'全唐诗/poet.song.40000.json','["附驥遊僧刹，天清曉色開。", "園林噴雨過，殿閣踏雲來。", "日轉花陰薄，山深磴道迴。", "憑欄堪寫望，隴麥翠如堆。"]'),
('d6154572-c4a9-4c42-9a62-e00439dcc3cc','唐卿既篆歐公侍郎滁州琅邪山醉翁亭記上石訖思莫能致之滁上因斧官之隙地眾材堪棟梁者枝其榱桷構堂於廨舍西偏高三仞植記於中楹若屏然圖悠久也因成長句五十六字以詩其名兼寄獻歐公侍郎','蘇唐卿','宋','宋诗','song-poetry','','[]','醉翁亭記醉翁堂，遠取琅邪近費鄉。',64,'全唐诗/poet.song.40000.json','["醉翁亭記醉翁堂，遠取琅邪近費鄉。", "高世雄文刊翠琰，老山孤幹負虹梁。", "左鄰鼇海三神島，西倚儒宮數仞牆。", "雖愧篆工非墨寶，英辭終與借輝光。"]'),
('5849c56f-47e3-4dbe-bad7-824c3639286e','再和諸公佳作','蘇唐卿','宋','宋诗','song-poetry','','[]','老文新刊立新堂，千里騰輝賁兩鄉。',64,'全唐诗/poet.song.40000.json','["老文新刊立新堂，千里騰輝賁兩鄉。", "江漢驪珠探作寶，龜蒙文桂斷爲梁。", "英辭美陋瓊瑤室，古篆工羞糞上牆。", "陵谷燮遷解訛缺，後賢何惜補休光。"]'),
('681e980a-b8d5-4597-b600-fba6857fbf1b','和蘇唐卿','龔敦','宋','宋诗','song-poetry','','[]','滁守南遷記醉狂，篆刊移近舞雩鄉。',64,'全唐诗/poet.song.40000.json','["滁守南遷記醉狂，篆刊移近舞雩鄉。", "當年寓興臨山水，今日希風構棟梁。", "吏部喪文辭避席，陽冰閣筆讓循牆。", "東沂從此遺聲跡，迥掩桐廬翰墨光。"]'),
('4bd35099-83c8-49db-8f32-bbc0816bbbf9','和蘇唐卿','史辭','宋','宋诗','song-poetry','','[]','昔日歐公鎮永陽，構亭直在水雲鄉。',64,'全唐诗/poet.song.40000.json','["昔日歐公鎮永陽，構亭直在水雲鄉。", "醉翁嘯傲曾爲記，賢宰風流別駕梁。", "老筆健遒刊琬琰，晴嵐滴瀝照門牆。", "更吟新詠深堂秘，相伴崑山片玉光。"]'),
('3763a7b3-1172-46e9-b9de-610c5e68e65f','篆書醉翁亭記石刻','邵忱','宋','宋诗','song-poetry','','[]','歐公頃歲守滁陽，題記蒼顔入醉鄉。',64,'全唐诗/poet.song.40000.json','["歐公頃歲守滁陽，題記蒼顔入醉鄉。", "賢宰特將刊古篆，舊碑不免棄山梁。", "軒楹別構如安屏，筆札難通似面牆。", "異口智仙來輦坐，退蒙從此謝聲光。"]'),
('9b6e01b2-3d66-486c-87b2-cb51f9be9cbe','頌','李特','宋','宋诗','song-poetry','','[]','出沒雲閑滿太虛，元來真相一塵無。',32,'全唐诗/poet.song.40000.json','["出沒雲閑滿太虛，元來真相一塵無。", "重重請問西來意，唯指庭前柏一株。"]'),
('065a613c-9f1d-4f94-b552-eddb5aeccf26','頌','慧禪師','宋','宋诗','song-poetry','','[]','朝朝日出東方，夜夜月落西戶。',28,'全唐诗/poet.song.40000.json','["朝朝日出東方，夜夜月落西戶。", "如今大宋官家，儘是金枝玉樹。"]'),
('cada6cb8-d7b1-465f-ae80-577f05d81dd3','偈','釋靈運','宋','宋诗','song-poetry','','[]','夜來雲雨散長空，月在森羅萬象中。',32,'全唐诗/poet.song.40000.json','["夜來雲雨散長空，月在森羅萬象中。", "萬象靈光無內外，當明一句若爲通。"]'),
('c244af08-bef3-47a1-81a6-ac6c15fc9c64','頌魯祖面壁','釋善冀','宋','宋诗','song-poetry','','[]','魯祖三昧最省力，纔見僧來便面壁。',32,'全唐诗/poet.song.40000.json','["魯祖三昧最省力，纔見僧來便面壁。", "若是知心達道人，不在揚眉便相悉。"]'),
('779a8bc9-4da8-4aef-9b78-92faa06760f6','頌','釋令滔','宋','宋诗','song-poetry','','[]','放卻牛繩便出家，剃除鬚髮著袈裟。',32,'全唐诗/poet.song.40000.json','["放卻牛繩便出家，剃除鬚髮著袈裟。", "有人問我西來意，拄杖橫挑囉哩囉。"]'),
('62287376-f41e-4e39-99fc-213cd47f9f65','答李陶','章阿父','宋','宋诗','song-poetry','','[]','通身一點法，四海永絕倫。',36,'全唐诗/poet.song.40000.json','["通身一點法，四海永絕倫。", "開得天關路，閉得地戶門。", "若要求長生，到斷五行因。"]'),
('d570a41f-e6bc-43e2-b1e5-f7a0b51dc267','性慵','黄希旦','宋','宋诗','song-poetry','','[]','性傭人事拙，思向遠山居。',48,'全唐诗/poet.song.40000.json','["性傭人事拙，思向遠山居。", "欲得是非少，先宜來往疏。", "善鄰惟水竹，良友秪琴書。", "冷淡生涯外，逍遙一室虛。"]'),
('5e060258-1235-4129-baae-afe80cda37e6','頤真亭','黄希旦','宋','宋诗','song-poetry','','[]','剪去舊蒿萊，開亭養聖胎。',48,'全唐诗/poet.song.40000.json','["剪去舊蒿萊，開亭養聖胎。", "閉開虛室白，隱几寸心灰。", "月上池浮露，風生竹掃苔。", "悠悠奔競者，何處問丹臺。"]'),
('7479dfb7-8ebd-4fe2-9942-90204c128ce3','春日書懷和韻','黄希旦','宋','宋诗','song-poetry','','[]','二月又將半，閑居興若何。',48,'全唐诗/poet.song.40000.json','["二月又將半，閑居興若何。", "芳菲殊未賞，泥濘阻相過。", "華砌饒苔蘚，柴門長薜蘿。", "韶顔須自惜，隨分樂天和。"]'),
('15303736-f323-4aa3-895a-bb07e9f46d62','采藥','黄希旦','宋','宋诗','song-poetry','','[]','采藥山中去，扳躋不覺賒。',48,'全唐诗/poet.song.40000.json','["采藥山中去，扳躋不覺賒。", "深源無俗跡，滿地是靈芽。", "巖迥陰留雪，溪澄淨見沙。", "可憐名利客，應笑此生涯。"]'),
('c193d5ad-f442-4650-ae7e-47c471618931','和人秋感','黄希旦','宋','宋诗','song-poetry','','[]','烈士感秋興，高吟擊太阿。',48,'全唐诗/poet.song.40000.json','["烈士感秋興，高吟擊太阿。", "功名辜壯志，歲月歎流波。", "永巷蛩初響，荒階葉漸多。", "靈槎如可約，從此泛銀河。"]'),
('1e6eb1fc-1289-43ca-aa3b-b1bd6f48d89e','水心亭','黄希旦','宋','宋诗','song-poetry','','[]','爲愛方池淨，危亭此構新。',48,'全唐诗/poet.song.40000.json','["爲愛方池淨，危亭此構新。", "寒光搖玉鑒，晴色戲金鱗。", "月上驪宮曉，蓮開水府春。", "主人能息慮，四座絕風塵。"]'),
('01b651ff-62c3-4b61-928b-8619486956f7','詠竹','黄希旦','宋','宋诗','song-poetry','','[]','生涯何所有，滿砌植琳琅。',48,'全唐诗/poet.song.40000.json','["生涯何所有，滿砌植琳琅。", "瘦影碎秋月，健梢橫曉霜。", "且從喧鳥雀，終待集鸞鳳。", "吟遶都忘卻，誰知此興長。"]'),
('6371b8d4-d6cd-4d4c-be83-e03ed58e2edc','二月春將半三首  其一','黄希旦','宋','宋诗','song-poetry','','[]','二月春將半，幽居掩竹齋。',24,'全唐诗/poet.song.40000.json','["二月春將半，幽居掩竹齋。", "自慚疏懶甚，苔蘚滿空階。"]'),
('aa88210d-3cb7-4015-b89f-40b288bb8790','二月春將半三首  其二','黄希旦','宋','宋诗','song-poetry','','[]','二月春將半，農耕細雨中。',24,'全唐诗/poet.song.40000.json','["二月春將半，農耕細雨中。", "花前輕薄子，醉倒笑春風。"]'),
('690b49b4-d36d-4ea4-9401-179c966a5fc6','二月春將半三首  其三','黄希旦','宋','宋诗','song-poetry','','[]','二月春將半，霖霪雨尚寒。',24,'全唐诗/poet.song.40000.json','["二月春將半，霖霪雨尚寒。", "松黄收拾晚，狼籍滿金壇。"]'),
('891636e0-0504-437f-8fe3-31ea8fae3298','贈逸人','黄希旦','宋','宋诗','song-poetry','','[]','白雲處士入雲中，三尺焦琴百尺松。',32,'全唐诗/poet.song.40000.json','["白雲處士入雲中，三尺焦琴百尺松。", "長嘯一聲寒澗遠，千崖萬壑起清風。"]'),
('a7c1d7ea-7e9a-484f-82e1-769812493718','寄贈寶幢修山主','黄希旦','宋','宋诗','song-poetry','','[]','瑤幢真勝概，晦跡一禪翁。',48,'全唐诗/poet.song.40000.json','["瑤幢真勝概，晦跡一禪翁。", "語默呈心印，縱橫振祖風。", "晝閑人事外，夜靜月華中。", "若問春來意，松青百卉紅。"]'),
('ab595ba9-a628-4b75-85c3-b0f9fce30ac9','秋日登樓','黄希旦','宋','宋诗','song-poetry','','[]','高閣倚斜陽，登臨覺倍涼。',48,'全唐诗/poet.song.40000.json','["高閣倚斜陽，登臨覺倍涼。", "殘蟬空自咽，歸燕爲誰忙。", "蔽日雲頭猛，沿山雨腳長。", "竹村溪上影，彷佛似瀟湘。"]'),
('a07d1df4-7e00-4201-a9e3-e1624779e92a','懷中孚','黄希旦','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','暌違雖未久，南走夢魂多。',48,'全唐诗/poet.song.40000.json','["暌違雖未久，南走夢魂多。", "客路隨飄梗，年光歎擲梭。", "葉凋隋苑樹，風走洞庭波。", "舊約龍山會，歸來赴若何。"]'),
('6cf508b6-455b-43bf-863b-7ce128645276','晚眺','黄希旦','宋','宋诗','song-poetry','','[]','晚涼思遠眺，策杖出松林。',48,'全唐诗/poet.song.40000.json','["晚涼思遠眺，策杖出松林。", "車馬自來往，路岐橫古今。", "商飈未落葉，永巷已鳴砧。", "自笑眠雲客，因時感激深。"]'),
('493ec72b-6948-4b99-a1a8-c601c047079d','寄友人','黄希旦','宋','宋诗','song-poetry','','[]','性僻少知已，惟君日往還。',48,'全唐诗/poet.song.40000.json','["性僻少知已，惟君日往還。", "聽琴憐寂靜，賒酒笑艱難。", "俗眼從他白，吾儕且任閑。", "生涯人莫問，到處有雲山。"]'),
('f1f460d8-1a35-43e2-82f3-247a8edf76b1','簡襲慶齋主人','黄希旦','宋','宋诗','song-poetry','','[]','雨過浮山好，無如襲慶齋。',48,'全唐诗/poet.song.40000.json','["雨過浮山好，無如襲慶齋。", "主人操大雅，樓閣俯蒼崖。", "檻碧搖新柳，庭黄發嫩槐。", "登臨詩酒興，此際與誰偕。"]'),
('f688868e-6a22-4085-9926-0a4d31f09084','遠遊','黄希旦','宋','宋诗','song-poetry','','[]','自在遠遊去，閑門誰見遇。',48,'全唐诗/poet.song.40000.json','["自在遠遊去，閑門誰見遇。", "援琴空轉軫，對酒不成歌。", "秋景生新桂，涼風撼敗荷。", "天涯誰是侶，歲暮莫蹉跎。"]'),
('ee1e7d50-52dd-42db-baa4-84bbc1442746','秋半','黄希旦','宋','宋诗','song-poetry','','[]','晚吹生叢竹，淒涼又半秋。',48,'全唐诗/poet.song.40000.json','["晚吹生叢竹，淒涼又半秋。", "年華驚倏忽，人事覺淹留。", "林噪殘蟬急，山光暮雨收。", "登臨將眺望，煙霧閉層樓。"]'),
('e99926ea-dc51-47f2-a15a-6685ce0a81f5','古意','黄希旦','宋','宋诗','song-poetry','','[]','大道長閑閑，人心自草草。',60,'全唐诗/poet.song.40000.json','["大道長閑閑，人心自草草。", "天地固無私，賢愚同一老。", "誰信丹丘人，顔色常美好。", "我亦斯人徒，相從須及早。", "君看東流波，日夜長浩浩。"]'),
('e0defa11-14ba-439c-b2b0-0af69bbc2e3a','寄益老侍官南康','黄希旦','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','匡山勝概昔賢欽，今日多君復訪尋。',64,'全唐诗/poet.song.40000.json','["匡山勝概昔賢欽，今日多君復訪尋。", "李白書堂螢自照，樂天撣室月空臨。", "澗松巖檜當年色，霧鶴霜猿此際音。", "莫對他山忘故里，武夷秋晚洞雲深。"]'),
('3a41e1f5-5ec5-4e15-bb66-ba90651af9e6','竹洞','黄希旦','宋','宋诗','song-poetry','','[]','竹洞新開碧玉林，徑幽疑入五華深。',64,'全唐诗/poet.song.40000.json','["竹洞新開碧玉林，徑幽疑入五華深。", "夜篩明月一天靜，晝擁青雲四座陰。", "剪杖佇看雷雨化，迎風時聽鳳凰吟。", "煙霞不用重關閉，塵俗誰能此訪尋。"]'),
('84beac61-eac9-4a45-9c64-a284dda9f988','燈夕和韻','黄希旦','宋','宋诗','song-poetry','','[]','年年此夕鬨閭閻，豈料閑居興自恬。',64,'全唐诗/poet.song.40000.json','["年年此夕鬨閭閻，豈料閑居興自恬。", "競逐豔陽遊冶去，寧知華髮等閑添。", "火連夜市曾無禁，燈混星文不可占。", "聞道玉樓歡宴處，夜闌猶未卷珠簾。"]'),
('6f6c5910-bef7-4db4-a082-afc7f3eb1560','讀禪月集','黄希旦','宋','宋诗','song-poetry','','[]','唐末高僧號貫休，篇章激切近詩流。',64,'全唐诗/poet.song.40000.json','["唐末高僧號貫休，篇章激切近詩流。", "煙華雪月何妨詠，水竹雲林不礙遊。", "蜀國至今名籍甚，蘭溪當日跡淹留。", "此心彈指雖云妙，爭奈闍黎未點頭。"]'),
('f39bac19-799d-4751-84c0-e4b55577de5a','閑居','黄希旦','宋','宋诗','song-poetry','','[]','草堂嘯傲動經年，已把生涯付自然。',64,'全唐诗/poet.song.40000.json','["草堂嘯傲動經年，已把生涯付自然。", "謾費工夫披古籍，懶通名字謁時賢。", "爐中閑養陰陽火，身外誰求子母錢。", "寄語王褒如著論，不同呼吸學神仙。"]'),
('b911992f-dcfb-41bc-915a-bd4d455ef4d3','寄李尊師','黄希旦','宋','宋诗','song-poetry','','[]','底事悠悠信莫聞，還疑深入武陵源。',64,'全唐诗/poet.song.40000.json','["底事悠悠信莫聞，還疑深入武陵源。", "幾年江上秋風夜，故國閩中暮雨村。", "塵世功名寧自笑，蓬壺旨趣有誰論。", "路岐無盡人空老，白髮慈親奈倚門。"]'),
('e52b6ad2-95df-40fb-9470-5d9c26eeaafc','謝人惠星冠','黄希旦','宋','宋诗','song-poetry','','[]','學道多年尚屈蟠，豈勝仙伯贈峨冠。',64,'全唐诗/poet.song.40000.json','["學道多年尚屈蟠，豈勝仙伯贈峨冠。", "曉簪乍覺星攢頂，夜戴偏宜月滿壇。", "對鑑寧煩朋友正，避時羞爲利名彈。", "豫思他日雲林下，輕罩紗巾鶴髪寒。"]'),
('c0905789-f121-4e9a-811a-0bf2747804cf','幔亭','黄希旦','宋','宋诗','song-poetry','','[]','曾孫嘗會幔亭中，脯擘麒麟酒滿鍾。',32,'全唐诗/poet.song.40000.json','["曾孫嘗會幔亭中，脯擘麒麟酒滿鍾。", "宴罷不知消息處，至今鄉老望孤峰。"]'),
('7e8f5444-4c17-4fb0-935e-5a27453098e4','讀方干詩','黄希旦','宋','宋诗','song-poetry','','[]','數篇騷雅名雖遠，三拜逢迎禮過差。',32,'全唐诗/poet.song.40000.json','["數篇騷雅名雖遠，三拜逢迎禮過差。", "補得唇來身巳老，灌園何苦更咨嗟。"]'),
('3392bcde-22ea-4154-9d48-9e43ef55285d','和賈鴻舉移竹','黄希旦','宋','宋诗','song-poetry','','[]','琳房珠館何虛寂，寶砌無塵苔蘚碧。',160,'全唐诗/poet.song.40000.json','["琳房珠館何虛寂，寶砌無塵苔蘚碧。", "仙翁倚檻靜吟哦，卻憶篔簹拂巖石。", "勁節虛心守歲寒，未嘗暫變風霜色。", "移來迢遞不辭勞，深根訝向瑤臺植。", "漸承春意葉青青，時惹天香煙冪冪。", "月籠翠影尚蕭疏，露被繁枝讒滴瀝。", "迎風閑夜擬龍吟，結實他年期鳳食。", "非才終約老煙霞，此際謬當親採擇。", "寄言紅紫莫相猜，彼此無情蒙化力。", "逢時剪拂任他人，沈去葛陂都咫尺。"]'),
('98e2152c-3f4b-4d09-a249-0dcf04aec665','感時行','黄希旦','宋','宋诗','song-poetry','','[]','勸君莫種木槿花，朝榮暮落堪咨嗟。',92,'全唐诗/poet.song.40000.json','["勸君莫種木槿花，朝榮暮落堪咨嗟。", "勸君種取亭亭竹，霜繁風勁依然綠。", "誰不見陳余張耳輩，當面論交旋踵背。", "又不見管鮑光武與嚴光，貧賤富貴難相忘。", "英聲獨與天地長，令人萬古遙相望，不可得見空徬徨。"]'),
('9a3a7fa1-6155-40a7-8619-511d7ab16ab4','觀申公山水','黄希旦','宋','宋诗','song-poetry','','[]','申公山水老更狂，躭躭巨耳雙瞳方。',128,'全唐诗/poet.song.40000.json','["申公山水老更狂，躭躭巨耳雙瞳方。", "生涯禿筆數千管，欲與造化爭毫芒。", "長煙三素掛四壁，經營指點何安詳。", "凝神淨慮偶得意，一灑混沌開玄黄。", "須臾三才及萬類，迤邐筆下分低昂。", "水寒石瘦老木怪，蒹葭岸占天蒼蒼。", "伊餘本是山間叟，對此直欲乘風翔。", "咫尺杳然數萬里，直疑跳入壺中藏。"]'),
('3f8d4cda-439c-45f3-83e6-7fd2ea9fa7ac','寄友人','黄希旦','宋','宋诗','song-poetry','','[]','昔遊西太乙，今日返成都。',24,'全唐诗/poet.song.40000.json','["昔遊西太乙，今日返成都。", "若問去來事，雲藏月影孤。"]'),
('a4ae75c2-ee15-46d5-bc58-977c136aa999','試心石','黄希旦','宋','宋诗','song-poetry','','[]','屏列郡南隅，子真常此憩。',24,'全唐诗/poet.song.40000.json','["屏列郡南隅，子真常此憩。", "雨欲澤人間，雲霞先掩蔽。"]'),
('398d6dbc-3a84-4d72-b514-9b21c4549bc5','西庵寺','黄希旦','宋','宋诗','song-poetry','','[]','勝刹幽深枕縣西，我來正值孟冬時。',64,'全唐诗/poet.song.40000.json','["勝刹幽深枕縣西，我來正值孟冬時。", "雖無慧遠門堪叩，幸有陶潛駕可隨。", "世態階前朝槿色，歲寒雲外老松枝。", "繄余本是林泉客，到此寧慚漫賦詩。"]'),
('85854de9-da90-428f-a393-c4184f1afa3f','九龍觀','黄希旦','宋','宋诗','song-poetry','','[]','峨峨古仙宮，樓殿蔭松柏。',168,'全唐诗/poet.song.40000.json','["峨峨古仙宮，樓殿蔭松柏。", "昔在貞觀年，天皇御區域。", "九龍出池中，遺下靈蹤跡。", "嘉祐辛丑歲，郡侯得召伯。", "是時夏六月，雲日紅翕赩。", "殿北古龍堂，窗戶久不闢。", "俄然靈蛇見，宛轉真像側。", "鱗甲錦繡文，燦爛輝五色。", "眎之頗馴擾，狎之不驚煬。", "邯侯率群僚，朋來擁旌戟。", "遲留夜未午，風雨滿天黑。", "迅電瞥四起，狂雷隨一擊。", "須臾風雨收，形影誰能覓。", "斯蓋龍之靈，變化固難測。"]'),
('8d021eaa-4c01-4d14-a255-1dd6418b0ad2','偈','黄希旦','宋','宋诗','song-poetry','','[]','地水火風，強名四大。',40,'全唐诗/poet.song.40000.json','["地水火風，強名四大。", "迷蕩真源，種種憎愛。", "咄哉憨癡，會即便會。", "雲散月明，朗同沙界。"]'),
('557bcc01-3cff-4c8d-9cd3-e03ba5b6e31b','越王臺','黄希旦','宋','宋诗','song-poetry','','[]','荒臺枕古邱，伊昔越王遊。',24,'全唐诗/poet.song.40000.json','["荒臺枕古邱，伊昔越王遊。", "輦路今何在，淒涼草樹秋。"]'),
('8ffbadae-4567-4c12-952e-600959959379','王官谷十詠 竹逕','俞充','宋','宋诗','song-poetry','','[]','入谷修竹密，蒼翠連前山。',48,'全唐诗/poet.song.40000.json','["入谷修竹密，蒼翠連前山。", "車馬跡不到，鷄犬音亦聞。", "蔽日清影合，迎風碎聲寒。", "漸近居士廬，溪水流潺潺。"]'),
('07f6d519-da3f-45ac-b34d-d3f92c619688','王官谷十詠 貽溪','俞充','宋','宋诗','song-poetry','','[]','濯纓溪流上，清心共澄澈。',48,'全唐诗/poet.song.40000.json','["濯纓溪流上，清心共澄澈。", "人存魚自躍，人亡魚亦竭。", "此意雖冥冥，可與仁者說。", "遣音競誰繼，十里閑風月。"]'),
('af2f357a-7de4-4194-80a1-7f34e6976a18','王官谷十詠 休休亭','俞充','宋','宋诗','song-poetry','','[]','洗耳謝市朝，構亭得餘址。',48,'全唐诗/poet.song.40000.json','["洗耳謝市朝，構亭得餘址。", "三徑草長深，一毫塵不起。", "支肘看青山，引鶴聽流水。", "獨有愛君心，時時擬綸旨。"]'),
('b2b55fbd-8b20-48ac-a276-88897db3ff1c','王官谷十詠 表聖影堂','俞充','宋','宋诗','song-poetry','','[]','事去惟山存，遣祠臨水曲。',48,'全唐诗/poet.song.40000.json','["事去惟山存，遣祠臨水曲。", "峻節凌雪霜，英顔瑩冰玉。", "至今崖壁間，尚耐塵埃辱。", "清風滿林泉，千戴仰高躅。"]'),
('2c12bb1c-ca43-4753-86f8-3d015f00cd4c','王官谷十詠 天柱峰','俞充','宋','宋诗','song-poetry','','[]','擎天有八柱，是峰居其一。',48,'全唐诗/poet.song.40000.json','["擎天有八柱，是峰居其一。", "根蟠地軸壯，群山俯爲碩。", "共工觸不折，萬古聳崒嵂。", "幽人步絕頂，引手攀星日。"]'),
('6fd0ccf3-83a9-4d35-8f58-37dc0e75e5d9','王官谷十詠 瑩心亭','俞充','宋','宋诗','song-poetry','','[]','野老傳此水，源與洪河透。',48,'全唐诗/poet.song.40000.json','["野老傳此水，源與洪河透。", "潺潺浩難窮，雨雹灑晴晝。", "巖頭白龍掛，灘前寒玉漱。", "不見瑩心人，客衣冷如漚。"]'),
('d65d8c22-5d0c-4d59-a05b-88497edc323a','王官谷十詠 雙人石','俞充','宋','宋诗','song-poetry','','[]','屹立高峰東，峭直如昔賢。',48,'全唐诗/poet.song.40000.json','["屹立高峰東，峭直如昔賢。", "夷齊恥周食，巢由傲堯天。", "不畏風霜侵，所依松柏堅。", "五老靜相對，森森莫知年。"]'),
('4873e38c-67c1-4adc-9e79-6356912ebe5e','王官谷十詠 司空氏舊居','俞充','宋','宋诗','song-poetry','','[]','孤鶴去不還，雲間犬空吠。',48,'全唐诗/poet.song.40000.json','["孤鶴去不還，雲間犬空吠。", "猶聞溪鳥衙，尚有里人愛。", "巖花無開落，世事幾興廢。", "我乘幽興來，靜邀秋月對。"]'),
('c8d88865-4121-4980-bfdb-fa4ab358d7b3','王官谷十詠 石硯','俞充','宋','宋诗','song-poetry','','[]','嘗讀表聖詩，云是秦王成。',48,'全唐诗/poet.song.40000.json','["嘗讀表聖詩，云是秦王成。", "憫時著密史，對此潛經營。", "新雨淨如洗，亂苔生復平。", "應誤山中客，浪近翰墨名。"]'),
('63b2d35e-e22e-4a82-9094-ed8fedf75280','王官谷十詠 機磑','俞充','宋','宋诗','song-poetry','','[]','誰鑿渾沌死，智者爭出力。',48,'全唐诗/poet.song.40000.json','["誰鑿渾沌死，智者爭出力。", "悠悠蟻在磨，雙輪轉何極。", "機心連機械，隨流還不息。", "莫笑抱甕翁，終日亦飽食。"]'),
('5fb9029a-5737-4461-9daa-3f981564a4d5','貽溪懷古十篇 濯纓亭','俞充','宋','宋诗','song-poetry','','[]','皎皎居士纓，豈有塵可濯。',48,'全唐诗/poet.song.40000.json','["皎皎居士纓，豈有塵可濯。", "愛茲滄浪清，偶以斯名記。", "轉谷群鴿歸，衢岸遊魚躍。", "簷頭碧梧枝，秋來垂影薄。"]'),
('45169035-b887-431d-b075-186d8d277259','貽溪懷古十篇 覽照亭','俞充','宋','宋诗','song-poetry','','[]','杖藜高山頭，歷覽眾景會。',48,'全唐诗/poet.song.40000.json','["杖藜高山頭，歷覽眾景會。", "泰摹屹若屏，黄河瀉如带。", "幽懷逐冥鴻，萬事寄天籟。", "不見玉京春，荒煙起蕭艾。"]'),
('45ccc20f-e08e-4803-bb2f-9cb0817d8323','貽溪懷古十篇 三詔堂','俞充','宋','宋诗','song-poetry','','[]','猛虎正橫行，孤猿發長嘯。',48,'全唐诗/poet.song.40000.json','["猛虎正橫行，孤猿發長嘯。", "名高世人間，三枉鶴書詔。", "借笏趨朝參，天意獨難料。", "咫尺首陽山，清光靜相照。"]'),
('ac8dc7fe-02ad-480f-8c9e-5d657b6e506c','貽溪懷古十篇 瑩心亭','俞充','宋','宋诗','song-poetry','','[]','妖氛滿世間，瑩心茲得地。',48,'全唐诗/poet.song.40000.json','["妖氛滿世間，瑩心茲得地。", "瀑布巖前飛，勢猛鷗烏避。", "洗滌無纖塵，澄虛全浩氣。", "清風林表來，千載有餘意。"]'),
('c09a66ef-42ba-43fa-9066-3e70de312892','貽溪懷古十篇 九籥室','俞充','宋','宋诗','song-poetry','','[]','仙術秘丹經，昔人藏九籥。',48,'全唐诗/poet.song.40000.json','["仙術秘丹經，昔人藏九籥。", "幽棲白雲根，保此一爐藥。", "吟殘深雨來，夢斷巖花落。", "萬慮正坐忘，未能看舞鶴。"]'),
('18e86231-0e70-4ff0-b6b3-ce6e3392e279','貽溪懷古十篇 修史亭','俞充','宋','宋诗','song-poetry','','[]','吁哉土德衰，群奸恣蟊賊。',48,'全唐诗/poet.song.40000.json','["吁哉土德衰，群奸恣蟊賊。", "欲加蕭斧誅，修史乃其職。", "誰知深山中，法若春秋直。", "俄驚濟陰變，絕筆幽巖側。"]'),
('23ab47f7-4301-4edf-8a7d-1a9f71a36ca3','貽溪懷古十篇 擬綸亭','俞充','宋','宋诗','song-poetry','','[]','大廈不可扶，誥命已云絕。',48,'全唐诗/poet.song.40000.json','["大廈不可扶，誥命已云絕。", "老臣坐深林，有淚化爲血。", "擬成絲綸言，救世心獨切。", "溪流今尚清，夜夜澄孤月。"]'),
('67b7bd5b-1f4b-4db8-a81c-e21da86cd089','貽溪懷古十篇 掛鶴臺','俞充','宋','宋诗','song-poetry','','[]','汙俗正朋亡，歸來臥空谷。',48,'全唐诗/poet.song.40000.json','["汙俗正朋亡，歸來臥空谷。", "養鶴不成雙，相從守幽獨。", "素羽信非群，孤唳杳無續。", "高臺委荒榛，追想人如玉。"]'),
('efd51d61-ebe5-40b3-85df-2eaf2f8000cd','貽溪懷古十篇 一鳴窗','俞充','宋','宋诗','song-poetry','','[]','天寒松柏青，廄閑驥驥老。',48,'全唐诗/poet.song.40000.json','["天寒松柏青，廄閑驥驥老。", "瀟灑竹窗前，超然鳴以道。", "惟有巖上月，時來伴幽討。", "茲意不可忘，還將拾殘稿。"]'),
('659a0bcd-b220-4f91-895c-495524e3a3a1','貽溪懷古十篇 東渠亭','俞充','宋','宋诗','song-poetry','','[]','二渠日夜流，利厚爭所起。',48,'全唐诗/poet.song.40000.json','["二渠日夜流，利厚爭所起。", "先生坐東亭，立法書在紙。", "老農到今守，後來誰敢毀。", "斯人不可見，空聽竹間水。"]'),
('d081f1bf-da3f-4223-b3fe-2bda5991229d','送靈巖法師','俞充','宋','宋诗','song-poetry','','[]','戰士長戈赴荔原，謀臣獻策廟堂間。',80,'全唐诗/poet.song.40000.json','["戰士長戈赴荔原，謀臣獻策廟堂間。", "吾師倜儻浮屠隱，不事王侯事經論。", "兩街推許住靈巖，百鳥銜花待師□。", "清風一振海潮音，曠劫曾蒙祖師印。", "窮秋別我欲何言，珍重詳師指一彈。"]'),
('95442dc2-0869-4ebc-b0d2-b78b2f95dd40','和岊仲次韻其兄穆父見寄','劉季孫','宋','宋诗','song-poetry','','[]','會稽山上月如輪，鴻雁相將江水春。',32,'全唐诗/poet.song.40000.json','["會稽山上月如輪，鴻雁相將江水春。", "幕府英豪雖可數，樽前誰是急難人。"]'),
('fc547184-1074-4780-ac04-035245037405','有美堂燕集','劉季孫','宋','宋诗','song-poetry','','[]','雲間獵獵立旌旗，公在胥山把酒時。',64,'全唐诗/poet.song.40000.json','["雲間獵獵立旌旗，公在胥山把酒時。", "笑語幾番留湛輩，風流千載與吳兒。", "湖山日落丹青煥，樓閣風收雨露滋。", "誰使管蕭江上住，胸中事業九門知。"]'),
('64e487a2-a268-4630-8e1c-18a83acc0757','登介亭','劉季孫','宋','宋诗','song-poetry','','[]','使君中和堂，六月無炎溽。',240,'全唐诗/poet.song.40000.json','["使君中和堂，六月無炎溽。", "隨呼眾賓集，一笑清風足。", "復爲曲水飲，石面湧寒淥。", "持杯襟袂涼，酒出金鯨腹。", "旌旗登鳳皇，羽翼在林麓。", "半空老崖斷，千載靈藥伏。", "松杉各雄枝，螭蜃傍奔逐。", "古韻豈塵世，遐瞻有天目。", "霸國荒故壇，墠社移新屋。", "霞標起山近，潮勢卷江速。", "物外得長涼，樽前尋往躅。", "有客告將行，遲留待珠玉。", "欣然點鼠鬚，萬象歸一幅。", "終篇燦燦動，滿座琅琅讀。", "此時天樂奏，到夜山鬼哭。", "和之慚豈敢，來者信難續。", "粉壁鑑相射，香媒塵不觸。", "醉歸掃雙堵，字字照巖谷。", "星辰眾所仰，富貴公豈欲。", "一言換凡骨，芝朮誰能服。"]'),
('2bb12652-d6d5-41a5-8ce3-5a55d09b06bc','送錢蒙仲赴舉  其一','劉季孫','宋','宋诗','song-poetry','','[]','膝下五車就業，殿前三月亨途。',28,'全唐诗/poet.song.40000.json','["膝下五車就業，殿前三月亨途。", "日出喚君名姓，春風吹過江湖。"]'),
('8744fe9e-c36f-4550-8ac4-43fa3449bcc5','送錢蒙仲赴舉  其二','劉季孫','宋','宋诗','song-poetry','','[]','文價從今第一，家風經古無倫。',28,'全唐诗/poet.song.40000.json','["文價從今第一，家風經古無倫。", "不假湘靈十字，知君才倍前人。"]'),
('99c87fe4-9db1-42e2-b536-14a5be32ac43','送錢蒙仲赴舉  其三','劉季孫','宋','宋诗','song-poetry','','[]','俊氣將探虎穴，清才早踐龍門。',28,'全唐诗/poet.song.40000.json','["俊氣將探虎穴，清才早踐龍門。", "故比隔江白鷺，萬人回首王孫。"]'),
('bd5b45ef-0696-4c68-959c-3444f9f5aa0c','西園和韻絕句','劉季孫','宋','宋诗','song-poetry','','[]','雨過西園物物佳，柳風竹日映葵花。',32,'全唐诗/poet.song.40000.json','["雨過西園物物佳，柳風竹日映葵花。", "更無人跡宜清睡，奈此池頭一部蛙。"]'),
('b44af0f1-9a01-4bff-8916-cc8e77a2a053','和東坡送仲天貺王元直六言韻五首  其一','劉季孫','宋','宋诗','song-poetry','','[]','誰懷二子千里，公賦五篇六言。',28,'全唐诗/poet.song.40000.json','["誰懷二子千里，公賦五篇六言。", "月底飛雲西去，山頭歸雁雙騫。"]'),
('7534fb62-811e-4a19-8a99-cf4e0392e80c','和東坡送仲天貺王元直六言韻五首  其二','劉季孫','宋','宋诗','song-poetry','','[]','小艇辭公晚發，高齋記客初來。',28,'全唐诗/poet.song.40000.json','["小艇辭公晚發，高齋記客初來。", "耿耿不忘歸路，阻修萬折千回。"]'),
('b70017ea-df0d-4dfd-bcd7-4f96fc0ba955','和東坡送仲天貺王元直六言韻五首  其三','劉季孫','宋','宋诗','song-poetry','','[]','府下莫非群雋，坐中不見三明。',28,'全唐诗/poet.song.40000.json','["府下莫非群雋，坐中不見三明。", "遠意關河馬首，靜吟筆硯泉聲。"]'),
('8c8f6c22-c57e-4757-9f1a-ddaa9712dbcf','和東坡送仲天貺王元直六言韻五首  其四','劉季孫','宋','宋诗','song-poetry','','[]','雖列蜀都有日，卻逢謝傅何年。',28,'全唐诗/poet.song.40000.json','["雖列蜀都有日，卻逢謝傅何年。", "歷歷林溪勝處，想君把酒依然。"]'),
('580fb62c-5ee8-4f6c-843c-0567f3f187ed','和東坡送仲天貺王元直六言韻五首  其五','劉季孫','宋','宋诗','song-poetry','','[]','樂事莫如飲酒，休官自是高人。',28,'全唐诗/poet.song.40000.json','["樂事莫如飲酒，休官自是高人。", "紅带鼇頭寄與，是翁矍鑠尋春。"]'),
('e97ee6e0-d9c3-44b1-bc89-4a3a603c3628','題饒州酒務廳屏','劉季孫','宋','宋诗','song-poetry','','[]','呢喃燕子語梁間，底事來驚夢裏閑。',32,'全唐诗/poet.song.40000.json','["呢喃燕子語梁間，底事來驚夢裏閑。", "說與傍人應不解，仗藜攜酒看芝山。"]'),
('6791bfe3-d439-4146-8249-349e165660e6','廣武山懷古','劉季孫','宋','宋诗','song-poetry','','[]','楚漢兵相接，乾坤晝亦暝。',48,'全唐诗/poet.song.40000.json','["楚漢兵相接，乾坤晝亦暝。", "虎爭千里震，龍戰四郊腥。", "故壘從誰問，嚴祠自昔靈。", "北風吹敗木，落葉任飄零。"]'),
('9afbf5f9-194e-45c7-9af4-4d5ef0e62d25','寄蘇內翰','劉季孫','宋','宋诗','song-poetry','','["\u897f\u6e56"]','倦壓鼇頭請左符，笑尋穎尾爲西湖。',64,'全唐诗/poet.song.40000.json','["倦壓鼇頭請左符，笑尋穎尾爲西湖。", "二三賢守去非遠，六一清風今不孤。", "四海共知霜鬢滿，重陽曾插菊花無。", "聚星堂上誰先到，欲傍金樽倒玉壺。"]'),
('60279c70-01e4-45cc-8380-47ef76f2b618','守關','劉季孫','宋','宋诗','song-poetry','','[]','晨雞三叫末開關，留滯行人更解鞍。',32,'全唐诗/poet.song.40000.json','["晨雞三叫末開關，留滯行人更解鞍。", "卻上月明高處立，曉風吹面作清寒。"]'),
('8d3eadbc-9871-4dd8-9b66-12c508dcc8a0','雲臺山','劉季孫','宋','宋诗','song-poetry','','[]','閬州富名山，冠者雲臺化。',24,'全唐诗/poet.song.40000.json','["閬州富名山，冠者雲臺化。", "幽深壓岷峨，孤峭抵嵩華。"]'),
('d1251b20-24b0-474d-97f6-f616e9aa6fda','送達師遊天台次參寥韻','劉季孫','宋','宋诗','song-poetry','','[]','正誦興公賦，報師來別予。',48,'全唐诗/poet.song.40000.json','["正誦興公賦，報師來別予。", "興長尋瀑布，語罷振行裾。", "勝事雲霞異，清吟巖谷虛。", "石橋鐫歲月，知不假人書。"]'),
('4f7132da-5b3d-41d8-9c70-c497f16c5579','次韻馬中玉提刑見寄','劉季孫','宋','宋诗','song-poetry','','["\u897f\u6e56"]','知公不奈二毛何，尋訪天台所得多。',64,'全唐诗/poet.song.40000.json','["知公不奈二毛何，尋訪天台所得多。", "宿處仙人千載宅，悟時禪友一聲歌。", "道心夷曠忘名勢，句法清新爲琢磨。", "每到西湖懷使節，春風紅紫照清波。"]'),
('16287e27-d284-4180-89ab-00a5f7ccbbf8','因見佛印自稱二浙雲遊老比丘遂成絕句','劉季孫','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','二浙雲遊老比丘，蘇州一宿過湖州。',32,'全唐诗/poet.song.40000.json','["二浙雲遊老比丘，蘇州一宿過湖州。", "錢塘江上乘杯去，雁蕩天台更自由。"]'),
('46daa9fe-9cd2-41d4-907a-bf2f0c28ec09','西湖泛舟呈東坡','劉季孫','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖春意勝當年，公領笙簫泛畫船。',64,'全唐诗/poet.song.40000.json','["西湖春意勝當年，公領笙簫泛畫船。", "錦繡一林生水面，衣冠萬堵立山前。", "仁恩在物禽魚遂，喜氣隨人草木妍。", "半醉插花風調別，寫真須是李龍眠。"]'),
('fa91246d-ca29-40e3-af05-94bb8e2d4b5c','陪東坡中和堂賞月','劉季孫','宋','宋诗','song-poetry','','[]','中和堂上月，盛夏似高秋。',48,'全唐诗/poet.song.40000.json','["中和堂上月，盛夏似高秋。", "天瀉銀河水，人披紫綺裘。", "氣飄聞赤壁，語勝踴黄樓。", "歸袂接夫子，適從何處遊。"]'),
('54093fc8-cbaa-4e66-b2da-f5a4fc78d877','次韻東坡賞枇杷','劉季孫','宋','宋诗','song-poetry','','[]','夏木有餘綠，山僧知勝春。',48,'全唐诗/poet.song.40000.json','["夏木有餘綠，山僧知勝春。", "日長尋臥榻，花落斷遊人。", "紅旆來雖晚，清風到亦新。", "成林盧橘熟，翠羽雜金鱗。"]'),
('213c146a-0517-4cb8-95f9-272c53edb119','雪中過城東仰懷平甫學士','劉季孫','宋','宋诗','song-poetry','','[]','馬蹄踏雪過東城，暫喜京塵不上纓。',64,'全唐诗/poet.song.40000.json','["馬蹄踏雪過東城，暫喜京塵不上纓。", "寒木烏驚花散漫，敗簷人怯玉崢嶸。", "豈無良燕容枚老，定有高才憶戴生。", "未負物華聊一賦，知君麗句已先成。"]'),
('2ea9f091-93ca-4433-b364-d9580d3e36a4','題子瞻揚州借山寺','劉季孫','宋','宋诗','song-poetry','','[]','給事風流在，虛亭景越閑。',48,'全唐诗/poet.song.40000.json','["給事風流在，虛亭景越閑。", "全臨故宮水，盡致別州山。", "峰勢晴相向，嵐光夜不還。", "無時供勝賞，歷歷白雲間。"]'),
('4e3268df-16ce-4263-badc-62efb17fc959','西山老人行','劉季孫','宋','宋诗','song-poetry','','[]','善冶一家稱主人，奴耕婢爨雞司晨。',67,'全唐诗/poet.song.40000.json','["善冶一家稱主人，奴耕婢爨雞司晨。", "置之得所生取備，何必百事皆躬親。", "爲主汲汲盡無獲，道路錐刀長苦卒。", "君不見西山老人不出戶，索酒烹羊呼四鄰。"]'),
('5d69c02c-c18a-4f35-8514-28508f34feb4','晚過范村呈元禮','劉季孫','宋','宋诗','song-poetry','','[]','漸老猶奔走，風埃過范村。',48,'全唐诗/poet.song.40000.json','["漸老猶奔走，風埃過范村。", "嶺寒催馬疾，村晚待鴉喧。", "世路窮迷久，人情應接繁。", "淵明吾所慕，高意在田園。"]'),
('aee60c71-5e8a-4807-95e5-cc7f83dcbe76','酒隱堂','劉季孫','宋','宋诗','song-poetry','','[]','醉鄉王績比華胥，酒隱堂名意豈殊。',64,'全唐诗/poet.song.40000.json','["醉鄉王績比華胥，酒隱堂名意豈殊。", "五斗樂真何所累，一樽隨分亦其徒。", "高才未愧人知少，老句曾容客和無。", "塵事萬端君莫問，到頭酩酊勝區區。"]'),
('1610abef-eceb-4f6c-a72b-23c27e984153','偶成','劉季孫','宋','宋诗','song-poetry','','[]','每過楊子宅，時醉庾公樓。',48,'全唐诗/poet.song.40000.json','["每過楊子宅，時醉庾公樓。", "黄鵠雲霄志，白蘋江海流。", "讀書非世用，種樹是吾謀。", "自識文章貴，多尋瀟灑侯。"]'),
('8796a5bb-3025-49d2-8f73-78a3fadd303f','送江寧知府林公修撰十韻律','劉季孫','宋','宋诗','song-poetry','','[]','昭代尊儒學，惟公簡拔頻。',120,'全唐诗/poet.song.40000.json','["昭代尊儒學，惟公簡拔頻。", "文章分造化，事業在經綸。", "天馬來夷路，人龍撫要津。", "幾年刊大典，四海屬名臣。", "汲引親疏共，光華出入均。", "玄暉賦江練，文暢詠汀蘋。", "道契巖廊久，恩隆建鄴新。", "七朝皆故事，十郡得仁人。", "豈晚還西掖，終朝對北辰。", "一言調鼎味，膏澤被斯民。"]'),
('42527bd2-f3a0-4130-963a-e0b7cfb2742b','將至王屋先寄張明府','劉季孫','宋','宋诗','song-poetry','','[]','詩仙假色管天壇，早晚真除碧落官。',64,'全唐诗/poet.song.40000.json','["詩仙假色管天壇，早晚真除碧落官。", "境內雨頻春畝潤，門前山聚曉雲寒。", "十年不見應題塔，萬事休論擬掛冠。", "同是清源騷雅客，欲言流涕已汍瀾。"]'),
('e0c3788d-422e-4be3-be3e-3692acb2fdcd','將至濟源府先寄姜明府','劉季孫','宋','宋诗','song-poetry','','[]','識君風概有三堂，別後頻驚鬢有霜。',64,'全唐诗/poet.song.40000.json','["識君風概有三堂，別後頻驚鬢有霜。", "經耳萬端人事近，動心千里客途長。", "讀書學劍全相誤，臨水登山獨未忘。", "路入濟源牽賦詠，此行真發鄙夫狂。"]'),
('8472e546-0cc4-439b-b192-9f99eb48ea7c','鄭令狐明府','劉季孫','宋','宋诗','song-poetry','','[]','行當臘候晚，共惜歲陰殘。',48,'全唐诗/poet.song.40000.json','["行當臘候晚，共惜歲陰殘。", "聞道巴山遠，何如蜀路難。", "荒林藏積雪，亂石起驚湍。", "君有親人術，應令勞者安。"]'),
('000b41f1-1b37-40ed-8a52-00217e9e41de','早發承甫館寄登州待制','劉季孫','宋','宋诗','song-poetry','','[]','水亭瀟灑離塵開，一醉扁舟載月迴。',32,'全唐诗/poet.song.40000.json','["水亭瀟灑離塵開，一醉扁舟載月迴。", "馬首西歸懷底事，只隨曉日望蓬萊。"]'),
('6b29649a-1354-4256-826b-4b7269196328','贈賈收處士十韻','劉季孫','宋','宋诗','song-poetry','','[]','君家霅溪上，日食霅溪魚。',120,'全唐诗/poet.song.40000.json','["君家霅溪上，日食霅溪魚。", "無錢買釣艇，貌古常有餘。", "遇人喜談笑，貰酒日不虛。", "浩歌出塵表，白鳥來徐徐。", "清風入窗牖，散亂床頭書。", "有琴壞徽軫，淵明意何如。", "我欲脫塵網，築室鄰君居。", "有地植松竹，有水種芙蕖。", "作詩賦生理，起居當和予。", "相顧可忘老，醉飽遺君諸。"]'),
('1e900001-77d1-491e-8db2-e81a65f838a4','贈朱象先處士十韻','劉季孫','宋','宋诗','song-poetry','','[]','前身應畫師，摩詰初自許。',120,'全唐诗/poet.song.40000.json','["前身應畫師，摩詰初自許。", "咫尺論萬里，宰也少陵與。", "朱翁趣豈凡，山水忘羈旅。", "晴窗布風雲，夏木迴炎暑。", "坐來摧虎頭，興盡禿鷄矩。", "況其塵外懷，出門皆勝侶。", "一畫不輕付，俗子吾避汝。", "能令希世跡，千載得處所。", "斯人定何如，篋有東坡語。", "畫以適其意，能文不求舉。"]'),
('7305ecd7-bd42-466f-afb7-efcf396c3b5c','三高祠詠古三首  其一','劉季孫','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','大湖際天碧，浩蕩浮萬象。',216,'全唐诗/poet.song.40000.json','["大湖際天碧，浩蕩浮萬象。", "中有洞庭山，天作蓬壺樣。", "蘆葦秋蕭蕭，時聞發漁唱。", "風順如可尋，月明迷所向。", "有人在扁舟，髪白意夷曠。", "扣舷了不顧，出沒信波浪。", "心已類水石，何由知得喪。", "遺民至如今，自古惟越相。", "初爲吳都囚，君臣憂醢醬。", "忍恥人謂愚，祈生世知妄。", "尪癯脫萬死，歸國奇謀創。", "行師舞群姓，下令躍諸將。", "夜半覆姑蘇，夫差始悲愴。", "安惻寬晷刻，反掌成伯王。", "江山入會稽，功高誰與抗。", "寵利速禍敗，忠臣半誅放。", "遯去舉邦求，君王鑄形狀。", "寂寥數千年，相見霜縑上。"]'),
('2215410f-44d3-47ef-90e3-f8c95f0d38c0','三高祠詠古三首  其二','劉季孫','宋','宋诗','song-poetry','','["\u592a\u6e56"]','吳江淨如鏡，吳艇輕如飛。',240,'全唐诗/poet.song.40000.json','["吳江淨如鏡，吳艇輕如飛。", "吳山遠如畫，此景天下稀。", "秋風曉槭槭，秋雨涼霏霏。", "誰將菰菜擷，正是鱸魚肥。", "時有季鷹者，懷此知所歸。", "浩歌有餘樂，肯樂首陽饑。", "親朋不可挽，飄忽雲邊衣。", "亦聞有富貴，大第嚴朱扉。", "食必列鐘鼎，侍妾鳴珠璣。", "簪裾望顔色，賓從生光輝。", "一言轉造化，枯朽生芳菲。", "功高責更重，勢或干天威。", "福深禍亦稱，顛覆始知機。", "斯人悟茲理，弔世潛歟欷。", "浮沉顧寵祿，安能與心違。", "滄波浩無際，草木情依依。", "可以恣幽步，白雲藏釣磯。", "靜引一杯酒，高歌憐昨非。", "數峰太湖上，斜陽明翠微。", "虛亭展遺像，想見猶忘機。"]'),
('d4d17fc9-0ba7-4eb6-81c4-bd8c5eae6570','三高祠詠古三首  其三','劉季孫','宋','宋诗','song-poetry','','[]','人物盛東南，莫如吳郡陸。',216,'全唐诗/poet.song.40000.json','["人物盛東南，莫如吳郡陸。", "漢季逮唐來，班班聞史牘。", "門庭迭輝赫，龍虎爭馳逐。", "風流郁蘭桂，氣象鮮車服。", "魯望乃其裔，清標映宗族。", "文章及者鮮，意趣超然獨。", "寧從一瓢飲，不枉萬鍾祿。", "雲煙藹巾袖，星斗粲胸腹。", "來居笠澤旁，蕭蕭數間屋。", "廚中甑起塵，筆下珠盈斛。", "吟須僧舍題，醉就友人宿。", "醒將太玄解，臥把離騷讀。", "心惟近漁釣，跡亦混樵牧。", "韻高誰可聽，皮子往還熟。", "唱酬數百篇，名流必雌伏。", "業書類有道，不賦長沙鵩。", "晚泊松江上，遺圖見眉目。", "分明孤鶴姿，軒昂駭鷄騖。"]'),
('e700fff6-2123-4222-a52b-11cfadd60b88','遊越山寺看泉','劉季孫','宋','宋诗','song-poetry','','[]','龜溪有路蓮花引，鷲嶺無時雲霧生。',32,'全唐诗/poet.song.40000.json','["龜溪有路蓮花引，鷲嶺無時雲霧生。", "聊放此身留舴艋，不逢人處聽泉生。"]'),
('f98fe682-0b7b-48f4-a9a5-d8af76e01fc3','詩三首  其一','劉季孫','宋','宋诗','song-poetry','','[]','中宮在天半，其上乃吾家。',48,'全唐诗/poet.song.40000.json','["中宮在天半，其上乃吾家。", "紛紛鸞鳳舞，往往芝朮華。", "揮手謝世人，聳身入雲霞。", "公暇詠天海，我非世人譁。"]'),
('70edb558-3639-4c44-9f7e-f3df02c1275d','詩三首  其二','劉季孫','宋','宋诗','song-poetry','','[]','仙都非世間，天神繞樓殿。',48,'全唐诗/poet.song.40000.json','["仙都非世間，天神繞樓殿。", "高低霞霧勻，左右龍蛇徧。", "雲車山岳聳，風鼙天地顫。", "從茲得舊渥，萬物毫端變。"]'),
('90ae3e81-00d6-4bc6-8d9d-d522105d313f','詩三首  其三','劉季孫','宋','宋诗','song-poetry','','[]','從來英傑自消磨，好笑人間事更多。',32,'全唐诗/poet.song.40000.json','["從來英傑自消磨，好笑人間事更多。", "艮上巽宮爲進發，千車安穩渡銀河。"]'),
('abcc6c91-a59c-4743-94c9-d3795220d0b7','句  其一','劉季孫','宋','宋诗','song-poetry','','[]','詩書魯國真男子，歌吹揚州作貴人。',16,'全唐诗/poet.song.40000.json','["詩書魯國真男子，歌吹揚州作貴人。"]'),
('2aac295c-6dd6-4c48-b915-7c625aac4ed3','句  其二','劉季孫','宋','宋诗','song-poetry','','[]','江心淨带三秋月，巖腹斜收萬里雲。',16,'全唐诗/poet.song.40000.json','["江心淨带三秋月，巖腹斜收萬里雲。"]'),
('4f6082b2-f761-418f-ba7b-7a8588dce032','聞侯舅應辟南征詩','程頤','宋','宋诗','song-poetry','','[]','辭華奔競至道離，茫茫學者爭驅馳。',160,'全唐诗/poet.song.40000.json','["辭華奔競至道離，茫茫學者爭驅馳。", "先生獨奮孟軻舌，扶持聖教增光輝。", "志期周禮制區夏，人稱孔陰生闕西。", "當途聞聲交薦牘，蒼生無福徒爾爲。", "道大不爲當世用，著書將期來者知。", "今朝有客關內至，聞從大幕征南垂。", "南垂凶冠陷州郡，久張螳臂抗天威。", "聖皇赫怒捷書緩，虎侯秉鉞驅熊罷。", "宏才未得天下宰，良謀且作軍中師。", "蕞爾小蠻何足殄，庶幾聊吐胸中奇。"]'),
('bd863e5b-dce3-4510-91c5-4fb9985638d8','遊嵩山','程頤','宋','宋诗','song-poetry','','[]','鞭羸百里遠來游，巖谷陰雲暝不收。',32,'全唐诗/poet.song.40000.json','["鞭羸百里遠來游，巖谷陰雲暝不收。", "遮斷好山教不見，如何天意異人謀。"]'),
('ef6181f8-7d3a-4948-8d7b-3aed5677a3a3','謝王佺期寄藥','程頤','宋','宋诗','song-poetry','','[]','至誠通聖藥通神，遠寄衰翁濟病身。',32,'全唐诗/poet.song.40000.json','["至誠通聖藥通神，遠寄衰翁濟病身。", "我亦有丹君信否，用時還解壽斯民。"]'),
('e5c6aa00-b6cc-46ef-b85d-55e087a24a84','秋日偶成','程頤','宋','宋诗','song-poetry','','["\u79cb\u5929", "\u4eba\u751f", "\u54f2\u7406"]','閑來無事不從容，睡覺東窗日已紅。',64,'全唐诗/poet.song.40000.json','["閑來無事不從容，睡覺東窗日已紅。", "萬物靜觀皆自得，四時佳興輿人同。", "道通天地有形外，思入雲煙變態中。", "富貴不淫貧賤樂，男兒到此是豪雄。"]'),
('9f36e6c9-327c-48bc-a59f-2e9e5c0afc4a','睢陽五老圖','程頤','宋','宋诗','song-poetry','','[]','天朝罷命錫歸閑，富壽康寧老稅冠。',64,'全唐诗/poet.song.40000.json','["天朝罷命錫歸閑，富壽康寧老稅冠。", "國史標名知骨鯁，邦人圖像勝楹桓。", "龍飛天上時還暖，魚躍波心氣未寒。", "惟我潛心於易理，備知先哲應時看。"]'),
('87602a70-656f-4619-b901-96362036696e','陸渾樂遊','程頤','宋','宋诗','song-poetry','','[]','東郊漸微綠，驅馬欣獨往。',48,'全唐诗/poet.song.40000.json','["東郊漸微綠，驅馬欣獨往。", "舟縈野渡時，水樂春山響。", "身閑愛物外，趣逸諧心賞。", "歸路逐樵歌，落日寒山上。"]'),
('579956a2-55bf-4c86-8919-5f49e6b51d1d','句','程頤','宋','宋诗','song-poetry','','[]','堯舜幾千年，其心至今在。',12,'全唐诗/poet.song.40000.json','["堯舜幾千年，其心至今在。"]'),
('4b075c9e-335a-4845-a586-88de9afbb912','端午帖子  其一','趙彥若','宋','宋诗','song-poetry','','[]','揚子江中方鑄鏡，未央宮裹更飛符。',32,'全唐诗/poet.song.40000.json','["揚子江中方鑄鏡，未央宮裹更飛符。", "菱花欲共朱靈合，驅盡神姦又得無。"]'),
('452774a2-711f-454b-a794-7193ae1e7030','端午帖子  其二','趙彥若','宋','宋诗','song-poetry','','[]','揚子江中百煉金，寶奩疑是月華沉。',32,'全唐诗/poet.song.40000.json','["揚子江中百煉金，寶奩疑是月華沉。", "爭如聖后無私鑑，明照人間萬善心。"]'),
('576df162-9785-448d-8861-6fa7be25b540','句  其一','趙彥若','宋','宋诗','song-poetry','','[]','江心百煉青銅鏡，架上雙紉翠縷衣。',16,'全唐诗/poet.song.40000.json','["江心百煉青銅鏡，架上雙紉翠縷衣。"]'),
('c6553a4b-4a45-495a-8ede-5eea1e1360b7','句  其二','趙彥若','宋','宋诗','song-poetry','','[]','花隨紅意發，葉就綠情新。',12,'全唐诗/poet.song.40000.json','["花隨紅意發，葉就綠情新。"]'),
('7eac2413-3367-43db-b333-002f5f4b5798','奉寄靈巖長老確公大師  其一','盛陶','宋','宋诗','song-poetry','','[]','適見隨州住，誰教復在齊。',24,'全唐诗/poet.song.40000.json','["適見隨州住，誰教復在齊。", "君看歷山北，何似善光西。"]'),
('26c37ae1-3349-4f37-b6f9-a0340f1247bb','奉寄靈巖長老確公大師  其二','盛陶','宋','宋诗','song-poetry','','[]','傳法仙城後，流名上國高。',48,'全唐诗/poet.song.40000.json','["傳法仙城後，流名上國高。", "游方緣漸契，無亦太忉忉。", "靈巖山下草，今古幾回春。", "不有開堂日，焉知卷席人。"]'),
('bea215f6-3abe-4552-b85d-778fe8335740','教授推官出示米元章詩詞翰俱美三四讀而不能休敬書二十八字謝之','程節','宋','宋诗','song-poetry','','[]','萬□□南泮水遙，清風來拂瘴煙消。',32,'全唐诗/poet.song.40000.json','["萬□□南泮水遙，清風來拂瘴煙消。", "袖中突兀龍蛇出，聊慰天涯久寂寥。"]'),
('30999488-18d0-4856-96cb-937148e01c25','荷花','豐稷','宋','宋诗','song-poetry','','[]','桃杏二三月，此花泥滓中。',48,'全唐诗/poet.song.40000.json','["桃杏二三月，此花泥滓中。", "人心正畏暑，水面獨搖風。", "淨刹如金湧，嘉賓照幕紅。", "誰歌采菱曲，舟在曉霞束。"]'),
('a3227ae2-d0d8-495a-ad59-1f9dde212822','朱氏天和堂','豐稷','宋','宋诗','song-poetry','','[]','路左漿先饋，門前屨幾重。',48,'全唐诗/poet.song.40000.json','["路左漿先饋，門前屨幾重。", "勇歸塵事擲，恬處道心濃。", "弄水知幽谷，觀雲想妙峰。", "夜探孤鶴唳，清露滴高松。"]'),
('b4dd0547-9b63-4c43-be53-a190bedd7222','和運司園亭 西園','豐稷','宋','宋诗','song-poetry','','[]','仙化二十四，境遠難遍探。',48,'全唐诗/poet.song.40000.json','["仙化二十四，境遠難遍探。", "錦城使君園，雅與雲洞參。", "回光試一覽，紫翠絕西南。", "池映金波靜，花沾玉露甘。"]'),
('b3ccba8c-73f4-47b8-a152-3e0ce04c302b','和運司園亭 玉谿堂','豐稷','宋','宋诗','song-poetry','','[]','一水從何來，應是崑山頂。',48,'全唐诗/poet.song.40000.json','["一水從何來，應是崑山頂。", "釃成淥玉池，虛堂逗清影。", "公退泠然賞，了非心外境。", "魚泳陽光動，鳥嗁春晝永。"]'),
('2347c231-655f-4b60-a90e-77e4eda83964','和運司園亭 雪峰樓','豐稷','宋','宋诗','song-poetry','','[]','雪峰在何許，樓倚青霄端。',48,'全唐诗/poet.song.40000.json','["雪峰在何許，樓倚青霄端。", "每來注心目，不覺生羽翰。", "終藉好風力，雲散銀闕攢。", "隻履西歸客，應笑空倚樓。"]'),
('b250d214-4807-4297-853b-baaaa0312dd8','和運司園亭 海棠軒','豐稷','宋','宋诗','song-poetry','','[]','文錦初動機，晨霞欲敷照。',48,'全唐诗/poet.song.40000.json','["文錦初動機，晨霞欲敷照。", "香傳雪樓濃，影落玉谿倒。", "子美不能賦，春工一何妙。", "惟有賞心人，相逢祇微笑。"]'),
('a973efaf-7259-4e41-8396-395176415350','和運司園亭 月臺','豐稷','宋','宋诗','song-poetry','','[]','石印魚在屏，犀透星入角。',48,'全唐诗/poet.song.40000.json','["石印魚在屏，犀透星入角。", "迺知明月光，日用心不覺。", "陟此百尺臺，餘念坐消剝。", "洞曉弦望機，仙丹茲可學。"]'),
('0766d03c-7d9c-4038-836e-aedded7bb35e','和運司園亭 翠錦亭','豐稷','宋','宋诗','song-poetry','','[]','簷外列修木，凜凜正人氣。',48,'全唐诗/poet.song.40000.json','["簷外列修木，凜凜正人氣。", "有德必有文，爛兮五色備。", "豈同夭韶花，弄春張繡被。", "須信輪囷材，堪爲萬乘器。"]'),
('1b5caa2b-c755-41a2-9389-735e01b88f98','和運司園亭 潺玉亭','豐稷','宋','宋诗','song-poetry','','[]','養源在西山，如玉抱精白。',48,'全唐诗/poet.song.40000.json','["養源在西山，如玉抱精白。", "引之落錦渠，歷耳不可擇。", "風雨雜鳴球，珠璣寫雲液。", "恰似偃谿聲，醒悟迷途客。"]'),
('eb7fbd1e-2980-43a8-96d5-fe90bb05c0f2','和運司園亭 茅庵','豐稷','宋','宋诗','song-poetry','','[]','覆以潔白茅，環以琅玕竹。',48,'全唐诗/poet.song.40000.json','["覆以潔白茅，環以琅玕竹。", "天籟旁鼓笙，月沼對鋪玉。", "借問清坐翁，此外更何欲。", "笑指博山爐，香飛柏子綠。"]'),
('1f778a24-0176-4aa3-afd7-ea4fb6ae5494','和運司園亭 水閣','豐稷','宋','宋诗','song-poetry','','[]','長虹臥松江，一葦航大河。',48,'全唐诗/poet.song.40000.json','["長虹臥松江，一葦航大河。", "豈如此安穩，無復畏風波。", "幽香萃花島，魚藻旨且多。", "徙倚小欄曲，月色透薜蘿。"]'),
('2cd6a193-70ce-496b-a551-e8b067882ece','和運司園亭 小亭','豐稷','宋','宋诗','song-poetry','','[]','東西對孤騫，杖屨可幽歇。',48,'全唐诗/poet.song.40000.json','["東西對孤騫，杖屨可幽歇。", "容光日月來，矧此明四徹。", "鱗木張幄翠，蜃泉飛玉潔。", "往往得意時，宛在廣寒闕。"]'),
('0c0721f4-5050-4300-ba26-8386580c2f6d','幸太學','豐稷','宋','宋诗','song-poetry','','[]','鳳幄雲開日月章，九霄嗚蹕下虞庠。',64,'全唐诗/poet.song.40000.json','["鳳幄雲開日月章，九霄嗚蹕下虞庠。", "朝元俊士鴻成列，拱極名臣玉照行。", "問道賈生稱五學，乞言戴聖美三王。", "上心夙悟周公戒，天下安危自一堂。"]'),
('369c1d4e-692e-4eb0-8e16-974dbbf18d73','句','豐稷','宋','宋诗','song-poetry','','[]','日來月往無成期，好把心源早夜思。',16,'全唐诗/poet.song.40000.json','["日來月往無成期，好把心源早夜思。"]'),
('df412408-ad54-42ee-b143-177d586ab4fd','存目','豐稷','宋','宋诗','song-poetry','','[]','詩題：霧山首句：霧山環合自雲川。',16,'全唐诗/poet.song.40000.json','["詩題：霧山首句：霧山環合自雲川。"]'),
('51898413-4ae5-4150-bdcb-9bfa39ecef99','詩三首  其一','徐守信','宋','宋诗','song-poetry','','[]','遙望南莊景色幽，前人田土後人收。',32,'全唐诗/poet.song.40000.json','["遙望南莊景色幽，前人田土後人收。", "兒孫自有兒孫福，莫與兒孫作馬牛。"]'),
('f57d5ed2-5442-44c6-afd1-d04adb3b445c','詩三首  其二','徐守信','宋','宋诗','song-poetry','','[]','富貴貧窮各有由，宿緣分定莫罔求。',32,'全唐诗/poet.song.40000.json','["富貴貧窮各有由，宿緣分定莫罔求。", "不曾下得春時種，空守荒田望有收。"]'),
('31a88b11-9800-4563-b4d4-4e7767eefbc7','詩三首  其三','徐守信','宋','宋诗','song-poetry','','[]','南莊北宅眼前花，好兒好女莫縵誇。',32,'全唐诗/poet.song.40000.json','["南莊北宅眼前花，好兒好女莫縵誇。", "我若一朝身死後，又屬張三李四家。"]'),
('16ff5d76-37be-4461-9f22-08200dd0738d','偈','徐守信','宋','宋诗','song-poetry','','[]','天地一尺，四海一滴。',20,'全唐诗/poet.song.40000.json','["天地一尺，四海一滴。", "把眼一眨，不見蹤跡。"]'),
('17e7c346-f48e-4862-9b00-a603e9e46289','詩一首','徐守信','宋','宋诗','song-poetry','','[]','牡蠣灘頭一艇橫，夕陽西去待潮生。',32,'全唐诗/poet.song.40000.json','["牡蠣灘頭一艇橫，夕陽西去待潮生。", "與君不負登臨約，同上金鼇背上行。"]'),
('0b99ac21-28f9-49a5-aa8f-4b822c90d97f','高峰','關詠','宋','宋诗','song-poetry','','[]','獨愛高峰最上頭，夕陽煙樹見嚴州。',32,'全唐诗/poet.song.40000.json','["獨愛高峰最上頭，夕陽煙樹見嚴州。", "子陵貪向溪邊釣，應未曾來此地遊。"]'),
('211b1ad4-e48f-4a47-8278-5ccfdf9bf0ea','題左溪齊雲閣','關詠','宋','宋诗','song-poetry','','[]','白雲來軒戶，清風生澗壑。',24,'全唐诗/poet.song.40000.json','["白雲來軒戶，清風生澗壑。", "山僧不管春，巖花開自落。"]'),
('c7fe649b-cb6f-4f3f-b60a-66b84c8a3b9b','和蘇唐卿','張頌','宋','宋诗','song-poetry','','[]','重惜歐陽滁記好，模刊翠琰費堂新。',64,'全唐诗/poet.song.40000.json','["重惜歐陽滁記好，模刊翠琰費堂新。", "文華起焰衝星斗，篆法通靈動鬼神。", "觀妙每多師道客，仰高常有慕賢人。", "璨然輝日如辰象，不朽宜爲萬世人。"]'),
('3832ae4f-a363-404b-9805-ec7fa6b8de40','送程給事知越州','沈希顔','宋','宋诗','song-poetry','','[]','帝恩耆德帥江東，銅虎分符錫我公。',64,'全唐诗/poet.song.40000.json','["帝恩耆德帥江東，銅虎分符錫我公。", "侍從暫辭仙殿秘，蕃宣聊擁使麾雄。", "過吳衣錦誇鄉曲，人越褰帷廣聽聰。", "莫戀湖山經歲住，早歸黄閣亮天功。"]'),
('fb5c1782-7586-479f-bb96-319264d3d05a','詩一首','沈希顔','宋','宋诗','song-poetry','','[]','此處離朝路幾千，爲官不取半文錢。',32,'全唐诗/poet.song.40000.json','["此處離朝路幾千，爲官不取半文錢。", "平生不養無情鳥，遮莫妖禽夜哭天。"]'),
('83d2d9a1-feab-4401-84a9-3f2990069b58','和陳述古僊居巖老堂詩','王振','宋','宋诗','song-poetry','','[]','政暇此觀書，心閑渭水漁。',48,'全唐诗/poet.song.40000.json','["政暇此觀書，心閑渭水漁。", "宛然山叟室，移入縣庭居。", "雨霽群峰秀，風生一谷虛。", "我朝求治功，好顧臥龍廬。"]'),
('47f94b17-e10b-4ba8-8126-dd9ad985594d','楓橋','郭附','宋','宋诗','song-poetry','','[]','師子山雲漠漠，越來溪水悠悠。',56,'全唐诗/poet.song.40000.json','["師子山雲漠漠，越來溪水悠悠。", "鐘到客船未曉，月和漁火俱愁。", "咫尺橫塘古塔，連綿芳草長洲。", "一老翛然自在，時時來繫扁舟。"]'),
('e5020a30-eebd-4c2d-a949-a9d3a52fd8d5','釣臺','張綬','宋','宋诗','song-poetry','','[]','范蠡功成始遁逃，淵明五斗便辭勞。',32,'全唐诗/poet.song.40000.json','["范蠡功成始遁逃，淵明五斗便辭勞。", "先生二事俱無一，名與青山萬古高。"]'),
('d4898ec1-02a2-4faf-b9c5-2f4cdceb4f0c','題奣巖','張綬','宋','宋诗','song-poetry','','[]','巖口呀然向日開，小橋飛入勢縈回。',32,'全唐诗/poet.song.40000.json','["巖口呀然向日開，小橋飛入勢縈回。", "幽深自可逃煩暑，況有寒泉石下來。"]'),
('fff107b9-7bcd-45f7-980b-58b9628fa437','瀉洪亭','張綬','宋','宋诗','song-poetry','','[]','潺潺石磴瀉紅泉，路躡丹梯入紫煙。',32,'全唐诗/poet.song.40000.json','["潺潺石磴瀉紅泉，路躡丹梯入紫煙。", "巖有高人無問處，菴羅雙樹碧參天。"]'),
('bcd79569-4934-4947-b078-890a62152ebd','遊層巖','張綬','宋','宋诗','song-poetry','','[]','群峰聳回環，一徑上縈曲。',228,'全唐诗/poet.song.40000.json','["群峰聳回環，一徑上縈曲。", "顧瞻得層巖，庨豁鑿山腹。", "片雲雨雹飛，勺水蛟龍縮。", "惟昔乘興遊，頗歎歸鞍促。", "念方困簿領，敢不勤櫛沐。", "四時各有趣，一賞豈能足。", "朅來俯二紀，經行徧四瀆。", "每懷佳山水，瀾僻聚燕蝠。", "高才茲南來，勝賞欣所欲。", "披尋到幽秘，徘徊或信宿。", "忘歸須眾同，寓意乃余獨。", "泉聲愜幽聽，翠色明遠目。", "夕鳥歸且鳴，牧牛駭而觸。", "此行固有得，何用論禍福。", "應同丁家興，肯效窮塗哭。", "堂下食張儀，綈袍哀范叔。", "大任或感發，一飯奚省錄。", "郵筒奉佳篇，兀坐聊躑躅。", "勉率繼高韻，願同刊澗澳。"]'),
('e1bfc2ee-7037-4e50-8e2d-6a350490fd8f','石井聯句','傅概','宋','宋诗','song-poetry','','[]','山川百千景，斯並誠敻絕。',132,'全唐诗/poet.song.40000.json','["山川百千景，斯並誠敻絕。", "靈源若神湧，怪石肖天裂。", "不與濁流並，恐是眾泉傑。", "銀漢河分派，玉壺冰借潔。", "中夜聲激愴，四時光秀澈。", "涇渭恥淆雜，潢潦愧涸竭。", "潤如周孔教，清比夷齊節。", "觀魚思文望，對巖夢武說。", "我欲斷諂佞，汲此洗劍血。", "我欲安廟社，磨此鏤勳碣。", "詩以誌本心，書之非詭說。"]'),
('363f11fd-3c80-47ba-9634-057f8f09b611','送程給事知越州','練定','宋','宋诗','song-poetry','','[]','鑑湖蓬閣南州冠，詔輟真仙去總臨。',96,'全唐诗/poet.song.40000.json','["鑑湖蓬閣南州冠，詔輟真仙去總臨。", "江上兒童爭跨竹，日逼鴛鷺惜分襟。", "氣凌沙漠冰霜凜，旌拂蘭亭雨露深。", "彩筆欲窮千里景，錦囊先屈滿朝吟。", "五雲鶴馭聊棲息，萬里鵬圖在尺尋。", "玉殿叮嚀天語密，未應閑得子牟心。"]'),
('0aa0bb2e-e31f-4060-88b6-da102b75cf53','熙春臺  其一','李詳','宋','宋诗','song-poetry','','[]','地回仙島風光別，人在春臺笑語溫。',32,'全唐诗/poet.song.40000.json','["地回仙島風光別，人在春臺笑語溫。", "事簡民淳知帝力，時和歲稔荷天恩。"]'),
('1da086ea-aee7-42e5-a28d-f058db503db7','熙春臺  其二','李詳','宋','宋诗','song-poetry','','[]','簾珠虛明十二欄，翛然身世尚人間。',32,'全唐诗/poet.song.40000.json','["簾珠虛明十二欄，翛然身世尚人間。", "怪來拾得無塵句，放出雲屏幾疊山。"]'),
('d066de28-c8a7-42b5-ab07-05c5505a82b2','句','李鎮','宋','宋诗','song-poetry','','[]','古木直無巢，野泉清絕釣。',12,'全唐诗/poet.song.40000.json','["古木直無巢，野泉清絕釣。"]'),
('a9a1c533-4cdf-480c-ac04-355bc85a9ffb','與剛中適甫游惠山','袁默','宋','宋诗','song-poetry','','[]','雨過山前翠欲飛，水雲高下正含暉。',64,'全唐诗/poet.song.40000.json','["雨過山前翠欲飛，水雲高下正含暉。", "魚跳細浪千花碎，蟬倚清陰一嘒微。", "沈李浮瓜吟齒盡，清風明月滿船歸。", "超然不負尋幽興，拂得荷香在葛衣。"]'),
('8f41f535-9376-4add-bbf4-6de13ab4ee37','季子廟','袁默','宋','宋诗','song-poetry','','[]','巢由高風不可及，後世家邦皆子襲。',128,'全唐诗/poet.song.40000.json','["巢由高風不可及，後世家邦皆子襲。", "東周不競諸侯強，中原未許干戈戢。", "修盟歃血血未乾，稷草離離戰鬼泣。", "闔廬釋楚夫概奔，公子糾殺桓公入。", "兄弟之間寧固多，旦正衣冠暮成執。", "前規舊轍不遠人，嗚呼季子其肯立。", "吳民猶有德吳心，廟貌相望在封邑。", "懷古令人憶慘悽，日落疏林風習習。"]'),
('ed828499-1833-4a4f-96bd-b0e84e933304','君山','袁默','宋','宋诗','song-poetry','','[]','君不聞吹簫得仙雙帝子，宅門敕牌金書字。',166,'全唐诗/poet.song.40000.json','["君不聞吹簫得仙雙帝子，宅門敕牌金書字。", "又不聞馬家堂宇色未昏，宅門題作奉誠園。", "古來將相多高第，今不爲園即爲寺。", "吾觀黄歇相楚時，豈意異時真似此。", "晚周諸國勢相傾，齊趙信陵爭下士。", "何術能令楚復強，三千賓客多珠履。", "一旦不謀毋望人，身亡家破神朱英。", "嗟乎養士漫如許，得失何異一老兵。", "吳墟索莫故城在，庭殿但聞鐘磬聲。", "猿哀鶴怨松風裏，遺恨江流終未平。"]'),
('a65b8ecf-6572-4f05-bd48-3b35f32e40dc','釣魚臺','袁默','宋','宋诗','song-poetry','','[]','將相寧有種，屠狗飯牛皆可用。',108,'全唐诗/poet.song.40000.json','["將相寧有種，屠狗飯牛皆可用。", "富貴出長年，勿謂暮塗吾倒行。", "先君太公望久矣，日老渭陽心以此。", "君臣相得漁獵間，廓清八表公名起。", "奠鼎扶周卜世長，洋洋齊封二千里。", "曹公黄相俱塵埃，至今猶有釣魚臺。", "苔侵石剝夕陽裏，滾滾寒江潮去來。"]'),
('cee2ea18-3800-44de-a1d3-0ebcf7e5ebe3','惠山','袁默','宋','宋诗','song-poetry','','[]','山翁自合老林扃，小有天中盡杳冥。',64,'全唐诗/poet.song.40000.json','["山翁自合老林扃，小有天中盡杳冥。", "兩面樓臺驅作勢，半崖松石倚爲屏。", "雲歸洞口紛紛見，泉入池心細細聽。", "勝景深藏誰到此，好須圖繪入丹青。"]'),
('2a6e2bda-4acc-45b4-9361-9148ebd27f0b','石女塚','袁默','宋','宋诗','song-poetry','','[]','君不見湘江不流湘水清，悲風愁雨能無情。',142,'全唐诗/poet.song.40000.json','["君不見湘江不流湘水清，悲風愁雨能無情。", "靈妃寶瑟聲未絕，九疑雲鎖蒼梧深。", "又不見霸陵路入新豐道，顧念邯鄲意悽惱。", "夫人鼓瑟君爲歌，北山爲槨吾將老。", "古來死者不勝計，歷歷道旁猶可記。", "人言梁女好鼓瑟，琴心未許人知意。", "高山流水聲已虛，想像當時足幽思。", "九原可作誰與歸，秋風蕭蕭草淒淒，邱墟之下多狐狸。"]'),
('498e655f-927f-4f9f-a958-dc4ec00949bb','次韻蔣不回惠山行見贈','袁默','宋','宋诗','song-poetry','','["\u592a\u6e56"]','九龍山高茂松竹，冉冉嵐光真潑綠。',352,'全唐诗/poet.song.40000.json','["九龍山高茂松竹，冉冉嵐光真潑綠。", "重岡複嶺勢崢嶸，五里垂楊排岸曲。", "雲生洞口若拖縑，泉落田間如噴玉。", "公乘若水遺跡在，瀟灑儒冠與僧服。", "夜蟾清影照寒流，春鳥新聲答寒谷。", "山畔人家農事閑，長得秋風魚稻熟。", "太湖光射夕陽間，澗澤相通財必育。", "一生遊賞心不足，憶與高人時往復。", "夢魂應是念歸歟，問舍求田無百斛。", "身名牽制悼人心，收拾未能如水覆。", "侵尋白髮已盈簪，方此徘徊干寸祿。", "樂安道人來自蜀，尚爾小官身僕僕。", "惠然相訪蓋初傾，符采瑩顔神滿目。", "徐言得道先辟穀，二年粒米不入腹。", "日南先生韻超俗，授術爲之留五宿。", "發洩天機指下傳，妙用圓通皆智燭。", "見我情親逾族屬，勸以修持言滿軸。", "自慚正類雞伏鵠，敢忘精心循所祝。", "痊除多謝枕中方，臭腐豈爲刀下肉。", "斧斤牛羊肆殘毒，古人已況牛山木。", "深言元氣須引續，起我衰羸丸射鹿。", "煩胸一訣願相傳，卦體儼然存九六。"]'),
('93e4bea5-6bd9-4bcb-a9b0-4f0d31887b95','白龍洞','袁默','宋','宋诗','song-poetry','','[]','開元年中關輔旱，靈岳神祠禱幾徧。',192,'全唐诗/poet.song.40000.json','["開元年中關輔旱，靈岳神祠禱幾徧。", "少監馮生能畫龍，明皂命試新池殿。", "落筆婉蜒勢未已，素鬣冰鱗濕如洗。", "池波洶湧雷電驚，雲氣之門白龍起。", "吾觀馮豈作霖人，畫龍能雨疑有神。", "深山大澤多窟穴，不應杳眇不似真。", "澄江接海連空白，泓深當是神龍宅。", "螭虬狡獪非其倫，河伯江妃敢驅役。", "霜鎖煙關晝不開，時傾膏雨蘇民災。", "一爐香火動誠意，風馬雲車天際來。", "吾聞澤國多水患，淮甸地乾多苦早。", "願均神力遍四方，無令水旱常相半。"]'),
('b2363f25-6853-42dd-b07f-6a17dad6432c','秦望山','袁默','宋','宋诗','song-poetry','','[]','海上仙山與凡絕，迢迢弱水不可涉。',144,'全唐诗/poet.song.40000.json','["海上仙山與凡絕，迢迢弱水不可涉。", "鷙膺蜂准豈不知，長生不死心未滅。", "雄伯關中亦一時，並吞六國猶指揮。", "白矜功德愚黔黎，驅山塞海疑有之。", "吾聞盧生言，辟惡真人至。", "又聞徐市言，蓬萊藥可致。", "願捕巨魚連弩射，史遷記此不及彼，古老相傳恐真是。", "岷峨一夜失崔嵬，峨耳山從蜀道來。", "嗟乎六丁汝狂斐，區區爲役長城鬼。"]'),
('922107b0-9a81-4351-99bf-08cad312c11e','句  其一','袁默','宋','宋诗','song-poetry','','[]','高標遠韻果何處，宜在小沼浮荷花。',16,'全唐诗/poet.song.40000.json','["高標遠韻果何處，宜在小沼浮荷花。"]'),
('d72b5103-9fb0-4882-9873-b8be1b735313','句  其二','袁默','宋','宋诗','song-poetry','','[]','吳家風情所中欲，但欠烏賊並蝦蟆。',16,'全唐诗/poet.song.40000.json','["吳家風情所中欲，但欠烏賊並蝦蟆。"]'),
('a8f427c4-b435-465e-93b6-f9dc389934de','句  其三','袁默','宋','宋诗','song-poetry','','[]','勞生多故今老矣，覽照飄然雙鬢華。',16,'全唐诗/poet.song.40000.json','["勞生多故今老矣，覽照飄然雙鬢華。"]'),
('91343b17-e402-41d0-bf8f-b6c87f22d1d5','句  其四','袁默','宋','宋诗','song-poetry','','[]','歸來聯騎踏明月，南去眇然神思遐。',16,'全唐诗/poet.song.40000.json','["歸來聯騎踏明月，南去眇然神思遐。"]'),
('b1128519-9d5c-40ce-9791-bb926031228d','贈王筌','龔原','宋','宋诗','song-poetry','','[]','華陽新報便門板，應爲高人受籙來。',32,'全唐诗/poet.song.40000.json','["華陽新報便門板，應爲高人受籙來。", "試問玉門砂遠近，未饒元放是仙才。"]'),
('d5ad23dd-7b77-48bb-814e-ed33208a8189','句','龔原','宋','宋诗','song-poetry','','[]','吾邑毛生者，畫格妙入神。',12,'全唐诗/poet.song.40000.json','["吾邑毛生者，畫格妙入神。"]'),
('c9fd1378-18ec-4e9d-9bf2-22e02fbb60de','送程給事知越州','黄顔','宋','宋诗','song-poetry','','[]','參天樓閣翠回環，暫擁旌旄笑解顔。',64,'全唐诗/poet.song.40000.json','["參天樓閣翠回環，暫擁旌旄笑解顔。", "久想高懷厭車馬，更緣吟興屬江山。", "清時獨往逍遙地，美政能成指顧問。", "行恐便膺宣室召，都人期見捧書還。"]'),
('8a9028f6-def1-4319-bd5b-df52f05b4831','詩呈同院諸公  其一','曹輔','宋','宋诗','song-poetry','','[]','十歲湖湘客，淹留何所依。',48,'全唐诗/poet.song.40000.json','["十歲湖湘客，淹留何所依。", "清名漢閣在，他夜楚帆歸。", "落日三秋晚，浮生一笑稀。", "每煩貽秀句，真似暗投璣。"]'),
('c4c2d254-8137-439b-b2cf-c2e82924fcdc','詩呈同院諸公  其二','曹輔','宋','宋诗','song-poetry','','[]','妙論凌朝徹，高文敵夜光。',48,'全唐诗/poet.song.40000.json','["妙論凌朝徹，高文敵夜光。", "煇煌照群玉，縹緲絕飛梁。", "得句題青竹，圍棋換紫囊。", "相從愧衰朽，湖海興偏長。"]'),
('beda8002-5f74-4429-a8ac-e88d0603c194','詩呈同院諸公  其三','曹輔','宋','宋诗','song-poetry','','[]','富貴心非願，山林首重回。',48,'全唐诗/poet.song.40000.json','["富貴心非願，山林首重回。", "拂衣清世外，築室白雲隈。", "杜口同摩詰，忘形學子來。", "斯遊行欲遂，聊此接群才。"]'),
('75b82680-a184-41ec-af66-c0e59b72894b','秋日同文館詩  其一','曹輔','宋','宋诗','song-poetry','','[]','別館朋簪盍，華堂燕俎齊。',48,'全唐诗/poet.song.40000.json','["別館朋簪盍，華堂燕俎齊。", "手香思露橘，齒冷怯冰梨。", "桐影迷金井，苔痕上壁題。", "共憐今夜月，亦解照秋閨。"]'),
('7ef57ad0-9546-4bd0-9e30-bbd28751ddeb','秋日同文館詩  其二','曹輔','宋','宋诗','song-poetry','','[]','平生詩酒興，縮手少年場。',48,'全唐诗/poet.song.40000.json','["平生詩酒興，縮手少年場。", "誰敵江河量，爭看錦繡章。", "論才皆國器，滿袖尚天香。", "欲寫弘文士，風流有長康。"]'),
('5213de46-72f5-4c1d-bc0a-98552a3ebff6','秋日同文館詩  其三','曹輔','宋','宋诗','song-poetry','','[]','開口曾吟鳳，臨池豈厭雞。',48,'全唐诗/poet.song.40000.json','["開口曾吟鳳，臨池豈厭雞。", "詩豪杜工部，墨妙庾征西。", "歸及黄花在，能忘彩筆題。", "醉游須爛漫，莫惜錦障泥。"]'),
('bfc1a90c-82b7-4634-a35d-5d036e595faa','和鄧慎思未試即事雜書  其一','曹輔','宋','宋诗','song-poetry','','[]','空庭秋色晚，風露入重闈。',48,'全唐诗/poet.song.40000.json','["空庭秋色晚，風露入重闈。", "白髮已無數，故山猶未歸。", "江湖千里月，砧杵萬家衣。", "把鏡西風裏，低徊志願違。"]'),
('88907a29-a3fd-4733-bbdd-1ce47a1ee667','和鄧慎思未試即事雜書  其二','曹輔','宋','宋诗','song-poetry','','[]','鄧子詩成癖，苦吟秋夜長。',48,'全唐诗/poet.song.40000.json','["鄧子詩成癖，苦吟秋夜長。", "江山得奇秀，風月借清涼。", "郢曲高難和，騷人興未忘。", "從君乞餘教，換骨有僊方。"]'),
('999132b1-7d8b-43c1-8e68-2ba1c9c85b55','和鄧慎思未試即事雜書  其三','曹輔','宋','宋诗','song-poetry','','[]','驄馬何時到，重闈計日開。',48,'全唐诗/poet.song.40000.json','["驄馬何時到，重闈計日開。", "迎門稚子笑，載酒故人來。", "休沐猶三日，狂歌且百杯。", "祥麟秋苑靜，更約看龍媒。"]'),
('a3ec6749-1927-4267-84c5-9cd24ec1bd73','詩呈同院後至諸公','曹輔','宋','宋诗','song-poetry','','[]','同文秋已半，簾幕燕初回。',48,'全唐诗/poet.song.40000.json','["同文秋已半，簾幕燕初回。", "議論皆先覺，衰遲愧後來。", "文衡那敢與，談柄且容陪。", "誰掘豐城劍，光鋩徹斗魁。"]'),
('1139e63e-2085-48e1-a8c5-4f0c9efb7576','同舍問及故山景物用鐘字韻詩以答','曹輔','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭湖外白雲峰，醉臥虛堂聽曉鐘。',64,'全唐诗/poet.song.40000.json','["洞庭湖外白雲峰，醉臥虛堂聽曉鐘。", "澗草巖花無日歇，仙人玉女有時逢。", "脂車石路君能去，蠟屐秋風我願從。", "欲藉神方變華髮，黄精苗盛菊香濃。"]'),
('162fd5a0-e422-4ff2-b86a-305d6aa96d95','慎思屢以佳篇見貽且俾屬和而衰老困於強敵輒爲詩以謝之兼簡無咎文潛天啟','曹輔','宋','宋诗','song-poetry','','[]','鄧侯清骨如冰瘦，少日文章苦用心。',64,'全唐诗/poet.song.40000.json','["鄧侯清骨如冰瘦，少日文章苦用心。", "賦罷吹噓因狗監，詩成傳誦到鷄林。", "陽春白雪無凡曲，流水高山有至音。", "更唱自存三益友，老來衰病廢長吟。"]'),
('5ac6cc25-b66e-4b7a-bd77-bb44cd5dd687','和','曹輔','宋','宋诗','song-poetry','','[]','秋風落盡千林葉，恰似並州快剪刀。',32,'全唐诗/poet.song.40000.json','["秋風落盡千林葉，恰似並州快剪刀。", "香冷洞房歸末得，一窗明月讀離騷。"]'),
('f0d4b01b-d9b4-4971-97fb-1f8bc991f0a8','中秋月','曹輔','宋','宋诗','song-poetry','','[]','空谷秋寒同子午，白月紛紛洗清露。',32,'全唐诗/poet.song.40000.json','["空谷秋寒同子午，白月紛紛洗清露。", "遙想燈花結夜愁，鬰金斗帳香如霧。"]'),
('77d47a28-4925-439d-b4f1-f2334adae7ef','呈鄧張晁蔡','曹輔','宋','宋诗','song-poetry','','[]','都城薄祿才二釜，白髮朱衫污黄土。',128,'全唐诗/poet.song.40000.json','["都城薄祿才二釜，白髮朱衫污黄土。", "九人同日鎖重闈，一夜濤聲卷秋雨。", "投身雖喜豪俊窟，刺手如逢虎方乳。", "鄧侯相逢十載後，清骨巉巖詩思苦。", "張晁自是天下才，黄卷聊同聖賢語。", "蔡子彎弓欲射胡，拔劍酒酣時起舞。", "何當連袂上霄垠，速致時康開外戶。", "病夫行矣老江湖，容我徜徉載樽俎。"]'),
('15cb3680-d611-4ed4-b128-634777fab1c5','次韻答天啟','曹輔','宋','宋诗','song-poetry','','[]','天兵連營十萬釜，烈烈威聲震西土。',128,'全唐诗/poet.song.40000.json','["天兵連營十萬釜，烈烈威聲震西土。", "崑崙月窟掃欲空，豈止斯民被時雨。", "賀蘭狡兔遁三穴，黄口嬌雛永離乳。", "臨機一失挫銛鋒，誰願忠言如藥苦。", "吾鄉蔡子喜談兵，早歲曾過阿戎語。", "逸才自擅鸚鵡賦，高韻仍爲鸜鵒舞。", "方略應須敵萬夫，徒擊韓嫣笑當戶。", "政宜弱冠請長纓，繫取單于置高俎。"]'),
('b954006f-842e-40ca-8125-e9ee7fa4d6f7','次韻無咎戲贈兼呈同舍諸公','曹輔','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','少年落魄走四方，看山聽水興難忘。',352,'全唐诗/poet.song.40000.json','["少年落魄走四方，看山聽水興難忘。", "深林誰復知孤芳，十載江湖稱漫郎。", "紫溪風月幽思長，綠水如鏡煙蒼蒼。", "追隨豪俊多清狂，春風爛醉胥山堂。", "下瞰群峰聳如槍，吳儂棹歌笛靈羌。", "攀蘿捫壁疲獲臧，經旬選勝行齎糧。", "客兒經臺倚高岡，共臥明月吟胡床。", "投身忽落崑崙傍，征西萬馬隨騰驤。", "官軍夜半填賊隍，食盡師老催歸裝。", "將軍數奇設鷹揚，斬捕不能酬失亡。", "曲突徙薪語莫償，幕中病客非智囊。", "扁舟夷猶憶吳鄉，晁侯平日丈人行。", "生駒今始見驌驦，伯樂一盼過老南。", "恐是稟質蒼龍房，尤工吳語放降王。", "叔敖抵掌對燭光，秋英落盡金鈿黄。", "玉甕浮春醅潑香，九天廣樂來新涼。", "笑談聊此共一觴，天街六翮將翱翔。", "正值羿彀遊中央，我老委翅無復望。", "洞庭橘熟千林霜，行當拂衣解銀章。", "買取百花洲畔莊，世外日月何曾忙。", "翛然一室生吉祥，車馬還能過我牆。", "夜具茗飲與柘漿，更看君詩雲綿張。"]'),
('0e0495cb-1218-4ea0-80be-68aea97020d4','呈恩府龍學','曹輔','宋','宋诗','song-poetry','','[]','此生飄泊住乾坤，南北東西豈更論。',64,'全唐诗/poet.song.40000.json','["此生飄泊住乾坤，南北東西豈更論。", "萬里欲封防墓土，十年重到李膺門。", "少驚人事時千變，盡付羈愁酒一尊。", "主上思賢厚風俗，如公終未老丘園。"]'),
('3374247c-89f5-474e-b4b7-25fe470f83b1','釣台','曹輔','宋','宋诗','song-poetry','','[]','天地何曾着兩雄，蟄龍飛去有冥鴻。',64,'全唐诗/poet.song.40000.json','["天地何曾着兩雄，蟄龍飛去有冥鴻。", "北辰夜動雙懸象，南浦秋歸一釣篷。", "自昔何人繼高躅，至今茲地仰清風。", "悲涼古意誰能盡，落日江山醉眼中。"]'),
('f242db8b-d9b0-408c-a413-e206e10d5dcd','送周吉州','曹輔','宋','宋诗','song-poetry','','[]','廬陵太守告我行，先把廬陵爲君說。',32,'全唐诗/poet.song.40000.json','["廬陵太守告我行，先把廬陵爲君說。", "龍須山對殷侯池，池面山容兩清絕。"]'),
('61851609-2eca-4513-9e6f-3052fa9a686d','元次山居','曹輔','宋','宋诗','song-poetry','','[]','峿臺倚溪雲，痦亭枕溪石。',24,'全唐诗/poet.song.40000.json','["峿臺倚溪雲，痦亭枕溪石。", "水石競奇麗，中有漫郎宅。"]'),
('0fb82c4f-0294-4f63-a46e-2fac617610b8','古秦城','曹輔','宋','宋诗','song-poetry','','[]','海窮山盡尚南征，髀肉銷殘只白驚。',32,'全唐诗/poet.song.40000.json','["海窮山盡尚南征，髀肉銷殘只白驚。", "回首長安八千里，此中那得有秦城。"]'),
('d1a2a989-4423-4e50-84d0-cabd46a5625c','劉仙巖','曹輔','宋','宋诗','song-poetry','','[]','石磴仙巖路，登臨莫倦攀。',48,'全唐诗/poet.song.40000.json','["石磴仙巖路，登臨莫倦攀。", "亂泉歸萬壑，一目盡千山。", "障雨收雲後，松風吹莫還。", "道人今不見，無處覓玄關。"]'),
('529efb96-5e09-4b2a-bf66-cb5993523d7f','游劉道人巖','曹輔','宋','宋诗','song-poetry','','[]','故老能將舊事傳，仙翁蹤跡尚依然。',32,'全唐诗/poet.song.40000.json','["故老能將舊事傳，仙翁蹤跡尚依然。", "方知物外壺中景，隱隱煙霞有洞天。"]'),
('58cc6bc9-b735-4004-aa4b-464b8b5bd00c','同歐陽晦夫邂逅遊風洞','曹輔','宋','宋诗','song-poetry','','[]','一水群峰翠若堆，洞天終日鼓風雷。',32,'全唐诗/poet.song.40000.json','["一水群峰翠若堆，洞天終日鼓風雷。", "每懷絕境超然處，卻與幽人偶爾來。"]'),
('33cb94af-4f65-4b41-a455-ba41d17b6d19','松江亭','曹輔','宋','宋诗','song-poetry','','[]','塵路長迷眼，江亭一散襟。',48,'全唐诗/poet.song.40000.json','["塵路長迷眼，江亭一散襟。", "始驚天地闊，更覺水雲深。", "點點鷖鷳影，疏疏橘柚林。", "扁舟他日興，誰共此登臨。"]'),
('0a62b790-7a34-40b6-9a73-71b9dada570a','題白氏莊','曹輔','宋','宋诗','song-poetry','','[]','浮雲萬態變朝昏，疊嶂尋常翠滿門。',64,'全唐诗/poet.song.40000.json','["浮雲萬態變朝昏，疊嶂尋常翠滿門。", "錦里先生多勝事，香山居上有賢孫。", "春風樓閣聞棋響，晚雨池塘見屐痕。", "寄謝世間無此樂，起予歸興憶江村。"]'),
('a270395c-b047-4fd4-b697-543d2cedf0c8','清溪行','陳軒','宋','宋诗','song-poetry','','[]','山色碧與溪，扁舟泛落暉。',48,'全唐诗/poet.song.40000.json','["山色碧與溪，扁舟泛落暉。", "水煙帆界破，水鷺槳驚飛。", "島嶼隨流曲，漁監隔岸微。", "月明何處宿，待訪子陵磯。"]'),
('db0bcc2f-e33e-4b19-bd9a-c68e4cf0fb4a','憶清溪縣','陳軒','宋','宋诗','song-poetry','','[]','昔愛清溪景，人煙百里閑。',48,'全唐诗/poet.song.40000.json','["昔愛清溪景，人煙百里閑。", "湖居皆釣客，郭外盡禪關。", "酒市遙青旆，公街枕碧山。", "枉教成久別，無計約追還。"]'),
('41450a0c-307c-48b9-9097-d3e7462af2fa','泛清溪','陳軒','宋','宋诗','song-poetry','','[]','曉煙如練曳平津，一棹東風兩岸春。',32,'全唐诗/poet.song.40000.json','["曉煙如練曳平津，一棹東風兩岸春。", "島鷺沙鷗休戀我，北堂歸有白頭親。"]'),
('f636edb3-dd61-4065-84e0-ee2a2bcb0217','憶雉山書齋','陳軒','宋','宋诗','song-poetry','','[]','松陰江曲舊齋堂，別業歸來各一方。',64,'全唐诗/poet.song.40000.json','["松陰江曲舊齋堂，別業歸來各一方。", "吟想晚潮煙柳濕，夢遊春檻露花涼。", "楊朱路遠空南北，青帝亭閑自短長。", "何門揚鞭訪前景，竹窗重整讀書床。"]'),
('02a63ff7-0f65-402d-8028-74d9d223981b','桐江夕下','陳軒','宋','宋诗','song-poetry','','[]','浪催鳴艫去嘔啞，古岸蕭蕭感歲華。',64,'全唐诗/poet.song.40000.json','["浪催鳴艫去嘔啞，古岸蕭蕭感歲華。", "雨腳蒼茫驚斷雁，煙痕蒙密濕棲鴉。", "蘆花正落汀飛雪，楓葉初丹岸有霞。", "漸覺望中山色暝，數星鐙火認漁家。"]'),
('b20531a3-8c4c-401f-825c-588dc47ac07d','建昌軍','陳軒','宋','宋诗','song-poetry','','[]','土狹山高更夾溪，登臨繚繞與雲齊。',64,'全唐诗/poet.song.40000.json','["土狹山高更夾溪，登臨繚繞與雲齊。", "時時仰視天如練，往往窮川徑似梯。", "石鑿龕巖茅作屋，泉噴墝埆稻分畦。", "居人不信王畿地，千里平盤載馬蹄。"]'),
('2747e717-88b6-4b76-a9bc-858475b665d4','福州','陳軒','宋','宋诗','song-poetry','','[]','城裏三山占越都，相望樓閣跨蓬壺。',32,'全唐诗/poet.song.40000.json','["城裏三山占越都，相望樓閣跨蓬壺。", "有時細雨輕煙罩，便是天然水墨圖。"]'),
('72dd476b-3aa9-4bc9-9b0a-2761aced4be2','汀州  其一','陳軒','宋','宋诗','song-poetry','','[]','居人不記甌閩事，遺跡空傳福撫山。',32,'全唐诗/poet.song.40000.json','["居人不記甌閩事，遺跡空傳福撫山。", "地有銅鹽家自給，歲無兵盜戍長閑。"]'),
('a3747a60-7753-4bd8-91b2-09a1dc0d63b5','汀州  其二','陳軒','宋','宋诗','song-poetry','','[]','一川遠匯三溪水，千嶂深圍四面城。',32,'全唐诗/poet.song.40000.json','["一川遠匯三溪水，千嶂深圍四面城。", "花繼臘梅長不歇，鳥啼春谷半無名。"]'),
('9ef43a56-d635-4542-ac0b-43d615ed784b','南山','陳軒','宋','宋诗','song-poetry','','[]','吁然碧玉洞，屹立分雙戶。',24,'全唐诗/poet.song.40000.json','["吁然碧玉洞，屹立分雙戶。", "天生護佳景，常恐塵土污。"]'),
('4ed8aaf9-ee03-49c4-9593-76ffc5f40b2d','蒼玉洞','陳軒','宋','宋诗','song-poetry','','[]','截斷蒼山百尺崖，崢嶸相倚洞門開。',32,'全唐诗/poet.song.40000.json','["截斷蒼山百尺崖，崢嶸相倚洞門開。", "天生只隔紅塵路，不礙浮雲自往來。"]'),
('34240f7c-5cbb-4e1c-bcf6-3a9be4a667f0','袈裟泉','陳軒','宋','宋诗','song-poetry','','[]','逕石無聲下無穴，停之不盈酌不竭。',32,'全唐诗/poet.song.40000.json','["逕石無聲下無穴，停之不盈酌不竭。", "銀瓶送響落清甃，鏡奩破碎冰壺裂。"]'),
('555dfc6c-660c-4ee8-9f43-ddd60f04b2c8','南樓','陳軒','宋','宋诗','song-poetry','','[]','誰跨崇塘更起樓，捲簾平視四山頭。',32,'全唐诗/poet.song.40000.json','["誰跨崇塘更起樓，捲簾平視四山頭。", "田間草暖牛呼犢，葉底巢成鵲避鳩。"]'),
('b13182b3-8ae0-46b3-a8b7-e48f6c64a544','雲驤閣','陳軒','宋','宋诗','song-poetry','','[]','瓦流雙澗合，簾壓亂山青。',24,'全唐诗/poet.song.40000.json','["瓦流雙澗合，簾壓亂山青。", "佛刹蟠深崦，漁蓑散晚汀。"]'),
('a0385685-41c6-4a06-a2d6-2f1fc720c042','蒼玉亭','陳軒','宋','宋诗','song-poetry','','[]','我愛汀州好，山川秀所鍾。',24,'全唐诗/poet.song.40000.json','["我愛汀州好，山川秀所鍾。", "閣前橫潏水，亭畔列奇松。"]'),
('c10d631a-21d4-423d-9ba0-097702457c58','西峰院','陳軒','宋','宋诗','song-poetry','','[]','捫蘿百尺上孤峰，紅蘚斑斑杖屨蹤。',32,'全唐诗/poet.song.40000.json','["捫蘿百尺上孤峰，紅蘚斑斑杖屨蹤。", "惟有潮聲生絕頂，晚風吹動半巖松。"]'),
('3f97b211-0d17-4513-99e2-985a7a911bbc','熙春堂','陳軒','宋','宋诗','song-poetry','','[]','樓上斜陽遇似飛，樓前秋景透人衣。',32,'全唐诗/poet.song.40000.json','["樓上斜陽遇似飛，樓前秋景透人衣。", "橫碧煙嵐濃可掃，半紅霜木冷相依。"]'),
('0eba57b9-774b-4852-b9a5-61e51176a095','汀州舊州城','陳軒','宋','宋诗','song-poetry','','[]','五百年前興廢事，至今人號舊州城。',32,'全唐诗/poet.song.40000.json','["五百年前興廢事，至今人號舊州城。", "草鋪昔日笙歌地，雲滿當年劍戟營。"]'),
('93337024-52b2-463a-ba07-8d002c3c3667','贊僧宗佑真','陳軒','宋','宋诗','song-poetry','','[]','不是十二面，虛堂空寂寂。',48,'全唐诗/poet.song.40000.json','["不是十二面，虛堂空寂寂。", "不是一千年，叢林聲嚦嚦。", "奇哉丹青者，具增減不得。", "珍重四方聞，一介善知識。"]'),
('e22c5b92-3c72-42fb-ad39-cd5a3a8a7025','題蓬萊觀','陳軒','宋','宋诗','song-poetry','','[]','蓬萊觀下瑞煙飄，劉氏曾經此地超。',64,'全唐诗/poet.song.40000.json','["蓬萊觀下瑞煙飄，劉氏曾經此地超。", "桃圃昔諧王母約，煙霄自赴玉皇朝。", "白鵝乘去人何在，青鳥飛來信已遙。", "若使何郎有仙骨，也須吹引鳳凰簫。"]'),
('0204cc36-c792-4ff3-979f-cafb45752e48','上竺寺記贊','陳軒','宋','宋诗','song-poetry','','[]','白衣仙人無住著，補陀落伽渺雲海。',264,'全唐诗/poet.song.40000.json','["白衣仙人無住著，補陀落伽渺雲海。", "爲大導師安樂國，歙然徧應河沙刹。", "世界熱惱或有聞，曾不旋踵垂覆護。", "眾生心念非一種，皇皇不足嘗有求。", "如饑須食渴須水，顧亦何從滿其願。", "我觀聖心等大虛，其視萬物猶一物，細視一物如一身。", "是身四大猶不有，萬物何能作留礙。", "殊功妙用濟十方，欲求功用不可得。", "群生夢幻可兩忘，爾固無餘我無欠。", "嘗觀瑞像見寶光，如淨明珠時白赤。", "琉璃琥珀雜蒼玉，熒煌璀璨照眉宇。", "山頂或見初日升，匹素曳空煙縹緲。", "凡人顛倒作思惟，須臾變滅無復初。", "非空非色非有餘，菩薩應身亦如是。", "堂堂秘殿表東南，山君海王盡回向。", "觀音智功不思議，佛子當作何等觀。"]'),
('57979eb2-3a57-4614-a9f4-66044fc66b77','題志添禪師','陳軒','宋','宋诗','song-poetry','','[]','車輪馬足走塵煙，競看成都萬炬然。',32,'全唐诗/poet.song.40000.json','["車輪馬足走塵煙，競看成都萬炬然。", "獨我踏開亭下雪，伴師同坐一庵禪。"]'),
('8bb5191b-778d-4985-9130-fd15d59fd1fa','句  其一','陳軒','宋','宋诗','song-poetry','','[]','插盡黄花君上路。',8,'全唐诗/poet.song.40000.json','["插盡黄花君上路。"]'),
('28276417-117d-4a82-9f6a-bd7b1e710777','句  其二','陳軒','宋','宋诗','song-poetry','','[]','門闞泉川南海浦，地雄都府左龍崗。',16,'全唐诗/poet.song.40000.json','["門闞泉川南海浦，地雄都府左龍崗。"]'),
('de2867d7-fce2-464c-923c-51795d9d736e','句  其三','陳軒','宋','宋诗','song-poetry','','[]','山連庾嶺爲南徼，水與潮陽作上流。',16,'全唐诗/poet.song.40000.json','["山連庾嶺爲南徼，水與潮陽作上流。"]'),
('dce5dbc9-ebab-48fe-8a6d-0c86452b8517','句  其四','陳軒','宋','宋诗','song-poetry','','[]','巨爲三縣鎮，雄據眾山尊。',12,'全唐诗/poet.song.40000.json','["巨爲三縣鎮，雄據眾山尊。"]'),
('85484629-fb83-4c75-93fe-32f728f30996','句  其五','陳軒','宋','宋诗','song-poetry','','[]','寒樹似添新喜色，野猿猶聽舊吟聲。',16,'全唐诗/poet.song.40000.json','["寒樹似添新喜色，野猿猶聽舊吟聲。"]'),
('ed09831a-15d2-4ea6-8df6-4f195d5d8d01','句  其六','陳軒','宋','宋诗','song-poetry','','[]','十萬人家溪兩岸，綠楊煙鎖濟川橋。',16,'全唐诗/poet.song.40000.json','["十萬人家溪兩岸，綠楊煙鎖濟川橋。"]'),
('4e694cad-67f6-4425-971a-892d137b2563','句  其七','陳軒','宋','宋诗','song-poetry','','[]','渡溪緣石磴，問寺轉松崗。',12,'全唐诗/poet.song.40000.json','["渡溪緣石磴，問寺轉松崗。"]'),
('aa27fc9b-a210-4b80-babf-a0a31dae92b6','句  其八','陳軒','宋','宋诗','song-poetry','','[]','奇哉江南郭夫子，一顧能令泉價美。',16,'全唐诗/poet.song.40000.json','["奇哉江南郭夫子，一顧能令泉價美。"]'),
('6ed10a8a-db78-4557-b0db-84aea0b62b3d','句  其九','陳軒','宋','宋诗','song-poetry','','[]','溪雲影亂杉松暝，簷鐸聲流殿閻寒。',16,'全唐诗/poet.song.40000.json','["溪雲影亂杉松暝，簷鐸聲流殿閻寒。"]'),
('b5a7763f-c203-4379-a049-57caf5a455c4','句  其一○','陳軒','宋','宋诗','song-poetry','','[]','清風猿鳥自吟歎，白日輪蹄誰往還。',16,'全唐诗/poet.song.40000.json','["清風猿鳥自吟歎，白日輪蹄誰往還。"]'),
('5e0de0e9-777a-47fe-ad24-e1cc3fe371ee','句  其一一','陳軒','宋','宋诗','song-poetry','','[]','雲邊借榻開僧閻，松下聽泉洗客心。',16,'全唐诗/poet.song.40000.json','["雲邊借榻開僧閻，松下聽泉洗客心。"]'),
('0c147d37-8597-4107-92be-b47d99924259','句  其一二','陳軒','宋','宋诗','song-poetry','','[]','漲水盡頭飛雁騖，行雲缺處見亭臺。',16,'全唐诗/poet.song.40000.json','["漲水盡頭飛雁騖，行雲缺處見亭臺。"]'),
('13d438d5-4f5e-46e1-b1d2-fe9fd6ca2e42','句  其一三','陳軒','宋','宋诗','song-poetry','','[]','塵埃不到溪山好，風雨初晴燕雀多。',16,'全唐诗/poet.song.40000.json','["塵埃不到溪山好，風雨初晴燕雀多。"]'),
('a8f57d38-1dff-496c-a378-3013f4de6dfe','句  其一四','陳軒','宋','宋诗','song-poetry','','[]','南安巖近南斗傍，乾坤締結雷電守。',32,'全唐诗/poet.song.40000.json','["南安巖近南斗傍，乾坤締結雷電守。", "雲寒木老洞穴古，巨鱉露脊鯨牙口。"]'),
('6579d759-8746-4063-a0b2-537fa23a9a5d','句  其一五','陳軒','宋','宋诗','song-poetry','','[]','相看竺國兩高士，對立劍潭雙老龍。',16,'全唐诗/poet.song.40000.json','["相看竺國兩高士，對立劍潭雙老龍。"]'),
('7fbe5cb8-cc6c-4a43-aa28-72c43dd6a7e5','句  其一六','陳軒','宋','宋诗','song-poetry','','[]','南極星邊人望闕，北山樓上客思家。',16,'全唐诗/poet.song.40000.json','["南極星邊人望闕，北山樓上客思家。"]'),
('167217ce-20f0-4998-8837-7c54686b4fd4','句  其一七','陳軒','宋','宋诗','song-poetry','','[]','水暖池塘閑睡鴨，煙深村落自鳴鳩。',16,'全唐诗/poet.song.40000.json','["水暖池塘閑睡鴨，煙深村落自鳴鳩。"]'),
('224c8453-c9c6-4b83-99c0-5b2addc3c34a','句  其一八','陳軒','宋','宋诗','song-poetry','','[]','對面心千里，藏機勢萬般。',12,'全唐诗/poet.song.40000.json','["對面心千里，藏機勢萬般。"]'),
('21448b56-bfdc-4b58-8c83-66247694f798','謝王介甫見寄','周衮','宋','宋诗','song-poetry','','[]','蕭蕭秋鬢衰，誰復到荒郊。',48,'全唐诗/poet.song.40000.json','["蕭蕭秋鬢衰，誰復到荒郊。", "海內文章伯，平生道義交。", "學須明體用，詩許定推敲。", "但共餘年醉，何妨作解嘲。"]'),
('c5b95db1-0ead-487f-b0b3-af6161da8cf1','早發湖口宿道傍山寺','周衮','宋','宋诗','song-poetry','','[]','寂寂山中寺，蕭蕭月下庭。',48,'全唐诗/poet.song.40000.json','["寂寂山中寺，蕭蕭月下庭。", "煙雲晴自散，松檜老還青。", "地僻堪藏拙，僧閑不誦經。", "我來非有意，乘興寄疏櫺。"]'),
('5c5ac476-995a-46e1-9ec1-e69d00bca482','簪屣','周邠','宋','宋诗','song-poetry','','[]','堂上歌聲想遏雲，玉人休整碧紗裙。',64,'全唐诗/poet.song.40000.json','["堂上歌聲想遏雲，玉人休整碧紗裙。", "妝殘粉落臙脂暈，飲劇杯深琥珀紋。", "簪屣定知高楚客，笑談應好卻秦軍。", "莫辭上馬玉山倒，已是遲留至夜分。"]'),
('923ccab7-044e-4371-8d37-9f7c14432719','竊聞子瞻學士昨日飄然單乘獨出南屏旋至北山窮幽覽勝真得物外自適之趣邠嘗從歐陽公詩云使君厭騎從車馬留山前行歌招野叟共步青林間然明公今日之樂正得於此因成詩一章上寄','周邠','宋','宋诗','song-poetry','','[]','放歸縐騎獨尋山，直入青蘿翠藹間。',64,'全唐诗/poet.song.40000.json','["放歸縐騎獨尋山，直入青蘿翠藹間。", "謝客藜杖方自適，阮公蠟屐許誰攀。", "何愁白髮能添老，須信黄金不買閑。", "應向林泉真得趣，徜徉終日未經還。"]'),
('fe55f43e-f589-46cf-ae15-e8e536bb9563','中秋','周邠','宋','宋诗','song-poetry','','[]','月華圓滿正秋中，天上人間此夕同。',32,'全唐诗/poet.song.40000.json','["月華圓滿正秋中，天上人間此夕同。", "桂魄十分澄浪海，冰輪千里碾霜空。"]'),
('af4a0961-f3a7-4cce-9940-ee711b75bfb3','月','周邠','宋','宋诗','song-poetry','','[]','落照西山夜色浮，彎彎寒掛碧雲頭。',64,'全唐诗/poet.song.40000.json','["落照西山夜色浮，彎彎寒掛碧雲頭。", "寶奩新樣橫眉黛，珠箔斜懸半額鉤。", "丹桂一枝初淺露，金波千里未圓流。", "嬋娟三五纔成魄，散滿清光四百州。"]'),
('2f29249a-4eeb-41cc-bbe4-0b8ae58bd29e','訪慧山錢道人不遇','周邠','宋','宋诗','song-poetry','','[]','登山穿破亂雲堆，不見高人眼倦開。',64,'全唐诗/poet.song.40000.json','["登山穿破亂雲堆，不見高人眼倦開。", "門掩水聲閑白日，路無車跡長蒼苔。", "牆頭五柳空搖曳，池上雙鳧自往來。", "卻棹扁舟自回去，過江思上子陵台。"]'),
('6f647952-4a40-405d-85e0-2019d61779cd','羞墓詩','周邠','宋','宋诗','song-poetry','','[]','當年一棄會稽侯，大墓煙蕪鎖別愁。',32,'全唐诗/poet.song.40000.json','["當年一棄會稽侯，大墓煙蕪鎖別愁。", "惆悵不逢郎衣錦，至今粉骨尚含羞。"]'),
('e26a2298-9e67-4b05-b046-e2054a4cdeb0','簫臺山','周邠','宋','宋诗','song-poetry','','[]','簇簇峰巒遍四圍，神僊舊隱歎今非。',64,'全唐诗/poet.song.40000.json','["簇簇峰巒遍四圍，神僊舊隱歎今非。", "溪中不見金沙出，山外空驚白鶴飛。", "石上瀑泉清照眼，竹間嵐氣冷侵衣。", "王簫聲斷人何處，千古煙雲鎖翠微。"]'),
('593dd720-2859-42b5-a930-fca0be79a557','白石山  其一','周邠','宋','宋诗','song-poetry','','[]','賞徧他山到此山，始知仙境異人寰。',64,'全唐诗/poet.song.40000.json','["賞徧他山到此山，始知仙境異人寰。", "巖前羽客尋黄鶴，澗下樵人放白鷳。", "路入洞門紆五鎖，雲盤石徑疊三關。", "窰間猶有仙翁竈，憶昔丹成煉九還。"]'),
('93abfadc-ecd8-4abe-a480-cae41cbcac3d','白石山  其二','周邠','宋','宋诗','song-poetry','','[]','登山踏遍萬千峰，直到青雲第一重。',64,'全唐诗/poet.song.40000.json','["登山踏遍萬千峰，直到青雲第一重。", "路僻頻驚來瑞鹿，洞深還見掛蒼龍。", "偶穿白石尋黄石，卻倚青松慕赤松。", "日腳西垂促歸興，巾車無復更從容。"]'),
('57257c3b-4807-4152-86a7-fd6e31909e02','雲巖禪寺','周邠','宋','宋诗','song-poetry','','[]','石城嶺下白蓮宮，天柱峰前碧玉叢。',64,'全唐诗/poet.song.40000.json','["石城嶺下白蓮宮，天柱峰前碧玉叢。", "誤入蓬瀛知有路，回看圖畫恨無功。", "平霞列嶂堆蒼黛，飛瀑寒巖掛斷虹。", "眼底更無塵一點，霅川休說水簾宮。"]'),
('979a782b-07b3-4806-afd1-017cc2a2b2d5','淨名院  其一','周邠','宋','宋诗','song-poetry','','[]','水簾谷口瀑泉飛，金鼎峰前玉骨奇。',64,'全唐诗/poet.song.40000.json','["水簾谷口瀑泉飛，金鼎峰前玉骨奇。", "入院未登居士榻，升堂先謁贊皇祠。", "庵開明月長圓滿，路插重雲半嶮巇。", "杖屨偶來聊宴坐，徘徊不厭出山遲。"]'),
('42fa858f-9f78-4a9a-a249-39e0aa318936','淨名院  其二','周邠','宋','宋诗','song-poetry','','[]','淨名庵畔水簾谷，萬仞蒼崖漱寒玉。',32,'全唐诗/poet.song.40000.json','["淨名庵畔水簾谷，萬仞蒼崖漱寒玉。", "布衣如簾窣地垂，更有鶯聲如度曲。"]'),
('472e9242-c9b3-40be-8ede-841cc00f0b61','集真觀','周邠','宋','宋诗','song-poetry','','[]','珍重開山李道人，林巒奇秀甲諸鄰。',32,'全唐诗/poet.song.40000.json','["珍重開山李道人，林巒奇秀甲諸鄰。", "奪將狐兔千年穴，化作寒泉一境春。"]'),
('cb89ea60-c765-4ba2-900d-1d196877dc0f','白石洞天','周邠','宋','宋诗','song-poetry','','[]','此境曾聞父老傳，頃無凡跡到巖顛。',64,'全唐诗/poet.song.40000.json','["此境曾聞父老傳，頃無凡跡到巖顛。", "青霄咫尺不多地，碧洞深沉第幾天。", "千古煙霞真勝境，一方水石最清淵。", "我行聊慰登臨興，着意來遊已四年。"]'),
('162dbf75-7bab-4443-b409-6cdbe69c3fe8','句  其一','周邠','宋','宋诗','song-poetry','','[]','小杜池邊暫艤舟，老齊山下共尋幽。',16,'全唐诗/poet.song.40000.json','["小杜池邊暫艤舟，老齊山下共尋幽。"]'),
('9fe69392-951b-4c24-a404-31bdcf33f78b','句  其二','周邠','宋','宋诗','song-poetry','','[]','泗水西來一带長，望中煙浪似吾鄉。',48,'全唐诗/poet.song.40000.json','["泗水西來一带長，望中煙浪似吾鄉。", "雲收雁塔初晴影，月照龜山午夜光。", "沿汴曉穿榆莢影，過淮時嗅稻苗香。"]'),
('a2ea4be3-7f4c-431c-85cb-c2c5ba527379','句  其三','周邠','宋','宋诗','song-poetry','','[]','候得南枝臘後芳。',8,'全唐诗/poet.song.40000.json','["候得南枝臘後芳。"]'),
('e182b7b8-2b1c-4f5c-926f-12fd877f7932','望江亭','周邠','宋','宋诗','song-poetry','','[]','滄波水上巔崔嵬，中有幽亭向水開。',64,'全唐诗/poet.song.40000.json','["滄波水上巔崔嵬，中有幽亭向水開。", "草色直連天色遠，風聲長送浪聲來。", "雲收山腳雞園見，潮滿航頭釣艇回。", "咫尺市廛塵不到，檻前鷗鳥自毰毸。"]'),
('1c7b2e3c-c162-4f6e-9436-3d0228ee6352','句','周邠','宋','宋诗','song-poetry','','[]','怪石參差蹲虎兕，亂峰重疊走龍蛇。',16,'全唐诗/poet.song.40000.json','["怪石參差蹲虎兕，亂峰重疊走龍蛇。"]'),
('4a9f992d-a58b-47fb-a0cc-520e806891e9','菊花詩問答  其一','楊處厚','宋','宋诗','song-poetry','','[]','問籬菊，誰遺金英秋始縟。',28,'全唐诗/poet.song.40000.json','["問籬菊，誰遺金英秋始縟。", "花枝依舊去年黄，人髪不如當日綠。"]'),
('46fd9ee2-70d1-4c06-b1bf-7223e2743c02','菊花詩問答  其二','楊處厚','宋','宋诗','song-poetry','','[]','籬菊答，清香數日還飄颯。',28,'全唐诗/poet.song.40000.json','["籬菊答，清香數日還飄颯。", "縱使人生鬢易華，猶見黄花開幾匝。"]'),
('e918c978-bde0-4d6c-aefc-e9d5b69aa2c0','句','楊處厚','宋','宋诗','song-poetry','','[]','回望鄉關在何處，更聞杜宇轉凝魂。',16,'全唐诗/poet.song.40000.json','["回望鄉關在何處，更聞杜宇轉凝魂。"]'),
('5cfb782b-dcd0-416a-9cc1-a5ed20329e94','雨霽剡谿','顔復','宋','宋诗','song-poetry','','[]','剡溪風雨霽，航葦重行行。',48,'全唐诗/poet.song.40000.json','["剡溪風雨霽，航葦重行行。", "到處楊柳色，幾家荷葉聲。", "噪蟬金鼎沸，游水玉壺清。", "最喜魚梁伴，歸帆的的輕。"]'),
('bacf9d0f-5c9a-4577-b69b-a9dbbfcba55d','寄雲門運禪師','顔復','宋','宋诗','song-poetry','','[]','句谿曲曲剡山重，誰訪桑門物外蹤。',64,'全唐诗/poet.song.40000.json','["句谿曲曲剡山重，誰訪桑門物外蹤。", "超世有言皆實際，示人無意在機鋒。", "平生懷抱佳高遯，壯歲衣冠鎖俗容。", "每想清蟬心暫寂，秋聲蕭瑟夜庵松。"]'),
('9ad9afe7-9dcf-46d7-8033-994f401fa92e','再寄雲門運禪師','顔復','宋','宋诗','song-poetry','','[]','雲門山巔櫻葉青，雲門山腳陰谿鳴。',88,'全唐诗/poet.song.40000.json','["雲門山巔櫻葉青，雲門山腳陰谿鳴。", "山翁毀服懼世榮，大心圓靜無能名。", "松間一飯養槁形，石壁幾見秋苔生，愛山不免搜其情。", "綴拾短闋成長行，施子傳來奇可驚。", "爽闊空谷天外聲，高風擺蕩疑莖英。"]'),
('fe03f6a0-a602-4866-90a5-83d6aa91fca3','調王辟之','黄廉','宋','宋诗','song-poetry','','[]','高唐不是那高唐，風物由來各異鄉。',32,'全唐诗/poet.song.40000.json','["高唐不是那高唐，風物由來各異鄉。", "若向此中求夢雨，只應愁殺楚襄王。"]'),
('925fdba2-fce3-42a9-ae78-d0ba00f596a2','勸學','黄廉','宋','宋诗','song-poetry','','[]','河東人物氣勁豪，澤州學者如牛毛。',160,'全唐诗/poet.song.40000.json','["河東人物氣勁豪，澤州學者如牛毛。", "大家子弟弄文墨，其次亦復誇弓刀。", "去年校射九百人，五十八人同賜袍。", "今年兩科取進士，十子釣海頓靈鼇。", "邇來習俗益遷善，家家門戶爭相高。", "驅兒市上買書讀，寧使田間禾不薅。", "我因行縣飽聞見，訪問終日忘勤勞。", "太平父老知此否，語汝聖世今難遭。", "欲令王民盡知教，先自鄉里蒸群髦。", "古云將相本無種，從今著意鞭兒曹。"]'),
('9b2e4f01-299c-4d6f-9ba6-f4fcbd77c78e','留題洪慶觀','黄廉','宋','宋诗','song-poetry','','[]','隔岸山如戲獅子，背看松林閑掉尾。',128,'全唐诗/poet.song.40000.json','["隔岸山如戲獅子，背看松林閑掉尾。", "天際蒼茫落數峰，青虬下飲黄河水。", "洪濤日夜洗崖腳，容易沙洲忽生嘴。", "浮嵐積靄增氣象，因抱湯城來迤邐。", "聖世封疆屬鄉縣，令宰衙門對山起。", "朝看片雲浮簷棟，暮雨逡巡周百里。", "可憐居民老蒼翠，未省勞生有塵滓。", "乘軺亦復愧斯人，特地郵亭解行李。"]'),
('8f14d074-82bc-411c-87a5-96097a114761','過靈泉寺  其一','黄廉','宋','宋诗','song-poetry','','[]','烏噪僧眠春晝遲，松陰樓殿日高時。',32,'全唐诗/poet.song.40000.json','["烏噪僧眠春晝遲，松陰樓殿日高時。", "入門未脫征裘立，拂壁先看學士詩。"]'),
('118e7f48-3d80-4254-a75d-315148679693','過靈泉寺  其二','黄廉','宋','宋诗','song-poetry','','[]','六年道路三經此，山色泉聲似故人。',32,'全唐诗/poet.song.40000.json','["六年道路三經此，山色泉聲似故人。", "慚愧老僧相慰問，官郎何事過門頻。"]'),
('ca6d41f7-7c75-4264-b418-9fc1403e3c2a','過靈泉寺  其三','黄廉','宋','宋诗','song-poetry','','[]','瘦馬行行不著鞭，一逢泉石便留連。',32,'全唐诗/poet.song.40000.json','["瘦馬行行不著鞭，一逢泉石便留連。", "每來無可相求索，只是松窗借榻眠。"]'),
('bf76b58b-73a4-456d-aa04-d68e6e06c575','過靈泉寺  其四','黄廉','宋','宋诗','song-poetry','','[]','攬勝尋幽本爲閑，可能忙裏去遊山。',32,'全唐诗/poet.song.40000.json','["攬勝尋幽本爲閑，可能忙裏去遊山。", "權宜且輟公家事，看徧林泉夜始還。"]'),
('b6cc4a71-dcea-4a9f-b13a-35847677c9a9','石潭院次蟾禪師韻','黄廉','宋','宋诗','song-poetry','','[]','一鉢誰知去住空，前朝遺事寄禪宮。',64,'全唐诗/poet.song.40000.json','["一鉢誰知去住空，前朝遺事寄禪宮。", "孤吟盤礴數行墨，古韻蕭條四壁風。", "遊客落帆頻上下，荒庭疏樹幾青紅。", "有人會得詩中趣，日月由來亦轉蓬。"]'),
('647e793b-8b26-4699-813e-c705a0f8ea32','句','黄廉','宋','宋诗','song-poetry','','[]','眉間見喜氣，行人有歸期。',12,'全唐诗/poet.song.40000.json','["眉間見喜氣，行人有歸期。"]'),
('652c7eb4-1cc0-40e0-9ed8-6a0033cd0593','和鄧舍人讀之罘碑二十韻','韋驤','宋','宋诗','song-poetry','','[]','之罘之碑何所刻，昔者秦人紀秦德。',320,'全唐诗/poet.song.40000.json','["之罘之碑何所刻，昔者秦人紀秦德。", "風鎪日鑠斷璞昏，雨暴冰殘老龜坼。", "微芒遺字三四行，容易歷年千五百。", "文詞事實可考求，賴有子長修簡策。", "始皇末年氣益矜，輕視天下夸功名。", "玉墀金戶厭宫殿，不遠萬里爲游行。", "鼓鐘帷帳不移徙，所至毫髮皆如情。", "温寒凊暑迴造化，絕深度險安經營。", "徐市盧生巧窺測，浪語神仙致君惑。", "東巡亟欲見三山，從此海壖来轍跡。", "神仙杳邈不可攀，六龍迴首滄波碧。", "從臣無以慰躊躇，請陳勳業刊諸石。", "高文大句如形容，将以榮耀傳無窮。", "銀鈎玉箸勒未久，變故恍惚如飄風。", "人心恚望鬼神怒，滈池神怪俄符同。", "禍秦非胡日在國，長城未畢咸陽空。", "空遺此石蒼崖裏，萬古悠悠辨終始。", "雖然篆刻半缺訛，至今不得藏虚美。", "世人往往愛瑰奇，蠟澤松烟印之紙。", "覽觀莫不哀所爲，豈獨玩焉而已矣。"]'),
('1aa8094f-3672-4fad-b631-68521aaa6e96','送皮獻臣郎中赴河朔','韋驤','宋','宋诗','song-poetry','','[]','明公器業真無敵，術學精深貫今昔。',288,'全唐诗/poet.song.40000.json','["明公器業真無敵，術學精深貫今昔。", "胸中應變勇所爲，韜養許誰窺畛域。", "立朝壯齒名已高，君相都俞采風跡。", "擢從畿邑超等倫，寘之計府憑宣力。", "古來才盛多見排，議論波濤起尋尺。", "剖符江表雖左遷，憤恤何嘗動顔色。", "惟思補報誠益勤，奚翅循牆驚寵錫。", "鋤姦整敝皆得要，百事詳求不容隙。", "宜陽編戶十萬餘，疲瘵彌年逢藥石。", "旄倪愛戴憂公去，口頌心祈繼朝夕。", "除書忽爾天上來，借寇無緣徒悵惜。", "汝曹固恨奪慈父，上意其如念河北。", "河北近罹災變深，墊溺之餘病艱食。", "經營調度難其任，正是廟堂精選擇。", "此時委寄非平時，賢者豈辭當遠適。", "長川六月風雲爽，苒苒雙旌標畫鷁。", "送行擁岸車馬稠，戀德尤多淚霑臆。", "袁民慎勿挽公舟，蚤看公歸廣膏澤。"]'),
('e8cdacf1-dc5e-4795-aab1-c2fe40ff97d3','觀劈石','韋驤','宋','宋诗','song-poetry','','[]','籃輿遠冒西山色，宛轉羊腸踏寒碧。',160,'全唐诗/poet.song.40000.json','["籃輿遠冒西山色，宛轉羊腸踏寒碧。", "巖涯深處屢騰聲，何事晴雲多霹靂。", "尋聲迤邐過枯林，始見羣工劈山石。", "斧斤鋒刃奚足云，鐵楔縱横乃爲力。", "隨文察理以段致，大或尋常小盈尺。", "心冥手應出自然，不啻庖丁操騞砉。", "問其勤苦将胡爲，驅車運致希酬直。", "牛山濯濯罹採伐，萌蘖悄如無夜息。", "此山遭值甚牛山，攻撃何年可終極。", "石頑人智其奈何，智巧反爲天地賊。"]'),
('860f0eac-3d86-4bec-b758-28978b48cf5a','和殘臘幽谷西遊適','韋驤','宋','宋诗','song-poetry','','[]','晴光泛泛山之阿，谷禽朝飛聲已和。',64,'全唐诗/poet.song.40000.json','["晴光泛泛山之阿，谷禽朝飛聲已和。", "溪面冰消玉沙活，臨溪逆想春風過。", "忽來忽往祇隨興，騶從屏寘殊無多。", "略挽梅梢數纖蕊，後日重來添幾何。"]'),
('8de2ef68-13bf-40fa-995a-6dbc3c30cfdc','賦金橘得曲字','韋驤','宋','宋诗','song-poetry','','["\u957f\u6c5f", "\u6d1e\u5ead\u6e56"]','結根長江左，移植清流曲。',60,'全唐诗/poet.song.40000.json','["結根長江左，移植清流曲。", "朝暉斂夜霜，香苞間寒綠。", "落落黄金丸，堆盤照明玉。", "遠想洞庭姿，宜慚風韻俗。", "咀嚼聊一評，嗜甘毋見辱。"]'),
('d2dbe8a4-5b8c-4095-8437-f11c63b81923','即席','韋驤','宋','宋诗','song-poetry','','[]','金爐獸燄迴春律，碧琖螘花資野逸。',64,'全唐诗/poet.song.40000.json','["金爐獸燄迴春律，碧琖螘花資野逸。", "臘枝剪斷玉蓮光，歌扇舞茵争秀出。", "主人醉賓賓醉德，傾兀不慚冠武側。", "一時陳迹去莫追，此段清歡寧易得。"]'),
('6a05fc94-b9af-4ccb-8914-cd99a7bea84f','復用前韻謝和鄙篇以送行縣','韋驤','宋','宋诗','song-poetry','','[]','耐衝曉霧狐裘密，亂踏寒霜馬蹄逸。',64,'全唐诗/poet.song.40000.json','["耐衝曉霧狐裘密，亂踏寒霜馬蹄逸。", "徧行屬邑敢憚勞，樂歲償逋民易出。", "雲間想戀雙旌色，跋轡長坡首頻側。", "更懷珍句重見酬，一顆驪珠探頷得。"]'),
('dfa193a3-0afc-4699-9812-445778079cf2','和待梅花從一字至十字句','韋驤','宋','宋诗','song-poetry','','[]','梅，遲迴。',104,'全唐诗/poet.song.40000.json','["梅，遲迴。", "雪已消，花未開。", "傍山林館，近水亭臺。", "相期白玉蕊，數費碧雲才。", "况有冰霜對偶，且無蜂蝶嫌猜。", "含蓄清香知自負，包藏幽艷俟誰來。", "嶺頭信兮使騎未至，樓間怨兮角聲已哀。", "提壺秉筆兮酣詠其側，花神有知兮得不留心哉。"]'),
('da61a000-85d1-4245-8cfb-17aa98812692','□□□','韋驤','宋','宋诗','song-poetry','','[]','……藥傷才小補。',40,'全唐诗/poet.song.40000.json','["……藥傷才小補。", "此時得雨誠可歌，千里一情同鼓舞。", "邦人欽誦太守吟，太守憐民過慈父。"]'),
('18ef205a-cd98-4322-b578-f77313210f78','和新晴','韋驤','宋','宋诗','song-poetry','','[]','晴溪綠于藍，舴艋隨風泛。',48,'全唐诗/poet.song.40000.json','["晴溪綠于藍，舴艋隨風泛。", "春光一何明，山川在軒檻。", "杖履登青臯，牽條繋柔纜。", "追攀盡幽興，尋源達觴濫。"]'),
('3f5525f7-e150-4dcc-b7b0-3bfb94454878','早春遊王氏園看牡丹約花開再遊探韻賦詩得早字','韋驤','宋','宋诗','song-poetry','','[]','蜿蜒溪岸尋芳草，似覺城東春色早。',64,'全唐诗/poet.song.40000.json','["蜿蜒溪岸尋芳草，似覺城東春色早。", "並溪穿竹入幽林，已愛和風養華藻。", "叅差彫檻木芍藥，細葉新抽看漸好。", "花開使節儻尚留，願奉清樽爲花倒。"]'),
('e53017dd-bc06-4e1a-b868-4634f1f91869','和留春亭席上送蘇判官','韋驤','宋','宋诗','song-poetry','','[]','淮野征途人，鄰邦蓮幕客。',48,'全唐诗/poet.song.40000.json','["淮野征途人，鄰邦蓮幕客。", "飛鳥逸鞭聲，遥山引行色。", "歸歟况春近，林芳多甲拆。", "投宿可收燈，囊中夜光白。"]'),
('1c0cbb4f-a623-4465-bd76-c8e2fcf33239','飲櫻桃園','韋驤','宋','宋诗','song-poetry','','[]','拂閭尖出櫻桃表，花枝巧向春風裊。',64,'全唐诗/poet.song.40000.json','["拂閭尖出櫻桃表，花枝巧向春風裊。", "四座交飛白玉船，一聲相勸提壺鳥。", "搖搖畫隼青天杳，落日酣歌近芳草。", "撥開塵淟從清遊，安得樽前辭醉倒。"]'),
('f2ec369c-1e09-4f68-b6a1-e6503dfc4251','州宅牡丹盛開蒙剪欄中奇品見贈仍屬爲短歌於席上','韋驤','宋','宋诗','song-poetry','','[]','永陽州宅如仙隱，花藥妝春有畦畛。',128,'全唐诗/poet.song.40000.json','["永陽州宅如仙隱，花藥妝春有畦畛。", "牡丹開處綵爲欄，翠幕障風怯風緊。", "日高花醒一開筵，酒琖照花花自哂。", "東君不負禁林人，猛放滂葩肆鉤引。", "莫教狂雨妬清歡，狂雨來時似秋槿。", "主人愛客令翦送，一朵綵雲離玉笋。", "飲量恨非千丈陂，欲吸百嘲還噪吻。", "殷勤厚意不可酬，謾作短歌羞不敏。"]'),
('99ccf65f-d851-42cc-a789-936c9f7f2dc0','新泉','韋驤','宋','宋诗','song-poetry','','[]','美泉在山人不知，美泉出山還有時。',192,'全唐诗/poet.song.40000.json','["美泉在山人不知，美泉出山還有時。", "琅邪之東幽谷西，公來發此清漣漪。", "搜尋土脈示山叟，霜钁入土荆榛披。", "逡巡方丈露澄瑩，十目爭看青琉璃。", "一之二之來觱沸，嶺猨驚嘯溪禽飛。", "呼工叢手甃白石，玉匣寶鑑生光輝。", "自從開鑿貯寒碧，朝雲夜月常遲遲。", "春華将近天氣爽，公携賓從何逶迤。", "回環欄楯照丹碧，顛倒旌旆浮葳蕤。", "飛觴弄翰不勝樂，梅柳恨不先芳菲。", "此時玩泉愛清切，異日飲德欽規爲。", "甘香潤澤濟枯槁，源源難絕滁人思。"]'),
('f81e12fb-1780-470d-ab2e-b8862384fb83','賦酴醾短歌少留行旆','韋驤','宋','宋诗','song-poetry','','[]','酴醾高架凌春風，飄然疑與天香同。',64,'全唐诗/poet.song.40000.json','["酴醾高架凌春風，飄然疑與天香同。", "瓊英綠葉何玲瓏，開樽爛賞情無窮。", "把酒祝花花且記，玉堂仙人将整轡。", "柔條好爲挽雲軿，少慰邦人戀軒意。"]'),
('b24ec8e1-8153-464f-968c-a652ee8b7b84','曉雨離銅山驛','韋驤','宋','宋诗','song-poetry','','[]','北風吹雲頑不散，山雨蕭蕭夜将旦。',64,'全唐诗/poet.song.40000.json','["北風吹雲頑不散，山雨蕭蕭夜将旦。", "起來勉強著征衣，索馬躊躇就途晏。", "岡泥漸滑沮遄邁，林靄正濃迷遠盼。", "旅懷慘鬰亦所宜，安得秋陽露霄漢。"]'),
('cb6ac5d9-cac8-4e78-ab66-c0b8277a1279','宿景德方丈','韋驤','宋','宋诗','song-poetry','','[]','塵跡走塵途，禪林少禪客。',60,'全唐诗/poet.song.40000.json','["塵跡走塵途，禪林少禪客。", "我來宿方丈，但愛秋月白。", "夜分始就寢，萬籟同一默。", "清輝滿紗幌，歸夢徒反側。", "木魚雖無心，琅琅動吾息。"]'),
('4c3584bc-37aa-44a3-a3eb-16961085eb45','鵝湖仁壽寺','韋驤','宋','宋诗','song-poetry','','[]','環抱烟雲峰，坦夷杉松逕。',72,'全唐诗/poet.song.40000.json','["環抱烟雲峰，坦夷杉松逕。", "古寺聊稅鞅，忻然遇幽勝。", "躋攀上崖閣，足以遠眺聽。", "秋花或丹紫，殘蟬尚呼應。", "著處有佳趣，征途自無定。", "臨風誦韓詩，兩事皆害性。"]'),
('57de987e-6ea1-4a01-931d-d57d7b600383','石井泉','韋驤','宋','宋诗','song-poetry','','[]','淺淺山下洞，澄澄洞中泉。',48,'全唐诗/poet.song.40000.json','["淺淺山下洞，澄澄洞中泉。", "泉聲寂無聞，泉色碧於天。", "解纓不欲濯，瑩澈殊可憐。", "掬飲聊漱甘，顧我心常蠲。"]'),
('7f9af59b-93ca-46f6-9b84-4496527d2d6e','上饒祥符寺山亭','韋驤','宋','宋诗','song-poetry','','[]','聯舟以爲梁，度溪即幽寺。',60,'全唐诗/poet.song.40000.json','["聯舟以爲梁，度溪即幽寺。", "危亭躡層雲，遠日得以肆。", "城中樓閣多，水外峰巒翠。", "地主喜載酒，相從車馬萃。", "客心正悠悠，嚴闉促回轡。"]'),
('5e694bbf-26a1-4465-8ac8-57bc56dec2f9','月巖','韋驤','宋','宋诗','song-poetry','','[]','一等造化功，此巖以異絕。',96,'全唐诗/poet.song.40000.json','["一等造化功，此巖以異絕。", "其高僅齊雲，中空杳如月。", "如月月不圓，望之光芒全。", "何人植蒼桂，婆娑亦相緣。", "凡物偶有象，愛好獨難偏。", "強名雖自人，所得重天然。", "詩人衒巧思，或比蝕與弦。", "由來假借中，奚必加鑽研。"]'),
('d13a9428-d702-46bf-a83d-adb32150df81','九日鳳凰寺','韋驤','宋','宋诗','song-poetry','','[]','節物驚重九，區區尚山行。',192,'全唐诗/poet.song.40000.json','["節物驚重九，區區尚山行。", "固無登高約，遲明即修程。", "下馬入古寺，榜懸鳳凰名。", "來巢古所傳，至今得徽稱。", "拂席坐其堂，耳目一以清。", "歘然壯穉集，往往持盤甖。", "問其何以至，云此謝秋成。", "年年當此時，村落相經營。", "薄具𤌭飣餖，所将惟至誠。", "感此良自嘆，吾生殆如萍。", "從仕徒衮衮，退亦無田耕。", "去歲嘗爲客，今晨復遄征。", "佳節眼前過，有酒難獨傾。", "紫萸金菊花，何以爲芳馨。", "豈如羣野人，蹄涔自紓情。", "行矣姑勉強，義命心所明。"]'),
('0ea9e6bb-1718-450d-a6e7-ac5522aef1e8','過婺源諸嶺','韋驤','宋','宋诗','song-poetry','','[]','古言行路難，非獨在險阻。',139,'全唐诗/poet.song.40000.json','["古言行路難，非獨在險阻。", "兹焉婺源道，登嶺足勞苦。", "所謂路之難，其他未足數。", "躋攀上崎嶇，僅與猨狖伍。", "下臨萬丈崖，險黑不可睹。", "馬蹄長及腹，僕頷幾著土。", "俯盼飛鳥背，仰躡游雲縷。", "藤蘿爲所依，用力必審舉。", "終日踐羊腸，天寒汗如雨。", "凝結本無心，開鑿知強取。", "君不見世情嶮惡未易論，此嶺雖高前孰禦。"]'),
('2c35e973-5626-42d9-8d24-f84639408e69','古金章','韋驤','宋','宋诗','song-poetry','','[]','黄金鑄印龜爲紐，埋沒郊原已綿久。',193,'全唐诗/poet.song.40000.json','["黄金鑄印龜爲紐，埋沒郊原已綿久。", "春泥深處襯耕蹄，臘雪銷時經獵走。", "臘去春來幾百年，年年寂寞無收夤緣。", "不知何代何王賜，於此奚爲獨墜捐。", "由來至寶寧長棄，一旦光輝難自秘。", "牧兒蕘子兩窺觀，不識彫章祇知利。", "里胥白官官爲收，歘從下邑歸之州。", "發囊啟襲生精彩，十目爭視寒星流。", "粲然五字分明在，蒼龍副将軍所佩。", "将軍安在惟空名，方寸堅剛終不潰。", "物否而通理所宜，在人誰謂殊於斯。", "請看金印雜瓦礫，未逢採拾毋輕嗤。"]'),
('67c9a44a-cfce-4e05-a775-9ff32ed19879','中和堂','韋驤','宋','宋诗','song-poetry','','[]','秋陽遠泛秋山色，越嶠連雲聳深碧。',128,'全唐诗/poet.song.40000.json','["秋陽遠泛秋山色，越嶠連雲聳深碧。", "廓然千里會一堂，勢壓全吳迥無敵。", "古今貴耳不貴目，方丈蓬萊徒記籍。", "安知嚴麗非壺中，登覽渾疑脱塵迹。", "芙蓉耐霜紅兩行，杉檜凌空翠千尺。", "捲簾樽俎當清風，大白一飛羣慮釋。", "燁燁輝光生舊榜，公以中和樂邦職。", "又欽德操必有鄰，朝夕堂陰看七石。"]'),
('c98239cc-6d33-45ff-85f0-c0ccbe1001e5','寒菊','韋驤','宋','宋诗','song-poetry','','[]','皎皎園中霜，鮮鮮砌間菊。',264,'全唐诗/poet.song.40000.json','["皎皎園中霜，鮮鮮砌間菊。", "長至破旬來，兹芳乃幽獨。", "豈其時使然，寒威未加肅。", "又豈各有命，榮謝分遲速。", "如何纖柔質，堅可敵松竹。", "綠葉共威蕤，金英相陸續。", "究之得所自，養助爲之福。", "去蠧誘童稚，剪蒿專野僕。", "恐弱即枝扶，憂乾必澆沃。", "北風賴密樊，朝暉借餘燠。", "侵牟絕蜂蝶，蹴蹂無雞騖。", "得以保天材，隆冬尚芬馥。", "一溉必後枯，嵇生論尤篤。", "孟軻亦嘗歎，濯濯牛山木。", "奚獨物有是，在人宜慎毓。", "關節防疾疢，驅除先嗜慾。", "所養重於心，非徒口與腹。", "所履正乎道，非徒險與曲。", "紛華靡交戰，忮害盡消逐。", "自然致冲和，久壽不遭促。", "持兹養生理，可繼喬松躅。", "興作寒菊詩，葩浮寧傳俗。"]'),
('7fb5d1f8-c1c8-42cf-9b61-48b68cc0f720','題君佐寓翁庵','韋驤','宋','宋诗','song-poetry','','[]','人生擾擾無非寓，以寓名庵深得趣。',64,'全唐诗/poet.song.40000.json','["人生擾擾無非寓，以寓名庵深得趣。", "寓翁之庵年月多，一日持文索詩句。", "乃知主意不在詩，欲以斯言昭未悟。", "吾儕又賦寓翁庵，附贅懸疣聊復賦。"]'),
('ee4b608e-1d7f-48bd-be62-360a1db883d5','觀江都王畫拳毛騧','韋驤','宋','宋诗','song-poetry','','[]','憶昔曾觀名畫記，畫馬獨貴江都王。',272,'全唐诗/poet.song.40000.json','["憶昔曾觀名畫記，畫馬獨貴江都王。", "當時所畫拳毛騧，聲名氣格凌有唐。", "太宗愛之自題識，縑素翕赩生輝光。", "何年流落傳人間，至今不冺猶珍藏。", "高堂邂逅一注目，彷彿神駿如騰驤。", "拳毛騧非凡馬匹，天駟之精爲時出。", "虬鬚英主數跨鞍，出入戈鋋勢飄逸。", "穀州洺水血戰酣，電轉風馳萬人屈。", "欃槍掃盡社稷牢，歸來始覺金創密。", "江都能事妙入神，落筆奪得造化真。", "星瞳月頰批竹耳，一毫不謬誠絕倫。", "時移物化丹青在，後世乃識真騏驎。", "寂寥莫繼數百載，世間唯有曹将軍。", "將軍畫馬超儔侣，於此區區奚足數。", "爲圖謾雜師子花，忍使龍媒失其處。", "予知此畫名實兼，虚美安能動今古。", "歎嗟不足聊一歌，却愧辭華非杜甫。"]'),
('5270c601-7731-4a4d-b1f8-e11b5ed44baf','求陳和叔草書千文','韋驤','宋','宋诗','song-poetry','','[]','伯英臨池池水黑，世稱草聖真無敵。',160,'全唐诗/poet.song.40000.json','["伯英臨池池水黑，世稱草聖真無敵。", "逸少奇蹤昔所珍，曾爲換鵝書道德。", "晚有張顛尤怪偉，意自公孫劍中得。", "由來傳播千百年，筆法至今爲準的。", "近時此學雖彫零，妙絕何嘗虛賞識。", "唯公氣格出天然，揮掃能兼古人蹟。", "縱如烟海魚龍遊，俊若秋天鷹隼撃。", "斡旋舒慘在術內，心通手應難窺測。", "曩傳法帖久已寘，安得千文飽矜式。", "越溪明楮白於霜，晝永願公飛電墨。"]'),
('0b55dd37-798f-4f62-8ea1-8536383cc2ac','謝中書張侍郎分惠賜冰','韋驤','宋','宋诗','song-poetry','','[]','蒸雲熾結炎威稔，紫禁傳宣馳內品。',160,'全唐诗/poet.song.40000.json','["蒸雲熾結炎威稔，紫禁傳宣馳內品。", "頒冰首及輔臣家，三伏歘成秋氣凛。", "寒光瑩澈带恩輝，圭角峥嶸出天禀。", "紅塵不敢傍朱門，溽暑何由近華寢。", "無瑕獨愜水精盤，薦冷潛被文石枕。", "池鳳應思引輕喙，鼎梅亦覬清餘餁。", "蝸廬窮處厭煩酷，嘉惠分霑幸尤甚。", "兒童驚目且相懽，蠅蚋竄身寧自審。", "荷公借潤變焦枯，食蘖肺腸方渴飲。", "強持累句冒鈞衡，深愧才華非鮑沈。"]'),
('6c89df48-2dc6-486c-81de-99d022e5f0a5','暮夜還家得清叟所留二詩因以謝','韋驤','宋','宋诗','song-poetry','','["\u897f\u6e56"]','暑雲結雨殊蒸鬰，騎馬天街塵土沕。',232,'全唐诗/poet.song.40000.json','["暑雲結雨殊蒸鬰，騎馬天街塵土沕。", "汗漬巾冠溜墨珠，兩目昏眵睛忽忽。", "入門下馬意歘紓，一派清風偶飄拂。", "豁然自喜方自疑，短軸碧牋僮捧出。", "開卷知爲清叟詩，濯熱蠲煩一何疾。", "清叟之詩豪且麗，筆力滂葩少儔匹。", "上篇首吟東府西壁之畫竹，彷彿龍孫見奇質。", "繼言手植湘川斑，一一琅玕露蕭瑟。", "次篇追憶錢塘西湖之荷花，十里紅香夢難必。", "形容摸寫極纖妙，造物無心爲之屈。", "繄余何幸併獲觀，冰飲玉壺清澈骨。", "須臾狂霔轟雷車，至寶似難安陋室。", "欲還却記古人言，在處護藏宜有物。", "且攄鄙思酢所貽，無以續貂還見詰。"]'),
('33c40b83-4013-4655-9b34-72d182d0f835','昨日輒以鄙句奉謝重辱長篇爲貺再藉來韻和答次韻','韋驤','宋','宋诗','song-poetry','','[]','屋梁曉影初日暾，銀潢下沃崑岡焚。',200,'全唐诗/poet.song.40000.json','["屋梁曉影初日暾，銀潢下沃崑岡焚。", "鐵騎騰突方追奔，璵璠入水體自温。", "翩翩夢翼飛天門，異香氣力能返魂。", "真珠傾寫琉璃盆，青銅古鏡磨塵昏。", "知音聽鳳裁龍孫，重然寶劍垂荒墳。", "扶搖九萬觀化鯤，君詩體格能並存。", "大言軟語清兼渾，搜索物象窮乾坤。", "瓊牋碾出花無根，字字馥郁如芳蓀。", "至寶無價難輕論，洪波蕩縱長鯨吞。", "元化運轉通崑崙，探頤不見雕鐫痕。", "胡爲及我窮陋門，守護固乏育與賁。", "美材誰薦爲犧樽，羃之疏布飾以琨，致用清廟非常恩。"]'),
('83a7d08b-a578-4e82-91c7-8c4baeedd66f','和彦常看月','韋驤','宋','宋诗','song-poetry','','[]','雙扉窈窕疑仙穴，鎖宿彌旬塵事絕。',192,'全唐诗/poet.song.40000.json','["雙扉窈窕疑仙穴，鎖宿彌旬塵事絕。", "夜色蕭然鼓二更，聯步空庭望寒月。", "衆星掩抑天無雲，萬瓦鱗鱗带霜雪。", "俯看腐草亦光輝，仰數冥鴻自行列。", "瑶臺十二好裴徊，銀界三千孰分别。", "鉤簾却坐未欲寢，况有高談助清澈。", "匆匆置酒當虛簷，餚蔌飣餖殊微纖。", "長檠徹去不復用，豈假密炬徒炎炎。", "追思李杜篇章妙，亦有狂語時相兼。", "舉杯勸飲一何怪，斫桂浪恣尤難厭。", "豈如我輩賞以意，一觴一詠情何恬。", "興闌影側各分散，心月兩適俱無嫌。"]'),
('6375dabf-69a1-4023-909f-0df1ec76cd6d','謝鄭州張資政惠書寄酥十四韻','韋驤','宋','宋诗','song-poetry','','[]','崢嶸歲律垂更舊，蕪室蕭然度清晝。',224,'全唐诗/poet.song.40000.json','["崢嶸歲律垂更舊，蕪室蕭然度清晝。", "追想牙旌欲首途，策羸取别嘗重復。", "躊躇去德不勝情，歸迫嚴闉僅能走。", "歘驚霜月再弦望，西向拳拳使心疚。", "心之疚兮日益深，使者踵門書忽授。", "燦然誨語盈累幅，字字煇華敵瓊琇。", "殷勤睠與奚所貽，紙尾復題酥以侑。", "開緘珍視未敢嘗，捧重臨風且三嗅。", "初疑黄玉可如泥，和以露華凝不溜。", "又訝仙膏久鍊成，自有光芒發昏瞀。", "輕言豈學陸機對，以况蓴羮一何謬。", "依稀乳酒下青雲，詩慕少陵慚淺陋。", "汪洋惠意不可酬，匕箸姑停聊密覆。", "留向春朝助後觴，却望台星祝公壽。"]'),
('ec16b68f-bd8c-40cf-9900-3bc44bd7ed86','之文','韋驤','宋','宋诗','song-poetry','','[]','薄晚出城闉，江橋渡清澈。',288,'全唐诗/poet.song.40000.json','["薄晚出城闉，江橋渡清澈。", "暝投僧居宿，虚閣對圜月。", "收燈納寒光，瑩凈見毫末。", "久之未即卧，爽氣愛軒豁。", "既眠復輾轉，竟夕灘聲聒。", "嘐嘐辨初鳴，隸報馬已秣。", "就途諏所歷，七驛皆岑絕。", "自兹五昏曉，寢食乃其歇。", "肩舁及攬轡，必步由險輟。", "側身經崎嶇，仰首睨嵽嵲。", "縈棧遠如綫，危處甚苕髪。", "獨榷跨不測，震足殊卼臲。", "履之爲不疑，無乃徼幸切。", "緣崖矚飛濤，盡眼噴霜雪。", "往往生眩轉，收昐不敢瞥。", "間或得佳趣，終多備驚蹶。", "高峰撼玉枕，日射增皎潔。", "因以名其村，野老能指說。", "蘧廬盡流泉，夜響每凄咽。", "哀吟聽猿狖，殘星半明滅。", "邊城行漸近，山勢如削鐵。", "跋歷愈艱苦，氣象且凋缺。", "蕭條道旁舍，編版代瓦設。", "田婦負所汲，鳶肩語嘲哳。"]'),
('21a59102-727c-4e5d-a024-bb6ef3f60a83','小仲渡','韋驤','宋','宋诗','song-poetry','','[]','山椒積雪尚堆瓊，山下桃花已開錦。',32,'全唐诗/poet.song.40000.json','["山椒積雪尚堆瓊，山下桃花已開錦。", "若教傳畫入中州，便謂仙家事難審。"]'),
('b90d9f36-0b1f-4fde-a25f-d0e28be3c15c','得鹿','韋驤','宋','宋诗','song-poetry','','[]','呦呦山中鹿，倉卒出深藪。',240,'全唐诗/poet.song.40000.json','["呦呦山中鹿，倉卒出深藪。", "車徒歘以至，驚顧却衝走。", "荷篋適當之，觝觸難措手。", "一夫不能勝，掎角賴前後。", "我馬止其所，險隘不敢驟。", "思欲縱之去，騰突懼反受。", "𨃪𨈌縶四足，憤氣徒陰吼。", "更番耦八肩，雙隻度九堠。", "順風率汗背，暮達行館右。", "解徽置中庭，微息已絕脰。", "事殊注虞旗，難以公私剖。", "臠割遇善屠，騞砉聲隨肘。", "均霑及兵隸，不使或薄厚。", "投醪古所重，况此徧羣口。", "聞音不食肉，兹義予獨守。", "猗嗟鹿之微，共命殆非偶。", "不由馳獵窘，不以罟擭誘。", "逡巡赴死地，有若杵投臼。", "無乃失所向，猖狂自貽咎。", "彼類榛莽間，知而能警否。"]'),
('b4f409c8-7b69-4676-a708-5e678e190fa9','百堂寺','韋驤','宋','宋诗','song-poetry','','[]','巍峨江之干，故跡百堂寺。',96,'全唐诗/poet.song.40000.json','["巍峨江之干，故跡百堂寺。", "寺墊徙於旁，遺構十一二。", "百堂依巖崖，像貌宛以備。", "間雖或彫缺，亦足起敬畏。", "江流幾淺深，江木幾榮悴。", "舟車日往還，興寢誰復議。", "鑪香有餘燼，無乃妄僥覬。", "獨歎鐫鑿功，綿歷何所自。"]'),
('a7fcbd7b-87c2-466b-8a32-d1e2f76b0806','石櫃閣','韋驤','宋','宋诗','song-poetry','','[]','一登石櫃閣，載讀石櫃詩。',72,'全唐诗/poet.song.40000.json','["一登石櫃閣，載讀石櫃詩。", "詩人不可作，詩思清可思。", "至今江水流，哀響猶依依。", "佳趣想如古，物是惟人非。", "孤烟起林坳，夕鳥相與歸。", "攬轡復前征，長言解歔欷。"]'),
('a5c3d4e6-5cdd-4174-ab29-0a204a4ee804','石鏊','韋驤','宋','宋诗','song-poetry','','[]','石鏊久已傳，往還迷所自。',144,'全唐诗/poet.song.40000.json','["石鏊久已傳，往還迷所自。", "下馬詰亭卒，指以水之涘。", "徐行即其旁，執钁俟我至。", "問其将胡爲，云此久埋秘。", "泥沙亦易發，應手可立致。", "逡巡肆揮舉，兩鏊露精粹。", "青如碧琅玕，光瑩非琢治。", "圓模出自然，小大羌有貳。", "石根不可窮，名鏊乃以類。", "象物固其偶，蕪沒良可喟。", "儻非以名求，何以見珍異。", "顧我乏高才，爲詩強標識。"]'),
('fec494da-2a2d-46b3-8b82-01f81ecb9b63','過龍洞','韋驤','宋','宋诗','song-poetry','','[]','曉過龍洞口，秋雨寒江急。',72,'全唐诗/poet.song.40000.json','["曉過龍洞口，秋雨寒江急。", "㸐炬撒星飛，隨風光熠熠。", "危閣勢凌空，履滑難擇澀。", "特特馬蹄聲，谷虛良易入。", "祇恐驚神怪，轟雷起蟠蟄。", "豈不念懷安，自公忘岌岌。"]'),
('cba6e450-2089-4b81-bef9-4aeca2e86423','和蘇進之同遊烏奴山告成寺','韋驤','宋','宋诗','song-poetry','','[]','長風掠疏林，殘葉何悽悽。',240,'全唐诗/poet.song.40000.json','["長風掠疏林，殘葉何悽悽。", "浮雲带遠山，半壓愁眉低。", "縱遊烏奴寺，乃在嘉陵西。", "嘉陵清且湍，依約剡中溪。", "十月未成梁，傍舟祛挈提。", "篙工上下手，往往咍州犂。", "繫纜即肩舁，踏石避角圭。", "詰屈上嵯峨，恍若登雲梯。", "下視飛鳥背，仰聽驚猿啼。", "參差列佳境，畫幅展不齊。", "崢嶸樓殿雄，勢欲凌烟霓。", "香穗暗金像，嵐光映璇題。", "寶函發神翰，熣燦壁與奎。", "聖言遠如天，至理豈易稽。", "洗目幸榮觀，詎止徒攀躋。", "四座敬無譁，寂默桃李蹊。", "遺韶動衆聽，司南警羣迷。", "兹辰尤樂只，併合又将暌。", "鵬摶九萬程，鷦鷯一枝棲。", "其適固均耳，安中養天倪。"]'),
('63286d30-9628-46f3-9ed3-0de83cc07e77','喜雨和曹子方','韋驤','宋','宋诗','song-poetry','','[]','班超已老入玉關，仲子欲絕得螬李。',224,'全唐诗/poet.song.40000.json','["班超已老入玉關，仲子欲絕得螬李。", "洗腸術妙久疾愈，拜井誠危湧泉起。", "較之今日遇滂沱，彼情未足方吾喜。", "自從三月變旱暵，百口嗸嗸沸田里。", "豚蹄榼醑謾禱求，朝夕叢祠致拳跪。", "苗根土乾類龜坼，愁望油雲杳無涘。", "富憂攘奪貧憂踣，疾首蹙頞誰不爾。", "噫予豈獨鈞爾憂，反覆萬端思所以。", "察冤遣滯督郡邑，焚巫暴尫固非理。", "精虔賴我同僚賢，甘澤應祈災可弭。", "沛然傾注數十刻，溝畎皆盈一何偉。", "閩山草木亦增輝，萬口懽聲寧遽止。", "翼朝又復得高篇，磊落珠璣光滿紙。", "強酬珍貺愧拙疏，兩喜相投當不鄙。"]'),
('3dfa1f3b-a535-4a2e-83f3-5afeb3058478','武夷游仙詠','韋驤','宋','宋诗','song-poetry','','[]','崔嵬倚天蒼翠勻，羅列百里清無塵。',384,'全唐诗/poet.song.40000.json','["崔嵬倚天蒼翠勻，羅列百里清無塵。", "氣象不與凡山鈞，舉目已訝非前聞。", "悠悠官道行溪濱，不陟峻險仙源分。", "穿松度竹微荆榛，古觀壮麗依嶙峋。", "道人鶴氅烏紗巾，引我舉棹來長津。", "横灘激浪花如銀，舟子敏捷妙入神。", "縈紆逆泝山之根，兩壁萬仞干青雲。", "如庵如室如倉囷，奇蹤怪状何紛紛。", "仰觀持久頭酸辛，開蓬偃卧望始真。", "遺機斷脱罏不燻，漆棺不朽藏何身。", "雞窠亂草宛若新，舟航六七排魚鱗。", "半入崖厂誰施陳，輒疑構置因昔人。", "留此詭異矜常倫，却看危峭無攀捫。", "下插萬丈深潭淪，雖有智力何由伸。", "此莫謾詰徒自勤，手披舊記煩咨詢。", "逖想會仙奚所存，兩峰最大勢最尊。", "當時曾集三千賓，幔亭鋪設紫雲茵。", "酒味醇潔餚羞珍，鳳兒荷香藝絕羣。", "賓雲奏徹更幾春，飲散祇以夸曾孫。", "神仙渺茫難重論，此會此語相傳云。", "儼然遺跡尚不冺，嚴祠唯奉武夷君。", "潛有惠澤均斯民，我遊自午至夕醺。", "目力所能纔逡巡，長言記錄濡毫頻。", "師仙術異非所欣，但悵勝概無緣鄰。"]'),
('802099a8-f6f9-4c56-ba60-29d49bb0a1a6','行役一首','韋驤','宋','宋诗','song-poetry','','[]','浮梁跨寒溪，出郭十餘里。',264,'全唐诗/poet.song.40000.json','["浮梁跨寒溪，出郭十餘里。", "暝投僧舍宿，月影清如水。", "剪燭吏人退，孤坐俄隱几。", "逡巡念歲月，彫疏驚鬢齒。", "少學雖自勇，壯行何不偉。", "胡爲浪奔走，豈足稱使指。", "許國徒有心，歸田尚無擬。", "徘徊仕路間，老大良可恥。", "氣弱不耐飲，詩多常累紙。", "一吟聊破悶，再詠漸輳理。", "以及百千言，往往不能已。", "且以養情性，固非爭綺靡。", "此樂非絲竹，美聽不在耳。", "紆鬰得以紓，易直油然起。", "所以驅馳中，冥搜未嘗弛。", "今宵幸夷曠，似匪塵紛邇。", "悠悠萬感集，銷爍欲何以。", "遂爲行役篇，篇成姑自喜。", "揮毫復吟諷，若與嘉賓比。", "疏泉以養泉，所益不在彼。", "蛟蚓間相雜，要之適吾己。", "儻或不吾知，奚卹譏狂斐。"]'),
('7fb447ae-8b83-447b-bc8c-7bcde90bbb7e','别李世美','韋驤','宋','宋诗','song-poetry','','[]','御茶貢了文書閴，静一堂深生晝寂。',208,'全唐诗/poet.song.40000.json','["御茶貢了文書閴，静一堂深生晝寂。", "木蘭花謝葉成陰，霽日輝輝蕩輕碧。", "主人爲我開芳筵，灧灔金樽泛春色。", "舉杯相屬念我行，贈以長篇重圭璧。", "聯官共職誠意鈞，踰歲光陰駒過隙。", "自慚老鈍於事疏，每幸高才見禆益。", "招攜地寶溢課輸，立遣訟筒平鬰抑。", "隔州移粟賑疲甿，指日敺兵斬狂賊。", "走章馳檄公事外，間有賡酬副清適。", "搜羅絕景窮造化，鋪寫幽情露胸臆。", "今朝飲别接殷勤，判袂分岐在朝夕。", "萍蓬邂逅難期度，魚雁附託宜頻的。", "願聆三節促歸軒，聊慰馳情想風格。"]'),
('fb9d9760-d693-49a4-ab36-5fe58073064e','和禮部蘇尚書穉栝','韋驤','宋','宋诗','song-poetry','','[]','淵明植五柳，萬古清風傳。',240,'全唐诗/poet.song.40000.json','["淵明植五柳，萬古清風傳。", "子猷種修竹，幽况亦飄然。", "峥嶸韓退之，甘受庭楸牽。", "由來高爽姿，氣欲凌雲烟。", "嗜好脱凡近，孰能窺後先。", "嶽嶽尚書公，聲華天下賢。", "儀曹經晝閒，春日方暄妍。", "不思葩蘤妖，惟喜操節堅。", "呼工斬惡木，買松種堂前。", "培溉勞朝夕，霜雪期千年。", "北垣有餘地，虚鍤徒自憐。", "名卿送珍材，類至誠所緣。", "穉栝僅踰尺，標致懷參天。", "拱把念所養，扶持必周旋。", "孤根舊土随，不使知其遷。", "逡巡十旬浹，生意何鮮鮮。", "棟梁他日功，顧遇此辰偏。", "清詩爲題品，光芒耀星躔。", "栝榮詩不朽，流芳共綿延。", "後來戒翦伐，當繼甘棠篇。"]'),
('cb4aa98d-93cb-4818-9d87-b63de1a32eea','和孔彦常侍郎癸酉冬雪','韋驤','宋','宋诗','song-poetry','','[]','淳深等彭澤，瑰怪輕玉川。',120,'全唐诗/poet.song.40000.json','["淳深等彭澤，瑰怪輕玉川。", "讀公冬雪吟，爽氣何飄然。", "齋祠宿華省，對此同雲天。", "坐看積瓊瑶，光輝想藍田。", "泥滓歘藏垢，朽枯頓增妍。", "紛紛布寒空，往往迷飛仙。", "狐裘閷餘温，薫爐凝微烟。", "清冷徹心骨，復誰嘲晝眠。", "雄詞筆下驅，若放春水船。", "慶豐仍記歲，諷咏期他年。"]'),
('48bf1aa1-7e46-4e56-9fdc-60094b69c743','留題忠州豐都景德觀','韋驤','宋','宋诗','song-poetry','','[]','豐都縣北岷江側，古觀峥嶸耀金碧。',64,'全唐诗/poet.song.40000.json','["豐都縣北岷江側，古觀峥嶸耀金碧。", "層巒秀拔異羣山，喬木侵雲競千尺。", "二仙去久丹竈冷，空載遺文在碑刻。", "俗士紛紛徒嘆嗟，曾有何人繼真跡。"]'),
('113df258-27d3-4005-84f7-56d6cab98d9a','岑公洞','韋驤','宋','宋诗','song-poetry','','[]','耽耽石洞天開鎸，岑公之隱來何年。',208,'全唐诗/poet.song.40000.json','["耽耽石洞天開鎸，岑公之隱來何年。", "一朝仙去名晦然，商人受香忘所傳。", "舟抑不進方省愆，奉香入洞舟乃前。", "靈蹤自此人拳拳，至今乾溢皆致虔。", "恍忽應禱殊無偏，我來敬謁歲欲遷。", "舣泊沙磧登舁肩，蹴踏錦石行江壖。", "洞門屣步侵雲烟，瞻望塑像欽華顛。", "挺之作記誇唐賢，勒珉雖昏辭尚全。", "卻恨戾止非炎天，不見百尺懸飛泉。", "唯有巖竇聲涓涓，頃之自可遺塵緣。", "况乃投隙圖留連，嗟予遠宦方拘攣。", "搜奇尋勝姑勉旃，此日得此澄心淵。", "安能擺脱追神僊，臨崖浪筆書長篇。"]'),
('f72c517a-5a56-47d5-803e-9a60d4c9f487','追詠西園海棠','韋驤','宋','宋诗','song-poetry','','[]','西園正月月欲殘，海棠一株花正繁。',160,'全唐诗/poet.song.40000.json','["西園正月月欲殘，海棠一株花正繁。", "滂葩灧灧鬭朝日，露洗蜀錦紅光寒。", "回環桃李競無色，卓爾獨秀當朱欄。", "兩春行役不及見，今日偶幸官身閒。", "擬開金罇恣歡賞，酬酢宿恨開衰顔。", "無何職事忽牽制，遽戒舟楫乘波瀾。", "却嗟逐物猶带芥，未免回首興長嘆。", "悠悠清夜入寤寐，往往蝶夢曾飛還。", "歸來綠葉空滿枝，正與老態相追攀。", "須知樂事少如欲，誰謂天意於人慳。"]'),
('01299665-9053-4c70-bf53-751e7c8c787e','楊內翰讀書堂','韋驤','宋','宋诗','song-poetry','','[]','無爲山色參天碧，翰林舊隱多遺跡。',96,'全唐诗/poet.song.40000.json','["無爲山色參天碧，翰林舊隱多遺跡。", "跨鶴凌風去幾年，獨有文章光翕赩。", "構堂續志廣所存，善矣鴒原足餘力。", "清白永随風月久，形容杳與塵埃隔。", "伊爾歘憶四紀前，曾躡雲梯附鵬翼。", "此堂坐想不獲登，謾寄長言勒巖石。"]'),
('65adb035-dd86-445b-80cd-a712cac14ce3','八月十八日觀潮','韋驤','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','浙湍浩溔連溟渤，宵晝潮頭卷沙出。',192,'全唐诗/poet.song.40000.json','["浙湍浩溔連溟渤，宵晝潮頭卷沙出。", "中秋三日日欲西，一歲之潮盛今日。", "雪山横亘截江來，巨浪翻空生倐忽。", "吳兒當此誇善泅，執炬揚旗徐出沒。", "旁觀奚止動精爽，壯士爲之猶股慄。", "由來習俗競兹辰，士女欣然勇相率。", "紛紛畢集遶長隄，翠蓋成陰何櫛密。", "邦侯樂衆爲開筵，歌管凌虚遏雲物。", "玉堂鉅公臨右席，賓主交輝映簪紱。", "注目應同濟川念，賞心仍寓和民術。", "區區下客久不逢，二紀光陰容易失。", "幸陪高會還舊觀，聊解嘆嗟揮老筆。"]'),
('8cf06e11-6d0a-4f8c-833a-b7a6dd479365','讒龍','韋驤','宋','宋诗','song-poetry','','[]','退之昔日讒風伯，今日吾友讒應龍。',240,'全唐诗/poet.song.40000.json','["退之昔日讒風伯，今日吾友讒應龍。", "應龍聞之兩耳卓，急卷海水飛長空。", "陰雲曀曀爲後先，變化赫日成昏曚。", "田間槁穗有生意，虢子屬纊盧醫逢。", "望霓萬口動一喜，往往備賽求豜豵。", "頃之氣象復舒霽，飄灑尚不遭溟濛。", "龍乎奚爾不努力，遽若有禀還收蹤。", "天豈虐斯民，不欲爲年豐。", "林林未必皆咎戾，必有任責當其凶。", "蘄君勿龍讒，讒龍非無從。", "旱乾水溢各有召，應答不謬如洪鐘。", "昭昭之鑒明且威，詎敢曠久而忘功。", "一欲竊弄權，霶霈私羣農。", "震怒起旋踵，葅醢灾誰躬。", "慎無凝土像夭矯，晝夜狂舞青衣童。", "精誠修警感畢聽，朝暮膏澤盈寰中。"]'),
('63e5ea20-4698-44b3-9f02-1d382b2a65c8','陪宜春守皮獻臣遊化成巖','韋驤','宋','宋诗','song-poetry','','[]','城闉北出春江闊，鐵鎖聯舟波浪截。',128,'全唐诗/poet.song.40000.json','["城闉北出春江闊，鐵鎖聯舟波浪截。", "驅車度岸得幽岑，半带雲陰青欲活。", "何年造化成此巖，誰爲高閣依巉巉。", "穿巖登閣意思豁，氣象百種相交參。", "雙旌遠映蒼煙色，山鳥江花俱自得。", "使君暇豫真適然，萬室鳴弦不知極。", "江南舊美傳庾公，浩輩爽逸陪遊從。", "風流不減當時盛，獨愧非才列座中。"]'),
('5bca5965-dbcf-4c88-bcb7-92ef5ca1b6a5','上太守陳少卿十韻','韋驤','宋','宋诗','song-poetry','','[]','風流富川盛，善政久濡霑。',120,'全唐诗/poet.song.40000.json','["風流富川盛，善政久濡霑。", "市價童無惑，關譏盜不潛。", "賣刀人向本，讓路俗知謙。", "明府精區處，圜扉絕滯淹。", "青綸方調補，內屏幸趨瞻。", "直道爰來遇，孤蹤豈自嫌。", "有時申讞議，仰見霽威嚴。", "志得寧辭賤，公閑倍養恬。", "爰須祈汲引，足以慰清廉。", "靜念官居樂，長言孰可箝。"]'),
('cbb78228-b614-4a4f-966e-90ae5691e480','董都官索署中山亭詩','韋驤','宋','宋诗','song-poetry','','[]','突兀靈亭倚翠微，紛然塵境此中遺。',64,'全唐诗/poet.song.40000.json','["突兀靈亭倚翠微，紛然塵境此中遺。", "高明頗愜星郎意，邃密如嫌俗客知。", "吟對青山搖玉麈，醉臨華月解銀龜。", "襟懷蹇蹇安閒久，偃卧多應夢赤墀。"]'),
('f3591651-fe79-4c95-912f-97f07a706d46','答董都官索去年詩債','韋驤','宋','宋诗','song-poetry','','[]','軫下傳音旨，胸中長忸怩。',48,'全唐诗/poet.song.40000.json','["軫下傳音旨，胸中長忸怩。", "如何終日暇，猶負隔年詩。", "寡和知聲妙，難抽恨思遲。", "殷勤還見趣，荒鄙敢爲辭。"]'),
('8d2a3ed3-23e8-4981-b51d-93f0cc57e943','和聞新制間歲貢士','韋驤','宋','宋诗','song-poetry','','[]','五載興賢日月疏，間關多是老閒居。',64,'全唐诗/poet.song.40000.json','["五載興賢日月疏，間關多是老閒居。", "朝廷遠慮淹才敝，郡國新頒間歲書。", "士子将期賀空谷，詩人當復興嘉魚。", "無能自愧逢辰早，已脱犂鋤就棧車。"]'),
('819bbf60-5ebf-4b5b-9bf6-600bc16a38fc','和江亭春半','韋驤','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','亭壓長江氣象雄，清明時節夕陽中。',64,'全唐诗/poet.song.40000.json','["亭壓長江氣象雄，清明時節夕陽中。", "天邊遠嶂横深翠，花外餘霞沒亂紅。", "鷗鷺飛鳴得閒趣，漁樵歌唱有淳風。", "誰能共向春光醉，窮達多忘學塞翁。"]'),
('27bc6507-c42f-4012-9f6b-88ecf18e5093','和久雨','韋驤','宋','宋诗','song-poetry','','[]','陰霖繼月酷相因，旱魃今年遽喪神。',64,'全唐诗/poet.song.40000.json','["陰霖繼月酷相因，旱魃今年遽喪神。", "膏澤翻憂害東作，芳期那敢愛青春。", "蜼谷雖智能蒙鼻，奈有民咨易動脣。", "天聽甚卑羣語切，雨師何事未迴輪。"]'),
('ae1e899a-79e4-4a0a-a12f-e4ac941e0676','和寒食','韋驤','宋','宋诗','song-poetry','','[]','城關咫尺到春郊，躍馬行春固不勞。',64,'全唐诗/poet.song.40000.json','["城關咫尺到春郊，躍馬行春固不勞。", "寒食蕭疏觀物態，楚歌嘲哳聚兒曹。", "平湖漾日扁舟滿，芳榭迎風畫鼓高。", "薄暮田翁醉歸樂，山花倒插挈餘醪。"]'),
('002ba35c-a38c-4064-a9e1-e4ae8d15cbb7','雜詠五首  其一','韋驤','宋','宋诗','song-poetry','','[]','長林棲息自安如，謾勸閒人挈酒壺。',32,'全唐诗/poet.song.40000.json','["長林棲息自安如，謾勸閒人挈酒壺。", "世治有誰從醉隱，徒勞健吻汝知無。"]'),
('4d5d2ece-9eb7-43d2-806d-4b5207fd14dd','雜詠五首  其二','韋驤','宋','宋诗','song-poetry','','[]','切切聲呼泥滑滑，強關人事最無機。',32,'全唐诗/poet.song.40000.json','["切切聲呼泥滑滑，強關人事最無機。", "安知巧舌爲身累，鎖向雕籠不得飛。"]'),
('3fc2201e-1a8e-4ef3-9ffe-5db643c500c2','雜詠五首  其三','韋驤','宋','宋诗','song-poetry','','[]','蟈氏官亡種類滋，脰鳴連黨欲何爲。',32,'全唐诗/poet.song.40000.json','["蟈氏官亡種類滋，脰鳴連黨欲何爲。", "喧然無理令人惡，憶著昌黎吏部詩。"]'),
('5c9d1a85-112c-47e7-bb72-2b8defcaddd8','雜詠五首  其四','韋驤','宋','宋诗','song-poetry','','[]','憂樂由來繋所存，強名微草不須論。',32,'全唐诗/poet.song.40000.json','["憂樂由來繋所存，強名微草不須論。", "簞瓢悦道顔淵德，陋巷當時豈種萱。"]'),
('88f7299e-3534-4649-9cad-0d415d8a91b9','雜詠五首  其五','韋驤','宋','宋诗','song-poetry','','[]','啼血辛勤爾自貽，百花時節好閒飛。',32,'全唐诗/poet.song.40000.json','["啼血辛勤爾自貽，百花時節好閒飛。", "行人日日春山過，相勸相呼縂不歸。"]'),
('ea129105-6f1a-465e-af86-d190f92c3b9f','惜花','韋驤','宋','宋诗','song-poetry','','[]','玉人攜酒對花枝，悵息紅芳已半稀。',32,'全唐诗/poet.song.40000.json','["玉人攜酒對花枝，悵息紅芳已半稀。", "楚帳歌中别虞氏，馬嵬坡裏顧楊妃。"]'),
('a1945f22-250e-40e4-83e2-078d6989f91f','清明聞楚歌','韋驤','宋','宋诗','song-poetry','','[]','彷彿漁陽參鼓撾，依稀江左後庭花。',32,'全唐诗/poet.song.40000.json','["彷彿漁陽參鼓撾，依稀江左後庭花。", "清明舊俗無佳尚，唯此喧聲雜暮蛙。"]'),
('f4d60109-4343-4259-85c3-85db15f31c80','初晴復雨感事','韋驤','宋','宋诗','song-poetry','','[]','朝暉還復變濛濛，過盡韶華冷落中。',32,'全唐诗/poet.song.40000.json','["朝暉還復變濛濛，過盡韶華冷落中。", "媚紫妖紅如病悴，也應無暇笑東風。"]'),
('cbf4be21-b8e2-44d6-8d3b-4a6ea86c0e3a','和董都官登城南樓','韋驤','宋','宋诗','song-poetry','','[]','危樓百尺據城堧，徙倚渾疑到紫烟。',64,'全唐诗/poet.song.40000.json','["危樓百尺據城堧，徙倚渾疑到紫烟。", "卑濕豈愁梅雨地，清和尤喜麥秋天。", "一川晚照飛孤鶩，滿袖薫風聽杜鵑。", "鄉思搖搖白雲外，官拘唯幸際堯年。"]'),
('b562ae54-96bc-49f4-922a-777b9b2150ee','對雨懷陶掾','韋驤','宋','宋诗','song-poetry','','[]','雨氣侵池館，清如秋向深。',24,'全唐诗/poet.song.40000.json','["雨氣侵池館，清如秋向深。", "遥知修敵具，蕭灑不關心。"]'),
('d8cf2a58-2c35-4ac0-9519-c98a7d405991','思養','韋驤','宋','宋诗','song-poetry','','[]','懶登危閣望天東，山外風烟隔幾重。',64,'全唐诗/poet.song.40000.json','["懶登危閣望天東，山外風烟隔幾重。", "白髪庭闈未歸侍，青綸塵土若爲悰。", "故鄉遼夐踰千里，薄宦拘攣等萬鍾。", "指數瓜期尚稽遠，悠悠斗粟爲誰舂。"]'),
('f0027db9-5ba7-4945-b46d-a37a2ac2d37b','和聶充甫水南見寄','韋驤','宋','宋诗','song-poetry','','[]','衮衮孤城裏，惟君離俗居。',48,'全唐诗/poet.song.40000.json','["衮衮孤城裏，惟君離俗居。", "車魚絕嗟嘆，詩酒養冲虛。", "掩面羞龍斷，澄心對古書。", "天其假幽寂，停滀合何如。"]'),
('5f119385-3016-4b89-b5c7-08c00cdcaf52','又和','韋驤','宋','宋诗','song-poetry','','[]','詩來盛說溪山好，局事蕭蕭似隱流。',64,'全唐诗/poet.song.40000.json','["詩來盛說溪山好，局事蕭蕭似隱流。", "閒對文枰銷白日，勇持吟筆戰清秋。", "城中事逐漁樵得，門外客無車馬留。", "而我拘攣但增羡，強酬佳句思難抽。"]'),
('bb3fb007-f14d-4a51-96ee-7e9c4fbfbdb1','和酬聶充甫新寄','韋驤','宋','宋诗','song-poetry','','[]','霜葉乘風舞，秋雲蓋野平。',48,'全唐诗/poet.song.40000.json','["霜葉乘風舞，秋雲蓋野平。", "南溪塵境絕，東道玉壺清。", "佳處憐君得，新篇慰我情。", "無緣一攜手，相共濯冠纓。"]'),
('c6207c35-7502-4ef8-9049-f87e66b2a9ba','送李尉解任歸廬陵','韋驤','宋','宋诗','song-poetry','','[]','官冷餘才晦，塗清得代還。',48,'全唐诗/poet.song.40000.json','["官冷餘才晦，塗清得代還。", "維舟紛擾外，行酒别離間。", "水落蛟黿伏，沙空雁鶩閒。", "歸歟風味好，天末辨家山。"]'),
('08ce5224-15ed-4ccf-bd35-a094260bcbb5','攝戶糾二曹事因自戲','韋驤','宋','宋诗','song-poetry','','[]','三參軍事歸權握，賤務區區日倍增。',32,'全唐诗/poet.song.40000.json','["三參軍事歸權握，賤務區區日倍增。", "却笑近賢銜署貴，時人虛號一條冰。"]'),
('b15e9eda-cf9c-4bea-9048-0e1e70c8a6a1','賈尉見迫給廪因以詩戲','韋驤','宋','宋诗','song-poetry','','[]','月粟見須何太迫，賤生奔走正無聊。',32,'全唐诗/poet.song.40000.json','["月粟見須何太迫，賤生奔走正無聊。", "蘄君勿慮晨炊絕，吾黨而今解折腰。"]'),
('05b3e2b6-c28b-45fc-9552-919c95a4a559','送浦大會甫赴榆次','韋驤','宋','宋诗','song-poetry','','[]','平生落落多豪氣，萬里區區赴冷官。',64,'全唐诗/poet.song.40000.json','["平生落落多豪氣，萬里區區赴冷官。", "今日送君非故閈，一樽爲我盡情歡。", "解舟吳浦江雲重，策馬并門塞雪寒。", "富貴功名行孰禦，古來新沐必彈冠。"]'),
('3085550f-6bc2-4937-8bdb-732e79e01498','賈慶甫示山中梅詩因繼成','韋驤','宋','宋诗','song-poetry','','[]','雪意将成臘欲来，亂山深處見寒梅。',32,'全唐诗/poet.song.40000.json','["雪意将成臘欲来，亂山深處見寒梅。", "化工若與人情比，此樹多應未及開。"]'),
('1dde5063-8b58-49df-94b9-f8388140c6cf','答魯虞部見寄','韋驤','宋','宋诗','song-poetry','','[]','鄙才效職便窮僻，忽忽天星殆二周。',64,'全唐诗/poet.song.40000.json','["鄙才效職便窮僻，忽忽天星殆二周。", "繫獄空虛民訟少，倖門堙塞吏心憂。", "琴書永日清無際，草樹逢春綠正柔。", "驚坐高賓如見顧，幽懽何惜貰貂裘。"]'),
('51e09ed6-40bf-49bf-bbbf-56bb05276f1d','又答惠詩并新鱔','韋驤','宋','宋诗','song-poetry','','[]','珠璣盈紙将新味，方丈分甘及賤夫。',32,'全唐诗/poet.song.40000.json','["珠璣盈紙将新味，方丈分甘及賤夫。", "大啜一杯鄉思動，却咍張翰只思鱸。"]'),
('751f4316-d451-4c8e-9990-9a95d395ba5a','獨登臨清閣','韋驤','宋','宋诗','song-poetry','','[]','揚揚何處一逍遥，朱閣臨清興味高。',64,'全唐诗/poet.song.40000.json','["揚揚何處一逍遥，朱閣臨清興味高。", "翠靄相連結春態，澄光下視鑑秋毫。", "綠楊静舞腰初困，白鳥閒栖目不逃。", "獨到獨歸俱有意，暫期塵土落祇裯。"]'),
('d434f126-1f4d-449a-967f-c023d1f68b95','得董都官書因爲寄四首  其一','韋驤','宋','宋诗','song-poetry','','[]','晚來音驛拜勤渠，咫尺拘攣萬里疏。',32,'全唐诗/poet.song.40000.json','["晚來音驛拜勤渠，咫尺拘攣萬里疏。", "却羨潯陽堤上柳，長條往往拂賢車。"]'),
('61bd47df-3184-48ad-8e21-7c95ad0bce16','得董都官書因爲寄四首  其二','韋驤','宋','宋诗','song-poetry','','[]','七年恬寞坐江瀕，今日登途氣象春。',32,'全唐诗/poet.song.40000.json','["七年恬寞坐江瀕，今日登途氣象春。", "請劇書成爲澤大，馬蹄無惜入紅塵。"]'),
('c267b6b0-ac12-4943-ad54-c36763470eb6','得董都官書因爲寄四首  其三','韋驤','宋','宋诗','song-poetry','','[]','花表危樓遠目窮，華軒不見見春濃。',32,'全唐诗/poet.song.40000.json','["花表危樓遠目窮，華軒不見見春濃。", "春山繚繞無重數，還在春山第幾重。"]'),
('093c4b32-d113-4e04-99cd-7ecedd6b96e8','得董都官書因爲寄四首  其四','韋驤','宋','宋诗','song-poetry','','[]','登臨何以慰相思，把酒開編讀舊詩。',32,'全唐诗/poet.song.40000.json','["登臨何以慰相思，把酒開編讀舊詩。", "正是去年酬唱景，春風花草半離披。"]'),
('e4196682-de4c-4aac-b23c-04e6512bdf26','椶花','韋驤','宋','宋诗','song-poetry','','[]','葉落不隨羣，花開亦趁春。',48,'全唐诗/poet.song.40000.json','["葉落不隨羣，花開亦趁春。", "初包蓮蕊白，半折粟文皴。", "蜂蝶遥相笑，兒童冷不親。", "華丹君勿責，勁直在吾身。"]'),
('5b7c8e1d-1b93-4c20-9f0d-31e6fe2415c0','和太守臨清閣一首','韋驤','宋','宋诗','song-poetry','','[]','朱閣新前構，峥嶸枕水端。',240,'全唐诗/poet.song.40000.json','["朱閣新前構，峥嶸枕水端。", "地饒千頃秀，天付四時寒。", "波蹙龍鱗活，山斜鳳翼攢。", "晴光照毛髮，翠靄奪華丹。", "賀老空遊鑑，嚴公浪記灘。", "軒窗通浩蕩，榱桷變彫殘。", "静極塵機喪，清多餌釣難。", "來當思潔白，意不在遊盤。", "氣爽如開凌，隄環若刈蘭。", "繪工憂措手，詩将勇濡翰。", "遠目窮層漢，澄心俯曲欄。", "鳶魚皆自得，宇宙始知寛。", "神物亨中發，賢侯與衆懽。", "政聲喧盛美，隅泣解辛酸。", "登覽臨春晝，雍容兀醉冠。", "千齡幸臣宋，五袴正歌潘。", "環佩鏘芳席，旌麾掲畫竿。", "笳簫音嘒嘒，貔虎勢桓桓。", "俗樂芹爭采，賓歸鋏不彈。", "落成今日事，遺愛永江干。"]'),
('0946483e-ea41-4a0f-b91d-66c46c89d9b1','榴花','韋驤','宋','宋诗','song-poetry','','[]','本根樹立宜堅厚，韡韡佳花號石榴。',64,'全唐诗/poet.song.40000.json','["本根樹立宜堅厚，韡韡佳花號石榴。", "丹赤終能盡敷吐，馨香何必事飄浮。", "晴光照處火欲烈，雨氣凝時血不流。", "莫怨春風施力晚，天教美實冠清秋。"]'),
('81896d40-ac48-4fff-b236-4269a003d51b','乾元節口號','韋驤','宋','宋诗','song-poetry','','[]','祥電當年繞斗明，巖廊今日享隆平。',64,'全唐诗/poet.song.40000.json','["祥電當年繞斗明，巖廊今日享隆平。", "三朝功業山河固，萬國謳歌宇宙清。", "湛露均恩錫華宴，薫風入奏阜羣生。", "庶官願祝無疆壽，葵藿心齊向日傾。"]'),
('88a44679-8e41-4c28-a305-b2c4d41e687a','觀棋','韋驤','宋','宋诗','song-poetry','','[]','不卜天時不背山，枯棋遇敵戰談間。',64,'全唐诗/poet.song.40000.json','["不卜天時不背山，枯棋遇敵戰談間。", "藏機闇伏三千楯，侵道雄闚百二關。", "羣語雖咻難改聽，一先偶失若無顔。", "人心勇善能如此，誰謂淵騫未易攀。"]'),
('58be95ce-0190-44b4-82a7-3f7e8a0e4fa4','剪金花一首和陶掾','韋驤','宋','宋诗','song-poetry','','[]','花神委曲競光陰，特向低叢剪寸金。',64,'全唐诗/poet.song.40000.json','["花神委曲競光陰，特向低叢剪寸金。", "買斷園林初夏景，竟教蜂蝶慰寒心。", "玲瓏圓影風前舞，寂寞紅芳雨後深。", "稚子知名不知實，采之擲地聽餘音。"]'),
('19107a30-fb18-4c58-9ad8-a5b84d4610ab','枇杷','韋驤','宋','宋诗','song-poetry','','[]','美種盛東南，園林十二三。',48,'全唐诗/poet.song.40000.json','["美種盛東南，園林十二三。", "金丸方磊落，瓊液正包含。", "採熟鳴禽怨，餐多稚子貪。", "豈須江國重，天下嗜柔甘。"]'),
('105ff562-072c-4af7-bf16-a52a0b33867c','和陶掾同登曉亭','韋驤','宋','宋诗','song-poetry','','[]','芳蹊詰曲上亭南，小樹縈紆若舞驂。',64,'全唐诗/poet.song.40000.json','["芳蹊詰曲上亭南，小樹縈紆若舞驂。", "直對蒼山班席坐，旋尋幽卉滿頭篸。", "楮皮裁幅明如玉，竹葉浮杯淥似藍。", "共酌共談其樂勝，俗憂應是不能堪。"]'),
('8f90f593-17d1-44be-9df3-039c0d1b1a95','慶甫借棋子','韋驤','宋','宋诗','song-poetry','','[]','碾玉爲棋黑白明，臨枰思策且須精。',32,'全唐诗/poet.song.40000.json','["碾玉爲棋黑白明，臨枰思策且須精。", "莫教敗衄空如掃，却出枝辭輒罪兵。"]'),
('4d11c592-7dd9-4562-983e-586a690a4da9','和賈尉女真花','韋驤','宋','宋诗','song-poetry','','[]','衹恐繁雲熾碧空，火龍晝躍汗随風。',64,'全唐诗/poet.song.40000.json','["衹恐繁雲熾碧空，火龍晝躍汗随風。", "飄來翠葉亭亭處，滴出芳葩點點紅。", "最美虛心如有待，直饒潤色更無濃。", "主人爲爾邀賓醉，狼藉杯盤晚照中。"]'),
('a5e27f13-472f-4690-afcf-cee32b1d5074','昨暮會飲慶甫署觀女真花因求一二諾以厥明至期不至遂戲成一首','韋驤','宋','宋诗','song-poetry','','[]','見許黎明和露翦，日高何事尚稽期。',32,'全唐诗/poet.song.40000.json','["見許黎明和露翦，日高何事尚稽期。", "也知更欲延賓履，次第開時固未遲。"]'),
('556d678e-5a0e-49d0-85db-81e3369a3790','謝太守惠家園瓜','韋驤','宋','宋诗','song-poetry','','[]','種繼青門氣類嘉，恩傳鈴閣動光華。',64,'全唐诗/poet.song.40000.json','["種繼青門氣類嘉，恩傳鈴閣動光華。", "含滋雖本生成力，采實難勝寵賜加。", "冽若層冰破蒸鬰，明如碧玉照玼瑕。", "賤官咀嚼深銜戀，代至明年正及瓜。"]'),
('1cd415df-4452-4aad-8c54-2ac7da8f130e','蕭灑參軍宇六首  其一','韋驤','宋','宋诗','song-poetry','','[]','蕭灑參軍宇，臨庭客不過。',48,'全唐诗/poet.song.40000.json','["蕭灑參軍宇，臨庭客不過。", "秋花生意漸，夏木晝陰多。", "坦腹羣書榥，搘藜一徑莎。", "塵泥奔走外，得此興如何。"]'),
('bdca1438-248c-4294-b0bd-7ce787af00f8','蕭灑參軍宇六首  其二','韋驤','宋','宋诗','song-poetry','','[]','蕭灑參軍宇，年來訟獄稀。',48,'全唐诗/poet.song.40000.json','["蕭灑參軍宇，年來訟獄稀。", "凝塵掩丹筆，蒼蘚半圜扉。", "晚樹鳴蟬沸，虛簷鬬雀飛。", "何須溪谷隱，即此是忘機。"]'),
('ddd7c7bb-35b8-4f82-9abd-61bdf1df3b37','蕭灑參軍宇六首  其三','韋驤','宋','宋诗','song-poetry','','[]','蕭灑參軍宇，郊原咫尺分。',48,'全唐诗/poet.song.40000.json','["蕭灑參軍宇，郊原咫尺分。", "門前漲溪水，屋角露山雲。", "白鳥斜陽見，鳴榔半夜聞。", "安知名利境，馳騁共紛紛。"]'),
('5cce9d77-54af-4944-ad28-854c84923108','蕭灑參軍宇六首  其四','韋驤','宋','宋诗','song-poetry','','[]','蕭灑參軍宇，回環百畝間。',48,'全唐诗/poet.song.40000.json','["蕭灑參軍宇，回環百畝間。", "山光侵戶牖，柳色鎖門闌。", "盡愛清風滿，相仍白日閒。", "祇贏詩思勇，濡筆濺青綸。"]'),
('cbec9963-56c5-46e0-ab3e-75519d173084','蕭灑參軍宇六首  其五','韋驤','宋','宋诗','song-poetry','','[]','蕭灑參軍宇，疏池小圃東。',48,'全唐诗/poet.song.40000.json','["蕭灑參軍宇，疏池小圃東。", "風荷朝披靡，月竹夜玲瓏。", "樽酒有時滿，嚢錢計日空。", "養恬真得地，捽茹樂融融。"]'),
('f1e1851e-fa2a-4f93-84bb-d50e95071a07','蕭灑參軍宇六首  其六','韋驤','宋','宋诗','song-poetry','','[]','蕭灑參軍宇，幽軒占一隅。',48,'全唐诗/poet.song.40000.json','["蕭灑參軍宇，幽軒占一隅。", "栟櫚雙翡翠，薜荔綠氍毹。", "偃息三年計，炎歊六月無。", "跧藏晦疏拙，違俗任盧胡。"]'),
('09290ee0-2126-427e-801a-692120c8de7e','八月泛江送客','韋驤','宋','宋诗','song-poetry','','[]','送客欲逡巡，方舟舣棹頻。',48,'全唐诗/poet.song.40000.json','["送客欲逡巡，方舟舣棹頻。", "夕陽千嶂外，秋色一江匀。", "酒面紅煙慘，歌眉翠黛顰。", "昔年離别恨，今日併如新。"]'),
('0c06d409-a6f8-4525-8e05-b71e6e3a68c8','送浦倅之闕','韋驤','宋','宋诗','song-poetry','','[]','翹翹别乘出吳關，吏俗随轅不敢攀。',64,'全唐诗/poet.song.41000.json','["翹翹别乘出吳關，吏俗随轅不敢攀。", "此日謾淹飛蓋住，明時那許壯才閒。", "秋花幾處逢孤驛，凉月相迎過暮山。", "請劇書成雙闕近，佇聞忠論解天顔。"]'),
('4ebd8083-0277-44e4-88cf-082af72bb397','酷暑初夜','韋驤','宋','宋诗','song-poetry','','[]','盡日炎炎酷暑蒸，黄昏氣象未全清。',64,'全唐诗/poet.song.41000.json','["盡日炎炎酷暑蒸，黄昏氣象未全清。", "天風難值樹渾静，海月不見雲空明。", "羣蚋得時方伺隙，噪蟬何事懶收聲。", "噫予自有安恬趣，豈廢林間坦腹行。"]'),
('36b539d8-f0b3-40bd-8af9-19a0146324e9','十月','韋驤','宋','宋诗','song-poetry','','[]','風脚無時定，霜花晝亦飛。',48,'全唐诗/poet.song.41000.json','["風脚無時定，霜花晝亦飛。", "天愁雲四合，樹冷鳥相依。", "陋室羣書滿，衡門俗客稀。", "饑腸何以療，園芋正豐肥。"]'),
('2ef084bb-fbaa-4bf8-bf0e-5b4aec4b1135','望','韋驤','宋','宋诗','song-poetry','','[]','木落望始遠，陰沈其奈何。',48,'全唐诗/poet.song.41000.json','["木落望始遠，陰沈其奈何。", "遥山雲四閉，飛雪兩相和。", "天慘景愈短，樓高寒更多。", "凝然空引睇，鴻鵠不知過。"]'),
('192a3a9c-c4bd-4907-9027-590bdf6f2632','和吳常甫移石','韋驤','宋','宋诗','song-poetry','','[]','千夫挽車載，無計奈人靈。',48,'全唐诗/poet.song.41000.json','["千夫挽車載，無計奈人靈。", "驚起蛟蟠跡，空遺鳥篆腥。", "莫歌山有栲，始信物如萍。", "只愛堅姿峭，予眸爲爾青。"]'),
('b155f1c4-a292-46c9-b661-45dfc0e5e557','再和','韋驤','宋','宋诗','song-poetry','','[]','突兀見升平，前非望汝靈。',48,'全唐诗/poet.song.41000.json','["突兀見升平，前非望汝靈。", "塵途雖闔眼，血刃不磨腥。", "氣格希神嶽，漂浮賤水萍。", "遇遷何足計，唯守自然青。"]'),
('15079b9c-9efe-44fa-9b81-466e1b853ef6','殘春  其一','韋驤','宋','宋诗','song-poetry','','["\u897f\u6e56"]','家近西湖日往還，恬然不覺到春闌。',32,'全唐诗/poet.song.41000.json','["家近西湖日往還，恬然不覺到春闌。", "水邊花發華丹盡，水面清光終未殘。"]'),
('3bd170ff-b93f-426e-b9d8-b70d6d8ff9a3','殘春  其二','韋驤','宋','宋诗','song-poetry','','[]','休王其如各有時，開榮方徧又春歸。',32,'全唐诗/poet.song.41000.json','["休王其如各有時，開榮方徧又春歸。", "東君憂在陽功乏，多少閒雲天上飛。"]'),
('4c75cc5e-8ab3-48b6-a0a7-fd75481bbd6b','塞上','韋驤','宋','宋诗','song-poetry','','[]','塞草游駒犢，邊城夜不關。',48,'全唐诗/poet.song.41000.json','["塞草游駒犢，邊城夜不關。", "健兒心亦禮，老将沒於閒。", "豈見兵符走，唯聞象貢還。", "從兹徐勣比，不得冢前山。"]'),
('92e734b1-ba87-40dc-bbe3-26e4c966a769','初上汴舟思歸','韋驤','宋','宋诗','song-poetry','','[]','夜氣凄清星斗全，倚檣引望東南天。',64,'全唐诗/poet.song.41000.json','["夜氣凄清星斗全，倚檣引望東南天。", "懷歸重念秋垂盡，倦目羞看月又圓。", "况是汴流投淺涸，夫何單舸尚留連。", "京華豈謂無心戀，自恨孤蹤遠邃延。"]'),
('1dbf8829-0403-4b18-9dc8-5620db8abc4b','小飲樓上作','韋驤','宋','宋诗','song-poetry','','[]','西風吹酒面，樓閣近重陽。',48,'全唐诗/poet.song.41000.json','["西風吹酒面，樓閣近重陽。", "悔把菊枝插，幡思鄉路長。", "比來求熟醉，到了减清狂。", "不是紛華少，紛華我所忘。"]'),
('905cfc30-f3ef-48d2-a9e1-1f11d0564a73','舟晚行','韋驤','宋','宋诗','song-poetry','','[]','汴水日就淺，篙師心不皇。',48,'全唐诗/poet.song.41000.json','["汴水日就淺，篙師心不皇。", "扁舟若無滯，舊里亦非長。", "殘葉餘秋色，明霞接暮光。", "黄昏未停泊，獨自倚危檣。"]'),
('c54f39ee-82af-4168-a3bc-4871a6cb27b3','汴上榆柳','韋驤','宋','宋诗','song-poetry','','[]','栽培芟治責官曹，官牒書爲第一勞。',64,'全唐诗/poet.song.41000.json','["栽培芟治責官曹，官牒書爲第一勞。", "擢幹不知多少樹，施功唯繫萬千艘。", "斧斤畏法誰能近，雨露流恩氣轉豪。", "今歲河堤新决壞，森然安用拂雲高。"]'),
('74354484-c301-40ba-b77f-06f92aa450f9','歸興','韋驤','宋','宋诗','song-poetry','','[]','船頭破浪疾如雲，船上篙工勇力分。',64,'全唐诗/poet.song.41000.json','["船頭破浪疾如雲，船上篙工勇力分。", "行色縱無笳鼓競，歸心急在旨甘勤。", "遠山偶向斜陽見，幽雁偏從半夜聞。", "安得巨觥爲大飲，亂澆鄉思作醺醺。"]'),
('56f45b86-1ff6-4231-9012-a248921e530f','初入淮上','韋驤','宋','宋诗','song-poetry','','[]','汴水方窮到淮水，大船蹇蹇拒風行。',64,'全唐诗/poet.song.41000.json','["汴水方窮到淮水，大船蹇蹇拒風行。", "不知静裏千帆過，唯喜空中一派清。", "秋氣已殘山態老，夕陽未盡浪花明。", "牧兒隨隊閒無事，強作歌聲和櫓聲。"]'),
('d2e61edf-bcc0-4918-9b4b-8a55c1991b0c','自守','韋驤','宋','宋诗','song-poetry','','[]','薄仕功名未計高，懶隨時輩強譊譊。',64,'全唐诗/poet.song.41000.json','["薄仕功名未計高，懶隨時輩強譊譊。", "推誠本在求諸內，害義何如寡所交。", "豈爲初官尋要路，唯憂舊學長心茅。", "清貧我樂人毋誚，不獨揚雄解解嘲。"]'),
('65282dcb-4c1f-4bea-8198-251c62fb1d7c','驤每惡晏起強酒二癖因作詩自警','韋驤','宋','宋诗','song-poetry','','[]','晏起已嗟爲惰甚，詎堪酒病復相嬰。',64,'全唐诗/poet.song.41000.json','["晏起已嗟爲惰甚，詎堪酒病復相嬰。", "未憂居養能移氣，當念懷安實敗名。", "便腹亦嘗嘲睡癖，腐腸非是醉時清。", "辰乎徑去誰能止，壯志毋宜恃晚成。"]'),
('f0567fa2-999d-40c2-8a46-4c1c74299143','感夢','韋驤','宋','宋诗','song-poetry','','[]','真人無夢夢非真，自愧通宵所夢頻。',32,'全唐诗/poet.song.41000.json','["真人無夢夢非真，自愧通宵所夢頻。", "凶吉有来皆繫命，豈須占訊復勞神。"]'),
('ea612e93-34eb-468d-b520-344c602010b0','将赴富川','韋驤','宋','宋诗','song-poetry','','[]','去年乾沒道途間，今歲官期日月慳。',64,'全唐诗/poet.song.41000.json','["去年乾沒道途間，今歲官期日月慳。", "學古雖然非爲祿，食貧寧不厭居閒。", "利心汲汲人皆是，巧宦悠悠我不關。", "三尺若能多所活，塵泥何必賤青綸。"]'),
('87d25936-ddb3-4fb0-aae9-a8b48c60594c','駐軒亭','韋驤','宋','宋诗','song-poetry','','[]','下馬得危亭，江晴氣象清。',48,'全唐诗/poet.song.41000.json','["下馬得危亭，江晴氣象清。", "潮頭千頃白，柳色萬株明。", "風物應如古，登臨獨有情。", "行春始今日，今日不虛行。"]'),
('46c950cf-b38b-4c9d-b8be-e9b6a70054c2','過桐廬縣','韋驤','宋','宋诗','song-poetry','','[]','舟倚桐廬岸，春風草樹明。',48,'全唐诗/poet.song.41000.json','["舟倚桐廬岸，春風草樹明。", "經由今假道，瀟灑舊聞名。", "山勢侵雲上，溪流見底清。", "兹行得佳味，夜枕聽灘聲。"]'),
('f6444ef9-c3ef-42f7-897d-7a5f6020176e','過七里瀧','韋驤','宋','宋诗','song-poetry','','[]','溪流一道突羣峰，耆舊傳爲七里瀧。',64,'全唐诗/poet.song.41000.json','["溪流一道突羣峰，耆舊傳爲七里瀧。", "唯喜幽佳忘世俗，不憂湍險賴篙工。", "鳥聲喧滑春風裏，人影稀疏翠色中。", "却惜扁舟不停泊，全輸好趣屬山翁。"]'),
('a48c88cd-f5e7-4a65-ba88-ca6281f6e792','和紅蕉','韋驤','宋','宋诗','song-poetry','','[]','欲賦紅蕉擬象難，等夷未必下芝蘭。',64,'全唐诗/poet.song.41000.json','["欲賦紅蕉擬象難，等夷未必下芝蘭。", "霞飛翠嶺分餘彩，鳳宿青梧半露冠。", "舉目盡知驚特秀，推誠誰解比含丹。", "莫教俗筆空傳畫，也作尋常潤色看。"]'),
('b2f2e082-4baa-4592-bba7-af97100e6072','和公餘言懷','韋驤','宋','宋诗','song-poetry','','[]','荆扉棲息久，壯志未能攄。',120,'全唐诗/poet.song.41000.json','["荆扉棲息久，壯志未能攄。", "昨被半通綬，新持三尺書。", "雖然煩聽訊，何足撓冲虛。", "伺隙餘公局，開編入燕居。", "敢希成大器，唯恐近污渠。", "心欲平冤獄，情奚病猾胥。", "賢門不多地，賤子幸投裾。", "每得高文貺，翻嗟舊業疏。", "自滋忘棄學，豈復悵離蔬。", "若使華無實，寧爲蔽芾樗。"]'),
('2094336a-601e-4db4-9265-9516b0edd85c','和訪古','韋驤','宋','宋诗','song-poetry','','[]','古人抱道重行志，未肯輕從碌碌居。',64,'全唐诗/poet.song.41000.json','["古人抱道重行志，未肯輕從碌碌居。", "孟子歷爲侯國客，退之三上相君書。", "心忘險阨高蘇武，言極興衰仰仲舒。", "試問渭濱如不遇，直鉤何日得生魚。"]'),
('7d31b82e-a0f3-465b-9534-1eaa98f73b08','五月到官七月八日始併得家問二','韋驤','宋','宋诗','song-poetry','','[]','瑣瑣塵泥跡，悠悠遠宦心。',48,'全唐诗/poet.song.41000.json','["瑣瑣塵泥跡，悠悠遠宦心。", "一朝何喜甚，連客得家音。", "義訓通千里，人情賤萬金。", "斜陽復東望，依舊暮雲深。"]'),
('4c17ba1e-1b22-4d5d-8e25-86213bb71983','紅文莧','韋驤','宋','宋诗','song-poetry','','[]','色若栖文雉，圓如插綉幢。',24,'全唐诗/poet.song.41000.json','["色若栖文雉，圓如插綉幢。", "春葩應有並，秋卉合無雙。"]'),
('80381064-b6da-4599-88ca-07d726e4fbf2','和董公肅十日菊二首  其一','韋驤','宋','宋诗','song-poetry','','[]','自是重陽過，重陽菊不遲。',48,'全唐诗/poet.song.41000.json','["自是重陽過，重陽菊不遲。", "幽芳始經宿，羣好奈隨時。", "未减黄金蕊，何妨白玉巵。", "賞花非賞節，衰謝直爲期。"]'),
('20dae4dc-d284-48f1-9bff-9bf6ee9f7c07','和董公肅十日菊二首  其二','韋驤','宋','宋诗','song-poetry','','[]','昨日堕烏紗，遊懽等孟嘉。',48,'全唐诗/poet.song.41000.json','["昨日堕烏紗，遊懽等孟嘉。", "今晨舉青眼，獨自競黄花。", "香冷朝猶盛，人疏勢可嗟。", "明年又重九，何以面芳葩。"]'),
('f02d2cde-4d82-4faf-ba8a-54ecbdd96604','和苦吟二首  其一','韋驤','宋','宋诗','song-poetry','','[]','夫子吟何切，辭源瀉不枯。',48,'全唐诗/poet.song.41000.json','["夫子吟何切，辭源瀉不枯。", "秋山鑿寒玉，夜蚌抉明珠。", "感嘆通前古，風情滿五湖。", "只憂長寡和，白雪本高孤。"]'),
('65ed44db-b652-49a7-a607-60209f537969','和苦吟二首  其二','韋驤','宋','宋诗','song-poetry','','[]','驤也饒詩癖，才疏思每艱。',48,'全唐诗/poet.song.41000.json','["驤也饒詩癖，才疏思每艱。", "持毫欲臨紙，逐獸不知山。", "著意窮三百，唯時見一班。", "羨他唐老杜，氣格獨優閒。"]'),
('552f2ebd-73e0-4fde-89ec-41ea26d1aecb','廳前叢竹','韋驤','宋','宋诗','song-poetry','','[]','軟枝輕翠近簷垂，朝暮清風不失期。',32,'全唐诗/poet.song.41000.json','["軟枝輕翠近簷垂，朝暮清風不失期。", "明月滿庭無隱伏，夜深惟有此君知。"]'),
('eb765dc5-4352-4bdf-9934-9ae0fe097d9a','八月十四日夜月','韋驤','宋','宋诗','song-poetry','','[]','中秋垂一宿，延頸望金波。',48,'全唐诗/poet.song.41000.json','["中秋垂一宿，延頸望金波。", "素魄雖微缺，清光已覺多。", "圓來殊俯近，觀者尚蹉跎。", "明夕當如鑒，光華更幾何。"]'),
('24d0762b-593d-49db-b52a-4c6fd530bdd8','十五夜','韋驤','宋','宋诗','song-poetry','','[]','八月得中節，今宵秋又中。',48,'全唐诗/poet.song.41000.json','["八月得中節，今宵秋又中。", "由來金氣王，向盡月華充。", "翫與多方共，清非别夜同。", "明皇如未死，依舊惑蟾宫。"]'),
('1a69bdb8-a391-4da3-9f72-364d976ae05a','十六夜','韋驤','宋','宋诗','song-poetry','','[]','明月上天稽，中秋已過期。',48,'全唐诗/poet.song.41000.json','["明月上天稽，中秋已過期。", "十分初减處，萬目共憐時。", "不見昨宵盛，安知今夜衰。", "清光比他夕，猶勝滿如規。"]'),
('91ef38da-4e44-4118-8016-4e43babaff0d','詠螢','韋驤','宋','宋诗','song-poetry','','[]','詩作東山事已賒，宵行今復動誰嗟。',64,'全唐诗/poet.song.41000.json','["詩作東山事已賒，宵行今復動誰嗟。", "秋高黨類縱横出，月黑光芒斗頓加。", "風觸羣飛迸星火，水澄亂影漾金沙。", "區區曾有分輝客，晉室寒儒本姓車。"]'),
('9ad91e10-7364-4e35-9316-85b8b30dbf41','詠水','韋驤','宋','宋诗','song-poetry','','[]','澤物施工詎可名，涓涓以及大川成。',64,'全唐诗/poet.song.41000.json','["澤物施工詎可名，涓涓以及大川成。", "更逢卑處須流惠，有不平時即發聲。", "傾側祇将盈上凖，毫釐寧向外邊明。", "宣尼所取尤深遠，蓋取原充晝夜行。"]'),
('56e8a19e-f7c2-46ee-ab8b-579c4c55bf83','詠竹','韋驤','宋','宋诗','song-poetry','','[]','此君堅直本天然，豈學妖花艷主軒。',64,'全唐诗/poet.song.41000.json','["此君堅直本天然，豈學妖花艷主軒。", "筠带輕霜凝不落，幹磋圓玉碧無痕。", "非春長自繁枝葉，有地終須大本根。", "誰爲裁音薦清廟，定勝嘉木就犧樽。"]'),
('6d34a85a-e50b-4a2d-8824-989240a7ebf6','殘燈','韋驤','宋','宋诗','song-poetry','','[]','寒窗夜将艾，一點映蕭蕭。',48,'全唐诗/poet.song.41000.json','["寒窗夜将艾，一點映蕭蕭。", "燄向雞聲短，花随蝶夢凋。", "何須惜餘照，且喜近清朝。", "老婢不知此，荆釵屢屢挑。"]'),
('067c12d3-3530-425a-9889-06088c590043','謝董都官見寄','韋驤','宋','宋诗','song-poetry','','[]','區區賤質恥無聞，深荷明公曲愛存。',64,'全唐诗/poet.song.41000.json','["區區賤質恥無聞，深荷明公曲愛存。", "談席方忻接餘論，詩筒多謝遺佳言。", "辭源浩若江河瀉，文意過于布帛温。", "聽獄平反願承教，異時安敢議高門。"]'),
('0f0b0175-a973-45f4-9061-ce864eff0974','再貺詩復以前韻答之','韋驤','宋','宋诗','song-poetry','','[]','媿将鄙句報多聞，操紙安能蔽所存。',64,'全唐诗/poet.song.41000.json','["媿将鄙句報多聞，操紙安能蔽所存。", "硯墨未乾憂見罪，牋封還枉却酬言。", "長吟不覺手之舞，熟覽方知即也温。", "長者如興起予嘆，攝齊時願一登門。"]'),
('afa4aaa0-9a3a-4515-bb66-223e0c469b76','詠草','韋驤','宋','宋诗','song-poetry','','[]','萋萋廣原上，苒苒曲江湄。',48,'全唐诗/poet.song.41000.json','["萋萋廣原上，苒苒曲江湄。", "人跡不到處，春風似有期。", "句牽碧成陣，蒙蔽密如絲。", "待看野火烈，百蟲悲不悲。"]'),
('1dcf33fe-f867-40c7-8311-adb2139fdfc5','聞新雁','韋驤','宋','宋诗','song-poetry','','[]','夜堂危坐氣凄清，秋月光中新雁鳴。',64,'全唐诗/poet.song.41000.json','["夜堂危坐氣凄清，秋月光中新雁鳴。", "出塞不知多少路，穿雲纔聽兩三聲。", "歸時行列應如舊，來處風烟合認程。", "今夕沙汀好栖息，弋人詭計未能成。"]'),
('1c57b6d2-1e89-4de9-9a19-a5242a17aee2','仙掌峰','韋驤','宋','宋诗','song-poetry','','[]','巨靈前事杳難評，融結皆由造化成。',64,'全唐诗/poet.song.41000.json','["巨靈前事杳難評，融結皆由造化成。", "山歷古今常似掌，地當西北是扶傾。", "擘開太華幾千仞，指出飛鵬數萬程。", "歲旱定須先展效，力推雲雨救蒼生。"]'),
('de14aa6c-fa30-4435-b0e3-d77554c19b50','翦刀','韋驤','宋','宋诗','song-poetry','','[]','一身分二首，一首一銛鋩。',48,'全唐诗/poet.song.41000.json','["一身分二首，一首一銛鋩。", "遇物無微細，交鋒即斷傷。", "翦齊繄汝鋭，任用在君詳。", "大抵便柔脆，毋令過所長。"]'),
('7e0fbf8a-0107-457c-9bc7-b680893e7ce2','秋懷','韋驤','宋','宋诗','song-poetry','','[]','西風瀟灑作輕寒，黄葉樓中強解顔。',64,'全唐诗/poet.song.41000.json','["西風瀟灑作輕寒，黄葉樓中強解顔。", "畫角幾聲催晚照，亂雲何處是家山。", "宦途有立寧辭賤，局事無多豈厭閒。", "濁酒一杯休萬慮，長林烟暝暮鴉還。"]'),
('669c764b-e23d-4633-ac1b-9c8f05d60548','汴河','韋驤','宋','宋诗','song-poetry','','[]','通濟名渠古到今，當時疏導用功深。',64,'全唐诗/poet.song.41000.json','["通濟名渠古到今，當時疏導用功深。", "源高直接黄河瀉，流去遥歸碧海潯。", "護冢尚存芳草亂，隋舟安在綠楊陰。", "年年漕運無窮已，誰謂東南力不任。"]'),
('0497086f-93c2-466e-836a-23a85024ba55','黄河','韋驤','宋','宋诗','song-poetry','','[]','四載收功故道循，滔滔千古勢無垠。',64,'全唐诗/poet.song.41000.json','["四載收功故道循，滔滔千古勢無垠。", "流知江海涵容大，静覺乾坤覆燾均。", "未必崑崙獨傾注，祇安河漢共濆淪。", "如何騎得鯨魚背，直到天涯一問津。"]'),
('b4089d73-b54a-4360-8eb9-29af9454d72d','和聶充甫晨霜','韋驤','宋','宋诗','song-poetry','','[]','勿異繁霜早，園林已具腓。',48,'全唐诗/poet.song.41000.json','["勿異繁霜早，園林已具腓。", "隕時兼夜氣，凝處張寒威。", "月落初分白，陽升還盡晞。", "稜稜不終日，由此識天機。"]'),
('2e5334b4-0529-4033-84df-c3e7ac973d6e','東庵院','韋驤','宋','宋诗','song-poetry','','[]','聞說東庵在廬岳，浮屠百數獨無雙。',64,'全唐诗/poet.song.41000.json','["聞說東庵在廬岳，浮屠百數獨無雙。", "堂陰翠色連危嶂，門外清光挹大江。", "怪石巑岏坐龍虎，老松突兀樹旌幢。", "何時得對幽佳趣，擺脱塵襟酒滿缸。"]'),
('39c6f3f3-9465-41db-a48f-c4e4f4d72bd1','次韻和聶充甫冬曉初起','韋驤','宋','宋诗','song-poetry','','[]','霜月孤光在，寒雞一唱催。',48,'全唐诗/poet.song.41000.json','["霜月孤光在，寒雞一唱催。", "晨興衣未煖，夜誦帙猶開。", "鄉夢還千里，愁腸過九回。", "浚明何所立，緹室又飛灰。"]'),
('b72e36a0-e1ff-4b8a-ac9c-b219e223c79b','習曹何君屢有引年之語而未暇請今兹官滿解去驤作詩言其榮以壯其志惟僚友不異幸同辭以助之','韋驤','宋','宋诗','song-poetry','','[]','容容貴富此胡爲，可止能歸即可師。',64,'全唐诗/poet.song.41000.json','["容容貴富此胡爲，可止能歸即可師。", "家住嶺南謀退老，官休江左正其時。", "相從祿仕材諸子，得謝鄉閭似者誰。", "贏取林泉長日月，爲君潛計樂無涯。"]'),
('e5d1d680-ae7c-4be1-a42f-399658824071','司馬南樓納凉','韋驤','宋','宋诗','song-poetry','','[]','溪外層樓入翠微，登臨炎酷杳如遺。',64,'全唐诗/poet.song.41000.json','["溪外層樓入翠微，登臨炎酷杳如遺。", "千山相掩雲爭出，萬浪欲光風倒吹。", "擺脱塵紛得危坐，牢籠清曠就新詩。", "短衣野老遥相目，應怪官閒亦有時。"]'),
('7464d3bf-3312-4b27-96e5-da3f66ff0889','賈中甫送慶甫弟來尉永興久之告歸僕多其來而重其去乃爲詩以送之','韋驤','宋','宋诗','song-poetry','','[]','仲弟安居後，先廬憶故鄉。',48,'全唐诗/poet.song.41000.json','["仲弟安居後，先廬憶故鄉。", "暌離何足惜，氣義已爲光。", "遠址他年見，歸心千里長。", "西風吹别酒，爲賦脊令章。"]'),
('b3b2a217-8b85-4349-aca7-e95a3a6a35a6','賈慶甫以局事乘小船犯風波感其危而爲詩且以相示僕亦於舟字韻和呈其卒章蓋言有俟以慰賢勞之嘆也','韋驤','宋','宋诗','song-poetry','','[]','萬頃風波一葦浮，髮巢猶穩羨蒙鳩。',64,'全唐诗/poet.song.41000.json','["萬頃風波一葦浮，髮巢猶穩羨蒙鳩。", "唯余忘膽驚其說，况子輕身坐此舟。", "軻戒立牆雖孝節，尊曾驅阪本忠謀。", "小官辛苦宜無念，自古高賢達以憂。"]'),
('6cc59ae1-654b-4b6f-9f41-f8a395cc1568','公閒念詩社之廢寄陶賈二同僚一首','韋驤','宋','宋诗','song-poetry','','[]','地僻少将迎，溪山一概清。',48,'全唐诗/poet.song.41000.json','["地僻少将迎，溪山一概清。", "秋深孟嘉宅，歲古闔閭城。", "吏隱全輸我，詩豪半屬卿。", "社壇何冷落，濡筆請尋盟。"]'),
('840e8e61-6875-4e30-bc04-97639ed3e734','雨後','韋驤','宋','宋诗','song-poetry','','[]','西風吹雨過江城，林館秋濃氣轉清。',64,'全唐诗/poet.song.41000.json','["西風吹雨過江城，林館秋濃氣轉清。", "掃葉堆枯階半沒，步畦經潤履無聲。", "拒霜欲蕊扶疏翠，暮雀争栖格磔鳴。", "賤局安閒出天幸，未須多口論功名。"]'),
('eebe8833-f18d-4f06-a7c5-0bcdfffc267b','見省符知有代官一首','韋驤','宋','宋诗','song-poetry','','[]','寸祿固拘攣，區區頓豁然。',48,'全唐诗/poet.song.41000.json','["寸祿固拘攣，區區頓豁然。", "比來符檄至，代者姓名傳。", "公事多閒日，歸期不及年。", "喜情通夢寐，累夕拜親前。"]'),
('2b5a956e-87ea-4468-8105-0a4e376f9f59','和陶掾見寄','韋驤','宋','宋诗','song-poetry','','[]','寂默公閒外，新詩忽見撞。',48,'全唐诗/poet.song.41000.json','["寂默公閒外，新詩忽見撞。", "比來知燕坐，時得近秋窗。", "臨弈誇能勝，持杯學詐降。", "相逢怯此病，繼晷請然釭。"]'),
('95b45a46-8c50-494a-be7b-fb7ac3267304','待拒霜開一首','韋驤','宋','宋诗','song-poetry','','[]','予憐拒霜好，獨立冠彫窮。',192,'全唐诗/poet.song.41000.json','["予憐拒霜好，獨立冠彫窮。", "故臘新移至，今年曲愛隆。", "栽培曾倩圃，灌溉每呼僮。", "覆護障炎日，枝撐禦暴風。", "欲高殱隘葉，待盛拓芳叢。", "不取蒿萊蔽，那妨雨露濛。", "翠行疏密等，微徑往來通。", "恐折頻敺雀，憂衰屢滅蟲。", "清秋方淡薄，碧蕊已玲瓏。", "占表如争勝，藏身若養蒙。", "綠幢擎蓶扈，圓玉琢青葱。", "美操寒中辨，丹心日已充。", "不甘爲菊後，漸見出籬東。", "雖本生成力，寧非養治功。", "從容延晚節，次第待輕紅。", "肯學楊花雪，悠悠負主翁。"]'),
('07283d1c-6fb8-493f-aa69-b13f11b43758','陶掾書齋小飲','韋驤','宋','宋诗','song-poetry','','[]','學非焉用贅多多，養浩當須繼孟軻。',64,'全唐诗/poet.song.41000.json','["學非焉用贅多多，養浩當須繼孟軻。", "把酒相懽外紛擾，吟詩大句破妖魔。", "坐中誰作向隅泣，天下今無扣角歌。", "圭紱巍巍君勿羨，安知此樂不如他。"]'),
('4a24f89b-0b03-410e-b96b-8e852ade3680','秋日即事呈同僚','韋驤','宋','宋诗','song-poetry','','[]','瀟灑臨霜夕，清居守決曹。',288,'全唐诗/poet.song.41000.json','["瀟灑臨霜夕，清居守決曹。", "嚴城吹角罷，隔壠聽猿號。", "警卒持更切，呼囚報鑰牢。", "訟庭澄一水，塵事戢千毛。", "簷閴蚊雷絕，池虛蛙吹逃。", "逍遥静襟慮，抖擻敞袛裯。", "樹木彫零盡，星辰氣燄豪。", "月微椶影薄，風急雁聲高。", "憶昔随羣學，當時髧二髦。", "讀書圖皦皦，感古動忉忉。", "意趣青雲近，煇光白玉韜。", "百錢寧問卜，一釣冀連鼇。", "直諒謀相與，回邪欲盡鏖。", "自期非幹蠱，幸遇豈屯膏。", "翻媿彫文陋，難逢異数褒。", "葳蕤從末宦，淟涊著青袍。", "斂翅鷹棲臂，垂頭驥伏槽。", "安能枉尋尺，猶得飽藜蒿。", "但恃心如砥，那矜目察毫。", "窮通任甄治，險惡遠波濤。", "養浩雖潛孟，折腰誠愧陶。", "常咍強蛇足，敢嘆抑牛刀。", "衮衮途泥裏，悠悠日月慆。", "居然成俗態，何足謂賢勞。"]'),
('b5d9a022-4a65-468d-b129-43e1f7c34df1','宣赦回馬上口占','韋驤','宋','宋诗','song-poetry','','[]','黄紙恩書下紫宸，豈惟羣罪許從新。',32,'全唐诗/poet.song.41000.json','["黄紙恩書下紫宸，豈惟羣罪許從新。", "其間多少寛民意，四海承宣有幾人。"]'),
('d0abac33-31f3-489e-a74d-40af3372199b','十月暮登延壽閣','韋驤','宋','宋诗','song-poetry','','[]','湖水漸如带，扁舟渡亦艱。',48,'全唐诗/poet.song.41000.json','["湖水漸如带，扁舟渡亦艱。", "山空翠屏淺，荻老雪花殘。", "立馬寒烟際，登樓靄暮間。", "嚴闉促回轡，吏隱樂終慳。"]'),
('0170a72a-0ee1-4179-b58d-550c73ddc285','曉坐','韋驤','宋','宋诗','song-poetry','','[]','曉鼓韸韸日欲升，寒廳危坐對前楹。',64,'全唐诗/poet.song.41000.json','["曉鼓韸韸日欲升，寒廳危坐對前楹。", "霜威著樹瓊瑤色，雁陣横空風雨聲。", "自喜優游服王事，那嗟寂寞滯山城。", "栖栖院吏公衙退，却就書帷萬慮清。"]'),
('062e8acc-c3e8-405b-97d3-fb362b1d5e36','夜射通叔虞曹圃','韋驤','宋','宋诗','song-poetry','','[]','束葦然膏百炬紅，夜堂寒氣變春融。',64,'全唐诗/poet.song.41000.json','["束葦然膏百炬紅，夜堂寒氣變春融。", "流星半沒飛金鏃，缺月初圓引角弓。", "賞罰明如棘門上，和融遠過澤宫中。", "平心不爲長眉醉，慷慨真成壯士風。"]'),
('e86c0b10-c6d4-4b85-974c-c6111fc5d0fb','辨詐','韋驤','宋','宋诗','song-poetry','','[]','遠俗無知祗慕恩，鑿山踰嶺獻麒麟。',32,'全唐诗/poet.song.41000.json','["遠俗無知祗慕恩，鑿山踰嶺獻麒麟。", "諸儒不用區區辨，多少難明僞似真。"]'),
('7d4396ef-e03b-42b6-b51c-4bfee1c82e62','田叔','韋驤','宋','宋诗','song-poetry','','[]','冒死隨敖衣赭衣，當時蹤跡已幾希。',32,'全唐诗/poet.song.41000.json','["冒死隨敖衣赭衣，當時蹤跡已幾希。", "忠哉相魯扶君過，不使民情向我歸。"]'),
('e2ee2b21-f13d-4590-996d-e5c8a90c3417','感事','韋驤','宋','宋诗','song-poetry','','[]','治體清明已久成，世途欹側未全平。',64,'全唐诗/poet.song.41000.json','["治體清明已久成，世途欹側未全平。", "憸人仗勢千鈞重，直士無媒一縷輕。", "忍視鑿墉高外觀，更嗟畫餅竊虛名。", "山林豈是多扃鐍，自爲區區志欲行。"]'),
('ec7eb8b6-4512-411c-8872-086e50ea97c1','和魯成之兄弟見謝','韋驤','宋','宋诗','song-poetry','','[]','新文來復數，舊觀頓然還。',48,'全唐诗/poet.song.41000.json','["新文來復數，舊觀頓然還。", "願助羣鋒鋭，那慚砥石頑。", "辭豪雖欲抑，理屬不容刪。", "廢懶幡多媿，衰遲近學山。"]'),
('2ccb5f97-9000-480b-9e25-ac7006b15d83','迎親來畢幼妹之嫁久雨稽阻思望而作一首','韋驤','宋','宋诗','song-poetry','','[]','江南二月尚春寒，千里安輿冒險艱。',64,'全唐诗/poet.song.41000.json','["江南二月尚春寒，千里安輿冒險艱。", "遠想長岐同積雨，不知今日過何山。", "出迎應喜諸孫慧，奉壽須驚兩鬢班。", "從此莫輕離膝下，茹蔬堅乞侍高閒。"]'),
('95e699dc-2688-4608-b8d0-6a7dec334d2e','董公肅都官被命倅南海以當分符之寄南歸道中貺書因以詩爲寄一首','韋驤','宋','宋诗','song-poetry','','[]','痟中邂逅飲寒冰，未及公書慰鄙情。',64,'全唐诗/poet.song.41000.json','["痟中邂逅飲寒冰，未及公書慰鄙情。", "脂轄近離雙鳳闕，拜恩新倅五羊城。", "旌旗曉過山川秀，笳鼓春歸里落榮。", "詩社荒凉懷舊将，不知何日可尋盟。"]'),
('dd1b8f81-3628-44ee-bb8a-f8a957679457','答魯成之兄弟以詩惠牡丹','韋驤','宋','宋诗','song-poetry','','[]','品冠名園蓋物尤，主人分惠若爲酬。',64,'全唐诗/poet.song.41000.json','["品冠名園蓋物尤，主人分惠若爲酬。", "摘兼殘雨妖嬈甚，将以新詩意義優。", "幾樹天香盈翠籠，一欄春色想鴻溝。", "滿頭恣插成狂醉，爲恐花神恨暗投。"]'),
('e332fa4c-5a6c-4d39-91ec-946fd0339c6f','聞詔寄魯成之兄弟','韋驤','宋','宋诗','song-poetry','','[]','天子需賢慮逸遺，詔書間歲出丹墀。',64,'全唐诗/poet.song.41000.json','["天子需賢慮逸遺，詔書間歲出丹墀。", "嗟予衮衮成無狀，羨子飄飄正得時。", "能將必先期敵勝，善占當自照心疑。", "相将岐路青雲近，莫厭蕭條更下帷。"]'),
('6099f813-768b-4844-8cc5-d003f5e697e6','代官未至泊舟頒條門獨宿署中','韋驤','宋','宋诗','song-poetry','','[]','獨宿官居静，維舟古岸斜。',48,'全唐诗/poet.song.41000.json','["獨宿官居静，維舟古岸斜。", "塵埃猶吏局，烟水寄吾家。", "鄉夢連宵動，歸心計日差。", "向晨望星斗，曉櫓趣嘔啞。"]'),
('77bcb87c-1166-4e22-bfbb-1dbd8be44bc4','南湖晚霽','韋驤','宋','宋诗','song-poetry','','[]','雨脚隨雲斷，湖光带日還。',48,'全唐诗/poet.song.41000.json','["雨脚隨雲斷，湖光带日還。", "微虹初照水，餘霧尚懷山。", "理網漁歌喜，支篷孤棹閒。", "蕭然安艤泊，盡室畫圖間。"]'),
('f93208a0-b05d-4b44-900e-97390ae91057','過白公堂','韋驤','宋','宋诗','song-poetry','','[]','四百餘年兵火後，至今遺構葺如新。',32,'全唐诗/poet.song.41000.json','["四百餘年兵火後，至今遺構葺如新。", "謫官豈是多恩惠，誰謂文章不動人。"]'),
('027d71db-9184-4dcc-ae83-756f03a8687e','庾樓','韋驤','宋','宋诗','song-poetry','','[]','仗節當年分國寄，危樓千古壓江潯。',32,'全唐诗/poet.song.41000.json','["仗節當年分國寄，危樓千古壓江潯。", "山川風月宜如舊，疏曠還同庾老心。"]'),
('4deebccc-478f-4375-8441-d6d2470ee4bf','狄公祠','韋驤','宋','宋诗','song-poetry','','[]','數間冷屋蒼山觜，忠孝功名萬載師。',32,'全唐诗/poet.song.41000.json','["數間冷屋蒼山觜，忠孝功名萬載師。", "曲俗佞神惟畏禍，停舟祗謁小姑祠。"]'),
('e516612d-a306-424f-b010-1b088066ab5d','陶令祠','韋驤','宋','宋诗','song-poetry','','[]','莫笑先生猶假醉，先生于道未宜輕。',32,'全唐诗/poet.song.41000.json','["莫笑先生猶假醉，先生于道未宜輕。", "門前五柳今何在，唯有江流百丈清。"]'),
('cbf62aa0-3191-41e0-be71-cbc04893c36a','舍綺霞閣五首呈石丈職方 綺霞閣','韋驤','宋','宋诗','song-poetry','','[]','美構冠名城，區區喜與登。',48,'全唐诗/poet.song.41000.json','["美構冠名城，區區喜與登。", "澄泉朝竊鑒，爽氣夜相陵。", "物象方傾蓋，襟懷過飲冰。", "蒼葭此何幸，玉樹是依憑。"]'),
('24e764fb-c341-427e-8ed0-542684f73a42','舍綺霞閣五首呈石丈職方 水中亭','韋驤','宋','宋诗','song-poetry','','[]','回環水面碧于藍，曉夕清虚萬象涵。',32,'全唐诗/poet.song.41000.json','["回環水面碧于藍，曉夕清虚萬象涵。", "佳趣不容爲獨攬，史君横彴在亭南。"]'),
('1d89da41-ac13-467a-b178-4fdb2012cfd3','舍綺霞閣五首呈石丈職方 枯荷','韋驤','宋','宋诗','song-poetry','','[]','綠萍漂合舊根斜，獨恨來遲過了花。',32,'全唐诗/poet.song.41000.json','["綠萍漂合舊根斜，獨恨來遲過了花。", "不見離披照秋水，盡依名閣作餘霞。"]'),
('703fa293-28a0-46e9-8a5d-135c1b11a94f','舍綺霞閣五首呈石丈職方 蕉逕','韋驤','宋','宋诗','song-poetry','','[]','兩行對植接低圯，弱質毋嫌費壅治。',32,'全唐诗/poet.song.41000.json','["兩行對植接低圯，弱質毋嫌費壅治。", "十月綠陰猶滿逕，也勝蒲柳望秋衰。"]'),
('32efd1eb-05fe-4e6b-9fb8-4333ed890f81','舍綺霞閣五首呈石丈職方 小山','韋驤','宋','宋诗','song-poetry','','[]','嵌空尋尺立池津，池北池南孰可鄰。',32,'全唐诗/poet.song.41000.json','["嵌空尋尺立池津，池北池南孰可鄰。", "草樹自羞還自笑，凋榮一節任天真。"]'),
('edc4dec8-39da-45e0-93b1-19c81d76bd6d','和石丈職方長春花','韋驤','宋','宋诗','song-poetry','','[]','舄奕紅芳續，皇皇若競辰。',72,'全唐诗/poet.song.41000.json','["舄奕紅芳續，皇皇若競辰。", "盡居羣卉右，獨得四時春。", "孤節寒方見，滂葩日又新。", "笑梅侵臘候，欺菊冒蕭晨。", "值賦知均被，生成此特頻。", "咨咨偏惠意，天聽杳難塵。"]'),
('d84b8159-db41-4eeb-b808-51c77f87f545','待令移寓趙氏園亭','韋驤','宋','宋诗','song-poetry','','[]','待次鄉閭計索然，故人亭館寓𨈊跧。',64,'全唐诗/poet.song.41000.json','["待次鄉閭計索然，故人亭館寓𨈊跧。", "折腰五斗羞彭澤，破屋數間如玉川。", "曉竹冒霜清節苦，夜禽啼月小聲圓。", "蕭條真趣非無賴，捽茹簞瓢素所便。"]'),
('56e05b80-6f96-4541-9932-8dcb64abf3d5','賀簡夫石丈罷令先期請老','韋驤','宋','宋诗','song-poetry','','[]','七十能歸世已稀，掛冠况在壯齡時。',64,'全唐诗/poet.song.41000.json','["七十能歸世已稀，掛冠况在壯齡時。", "休風遠過疏公上，清節未甘陶令卑。", "門枕白雲朝睡美，席函明月夜杯遲。", "區區膠祿寧無耳，漏盡鐘鳴合自思。"]'),
('79294dd8-96ef-492c-80d7-51d78a1793bd','遣興一絕','韋驤','宋','宋诗','song-poetry','','[]','睡思容易醒，輾轉衾裯單。',24,'全唐诗/poet.song.41000.json','["睡思容易醒，輾轉衾裯單。", "今宵聽風竹，始覺窗外寒。"]'),
('12d939d4-4627-4427-b3a7-b095b98133ed','得陳安道書知移邑名次','韋驤','宋','宋诗','song-poetry','','[]','安道枉書自東都，報我外移春可凖。',64,'全唐诗/poet.song.41000.json','["安道枉書自東都，報我外移春可凖。", "予方寂處藜藿空，蓄縮僅同枯壤蚓。", "聞之雖喜良自嗟，仕豈爲貧今頗近。", "男兒有志期必行，五斗折腰何足愍。"]'),
('3930e139-ea99-4e58-a18c-6ea4eb75b949','初睡','韋驤','宋','宋诗','song-poetry','','[]','凍雲卷盡月華清，寒氣稜稜夜轉生。',64,'全唐诗/poet.song.41000.json','["凍雲卷盡月華清，寒氣稜稜夜轉生。", "一卷古書齊萬慮，滿杯醇酎卧三更。", "附炎鄙態悲時薄，養僻孤蹤任俗評。", "曠逸最便朝睡美，鄰雞不用再三鳴。"]'),
('39634b10-2ca0-4b13-8a86-1348387982d5','憶富川四首  其一','韋驤','宋','宋诗','song-poetry','','[]','渴憶富川好，官居似隱潛。',48,'全唐诗/poet.song.41000.json','["渴憶富川好，官居似隱潛。", "江山慰情淡，魚稻養貧廉。", "旅傳無將送，狴牢絕滯淹。", "疏閒真自得，何恤遠炎炎。"]'),
('0f14c1d0-7536-4fb3-94e3-c63537239f1e','憶富川四首  其二','韋驤','宋','宋诗','song-poetry','','[]','渇憶富川好，孤城插翠屏。',48,'全唐诗/poet.song.41000.json','["渇憶富川好，孤城插翠屏。", "淳風在人物，真趣滿郊坰。", "野屋千間古，晴山四壁青。", "别來千鄙思，偃卧閲圖經。"]'),
('c1b761cd-ef6a-4c78-8ff2-17b0f9a26387','憶富川四首  其三','韋驤','宋','宋诗','song-poetry','','[]','渴憶富川好，優游度歲時。',48,'全唐诗/poet.song.41000.json','["渴憶富川好，優游度歲時。", "白雲藏治署，蒼竹對書帷。", "弈戰侵遺算，詩壇讓擁麾。", "還鄉固佳况，疇昔尚深思。"]'),
('47d2fe7b-e19b-470d-a828-dc479d930fc6','憶富川四首  其四','韋驤','宋','宋诗','song-poetry','','[]','渴憶富川好，官休欲放船。',48,'全唐诗/poet.song.41000.json','["渴憶富川好，官休欲放船。", "垂囊買村釀，擲餌得溪鮮。", "跡寄紛囂外，懷攄曠逸全。", "交游日相醉，屢以去期遷。"]'),
('b346b671-f456-459e-a2e7-1bcea76a45a4','陪胡公弈棋','韋驤','宋','宋诗','song-poetry','','[]','區區席末侍枯棋，臆計蒼黄膽欲飛。',64,'全唐诗/poet.song.41000.json','["區區席末侍枯棋，臆計蒼黄膽欲飛。", "制勝固難施小智，冥行多是觸沈機。", "狂謀殊愧千無得，鋭氣何勞十即圍。", "賤子衄歸深自慶，袛裯榮带老人輝。"]'),
('14f42bd8-2ba0-440b-aec3-af42b6287f3f','清明','韋驤','宋','宋诗','song-poetry','','[]','去歲清明富水濱，今年舊里遘芳辰。',64,'全唐诗/poet.song.41000.json','["去歲清明富水濱，今年舊里遘芳辰。", "風流蕭灑殊前日，花木依稀似故人。", "遊覽不宜辭爛熳，别離還復在逡巡。", "暫閒幸可頻吟醉，春色當于我輩親。"]'),
('7f14f74a-4118-4bd6-92ca-9db35c16dd42','阻雨','韋驤','宋','宋诗','song-poetry','','[]','清明未遠正春濃，澍雨無情苦見攻。',64,'全唐诗/poet.song.41000.json','["清明未遠正春濃，澍雨無情苦見攻。", "沽酒窮壚應减價，障泥豪錦若爲功。", "輪蹄寂寞湖山闇，桃杏彫疏臺榭空。", "唯有居閒足幽况，晏眠冷屋似山翁。"]'),
('1d87b6d2-e9a1-4adc-9b31-d0a50a2fe1cc','病目未愈','韋驤','宋','宋诗','song-poetry','','[]','病目私廬藥足治，茫然盈月尚多眵。',64,'全唐诗/poet.song.41000.json','["病目私廬藥足治，茫然盈月尚多眵。", "易平本遠風埃路，難愈應緣笋蕨時。", "花入書編飛樸樸，星攢簷隙轉纍纍。", "古今是否消深慮，視少唯便默以思。"]'),
('acbbbe95-01e9-4672-9382-94e8181e81bc','即事','韋驤','宋','宋诗','song-poetry','','[]','雲物半陰晴，春罍酒氣清。',48,'全唐诗/poet.song.41000.json','["雲物半陰晴，春罍酒氣清。", "花空葉自隘，梅重核初成。", "噱論無柔語，酣歌有壯聲。", "翠眉應見笑，先老擲風情。"]'),
('2fcba923-aba9-4cd7-845f-beac9f8b9025','杜鵑','韋驤','宋','宋诗','song-poetry','','[]','杜鵑叫林表，曉窗色初分。',24,'全唐诗/poet.song.41000.json','["杜鵑叫林表，曉窗色初分。", "却憶動鄉思，去年江外聞。"]'),
('691befb1-82d2-4b9c-bf89-9f8d8f60e375','周生哀辭','韋驤','宋','宋诗','song-poetry','','[]','所到固爲命，嗟君志不通。',48,'全唐诗/poet.song.41000.json','["所到固爲命，嗟君志不通。", "未施稽古效，遽遘及泉凶。", "玉毁垂成際，蘭摧共茂中。", "哀歌閉新壟，寂寞四山空。"]'),
('9cf221fc-7c9c-4af3-bba2-9ea0e6fb87e9','致政胡郎中生日','韋驤','宋','宋诗','song-poetry','','[]','未容廣受擅餘徽，遠嗣親榮二十期。',64,'全唐诗/poet.song.41000.json','["未容廣受擅餘徽，遠嗣親榮二十期。", "山嶽有神儲秀日，朝廷無事乞身時。", "挂車濯濯吳風厚，奉壽詵詵夏景遲。", "賤士葭莩敢爲獻，願光南國過期頤。"]'),
('7140135d-b25c-4c4b-befa-f32476c4e308','和簡夫遊南巖','韋驤','宋','宋诗','song-poetry','','[]','古寺因山半翠微，躋攀危蹬上雲扉。',64,'全唐诗/poet.song.41000.json','["古寺因山半翠微，躋攀危蹬上雲扉。", "祇應秀色隨秋吹，還似紅塵染客衣。", "子賤鳴絃方暇逸，淵明解綬已来歸。", "吾儕幸得陪清覽，相與優游養道肥。"]'),
('6aaceaaa-23ca-424d-922d-0182acfca279','又和見招鼓山遊','韋驤','宋','宋诗','song-poetry','','[]','氣凉天淡正時秋，野興山情猝未休。',32,'全唐诗/poet.song.41000.json','["氣凉天淡正時秋，野興山情猝未休。", "承召驩於鳬藻甚，但憂塵跡累清遊。"]'),
('d6635290-cc3a-4356-b0fc-bd809fffee48','又和閒居','韋驤','宋','宋诗','song-poetry','','[]','雨餘秋氣逼幽齋，時動新篇雅奏諧。',64,'全唐诗/poet.song.41000.json','["雨餘秋氣逼幽齋，時動新篇雅奏諧。", "不是溪山清耳目，自緣冰雪滿襟懷。", "榮名疣贅心都棄，世事毫毛力已排。", "唯有鑒湖風月近，賀公前跡可爲儕。"]'),
('e1cd199b-543f-4abe-82b7-2e8f66aa7938','和撲滿','韋驤','宋','宋诗','song-poetry','','[]','一等出鈞陶，唯便兒女曹。',48,'全唐诗/poet.song.41000.json','["一等出鈞陶，唯便兒女曹。", "誨慳材甚小，撲滿禍難逃。", "所忌同敧器，爲憂在錯刀。", "物微誠諭遠，招損警貪饕。"]'),
('3e9f9c14-46eb-4e48-b0aa-931f3d139bf0','送處道丈之台任民掾','韋驤','宋','宋诗','song-poetry','','[]','詞曹新調補，術學久堅完。',48,'全唐诗/poet.song.41000.json','["詞曹新調補，術學久堅完。", "有位欲行志，愛民無小官。", "脂車乘短日，山國動微寒。", "即聽佳聲滿，賢勞豈或嘆。"]'),
('6efd7577-8978-4c39-b621-e7abba7a6b08','簡夫丈昔遺老杜别集而驤以外集當之久而亡去近承多本因以詩請','韋驤','宋','宋诗','song-poetry','','[]','昔日交傳集外詩，規模雖記舊編遺。',32,'全唐诗/poet.song.41000.json','["昔日交傳集外詩，規模雖記舊編遺。", "近聞几格多兼副，可賜閒中一解頤。"]'),
('dcba071a-96c0-4026-a680-42d87545f64f','贈項子後處士','韋驤','宋','宋诗','song-poetry','','[]','介似於陵可謂清，老來志操益堅成。',64,'全唐诗/poet.song.41000.json','["介似於陵可謂清，老來志操益堅成。", "脅肩傅會羞衰俗，捽茹優游盡此生。", "祇以圖書養高性，不繇林藪市虚名。", "誰編野史防遺逸，當爲先生作獨行。"]'),
('ca86f402-98a4-4e7d-b1e8-68ecf181d900','去年今日','韋驤','宋','宋诗','song-poetry','','[]','去年今日到宣州，舟倚昭亭晚雨收。',64,'全唐诗/poet.song.41000.json','["去年今日到宣州，舟倚昭亭晚雨收。", "鴨脚飣盤隨土物，蟹螯将酒揜珍羞。", "溪間雁集菰蒲老，田外人歌𥝧稏稠。", "此際剡遊還憶舊，閒中情味兩悠悠。"]'),
('c4d352bb-1bbe-41ba-b61a-1546184b1d23','憶江上','韋驤','宋','宋诗','song-poetry','','[]','故歲官還勢亦勤，飄然單舸下長津。',64,'全唐诗/poet.song.41000.json','["故歲官還勢亦勤，飄然單舸下長津。", "風江無定收帆早，夜浦多虞撃柝頻。", "俸輟稻粱雖怕之，值輕魚蟹不嫌貧。", "蒼波古木應如舊，惆悵經由又隔春。"]'),
('22a34ba0-459a-4874-96cc-6c44221635b8','千佛巖讀書寄內','韋驤','宋','宋诗','song-poetry','','[]','官期未迫暫閒身，斆學巖居及夜分。',64,'全唐诗/poet.song.41000.json','["官期未迫暫閒身，斆學巖居及夜分。", "霜落空山寒切骨，風號萬木響連雲。", "有民勿謂書休讀，無術當知政必棼。", "獨宿不辭應會我，功名富貴本辛勤。"]'),
('7ee1b9a4-8af3-4838-8675-302f7a2adfff','石夫人挽辭','韋驤','宋','宋诗','song-poetry','','[]','有子任清時，夫人新拂衣。',48,'全唐诗/poet.song.41000.json','["有子任清時，夫人新拂衣。", "人生到此樂，天數奈相違。", "壼肅風規在，匳閒粉澤微。", "雲愁寒壟暮，何處是魂歸。"]'),
('bb56a199-04cd-4f9d-80c7-9642ca47551b','石經老挽辭','韋驤','宋','宋诗','song-poetry','','[]','已矣九泉歸，嗟君值短期。',48,'全唐诗/poet.song.41000.json','["已矣九泉歸，嗟君值短期。", "胸襟遺草在，孝友闔門悲。", "學謝生前用，名多沒後知。", "幽冥當自慰，造物本無私。"]'),
('e779f49e-e678-4b70-9773-e57290d988c1','詠唐史 李衛公','韋驤','宋','宋诗','song-poetry','','[]','能作膏肓遺蕭輔，更於西北振威雄。',32,'全唐诗/poet.song.41000.json','["能作膏肓遺蕭輔，更於西北振威雄。", "若非明主矜羸老，幾向高麗棄舊功。"]'),
('53fa4103-d3ee-4c2d-8d7b-096e104172eb','詠唐史 李英公','韋驤','宋','宋诗','song-poetry','','[]','威加突厥勝長城，藥賜鬚灰感聖情。',32,'全唐诗/poet.song.41000.json','["威加突厥勝長城，藥賜鬚灰感聖情。", "垂沒訓言非不慮，奈何墳土竟遭平。"]'),
('a8a4c41a-bec3-44e4-b475-3609264cfca4','詠唐史 尹思正','韋驤','宋','宋诗','song-poetry','','[]','執筆威踰知一杖，忤權活得月将身。',32,'全唐诗/poet.song.41000.json','["執筆威踰知一杖，忤權活得月将身。", "位終八座非爲幸，埋戟相符豈不神。"]'),
('734f8862-5ffa-4f66-b650-1478f5e077e5','詠唐史 李朝隱','韋驤','宋','宋诗','song-poetry','','[]','拽宦鞭奴蔑貴權，當時風骨愯衣冠。',32,'全唐诗/poet.song.41000.json','["拽宦鞭奴蔑貴權，當時風骨愯衣冠。", "及爲御史聲名减，豈是官高便欲安。"]'),
('c2cb719a-1c78-4bbb-9ced-e2217de0cf8d','詠唐史 張中令','韋驤','宋','宋诗','song-poetry','','[]','金鏡文高壓萬珍，開元寵遇號知人。',32,'全唐诗/poet.song.41000.json','["金鏡文高壓萬珍，開元寵遇號知人。", "范陽奏日言如用，安得西蒙蜀道塵。"]'),
('8d855918-bc4e-44a4-8c7d-6ab454d5efde','詠唐史 李適之','韋驤','宋','宋诗','song-poetry','','[]','礦金言率遇參商，罷相還歌樂聖章。',32,'全唐诗/poet.song.41000.json','["礦金言率遇參商，罷相還歌樂聖章。", "怖死宜春中姦賊，令人扼腕痛其亡。"]'),
('b079863a-d8f7-4f20-949b-3cfd4b310706','詠唐史 二閻','韋驤','宋','宋诗','song-poetry','','[]','八座蟬聯屬弟兄，當年門地足輝榮。',32,'全唐诗/poet.song.41000.json','["八座蟬聯屬弟兄，當年門地足輝榮。", "可嗟不富經綸業，唯著丹青制造名。"]'),
('9d3083f1-82c6-48a4-add5-8db7b270107c','詠唐史 蘇世長','韋驤','宋','宋诗','song-poetry','','[]','披香殿上嘆隋君，校獵營閒勸十旬。',32,'全唐诗/poet.song.41000.json','["披香殿上嘆隋君，校獵營閒勸十旬。", "莫謂口忠心則詐，如何膠祿不言人。"]'),
('b6356d55-d99a-482b-b3b3-9e4586e4b005','詠唐史 劉知幾','韋驤','宋','宋诗','song-poetry','','[]','五說三長歷歷陳，堅辭史任斥因循。',32,'全唐诗/poet.song.41000.json','["五說三長歷歷陳，堅辭史任斥因循。", "若教直筆專歸手，褒貶應能慰後人。"]'),
('89a49e96-ee17-45f7-9d40-1c3ce7f4fc05','詠唐史 盧懷慎','韋驤','宋','宋诗','song-poetry','','[]','言極公忠器業清，死猶勤懇薦時英。',32,'全唐诗/poet.song.41000.json','["言極公忠器業清，死猶勤懇薦時英。", "賢哉度己推姚相，不幸幡成伴食名。"]'),
('f5a407da-5fcb-4652-9deb-e3c66ece7b5a','詠唐史 李林甫','韋驤','宋','宋诗','song-poetry','','[]','國忠禍釁根芽日，此賊傾唐勢已先。',32,'全唐诗/poet.song.41000.json','["國忠禍釁根芽日，此賊傾唐勢已先。", "搆陷名臣冤且衆，天乎何意與終全。"]'),
('4b4e365d-0cd0-43cb-9f8f-7200055d5cae','詠唐史 楊國忠','韋驤','宋','宋诗','song-poetry','','[]','權由寵盛危宗社，天子傾心日自如。',32,'全唐诗/poet.song.41000.json','["權由寵盛危宗社，天子傾心日自如。", "十萬北來猶未悟，潼關尚聽促哥舒。"]'),
('1ecc8bc1-2580-4cea-8fb6-df351303c682','詠唐史 王珪','韋驤','宋','宋诗','song-poetry','','[]','斥姬援祖沃君心，貞觀箴規器獨深。',32,'全唐诗/poet.song.41000.json','["斥姬援祖沃君心，貞觀箴規器獨深。", "私廟因循遭糾刻，可嗟疵玷在球琳。"]'),
('d5c053b2-0669-4042-90fb-5a8b4eccb475','詠唐史 戴胄','韋驤','宋','宋诗','song-poetry','','[]','持平遠繼張廷尉，獻議嘗班魏鄭公。',32,'全唐诗/poet.song.41000.json','["持平遠繼張廷尉，獻議嘗班魏鄭公。", "誰謂尚書無學術，沒身何媿謚爲忠。"]'),
('653a8afc-3dd4-4bb8-87fb-c6e104604bc5','詠唐史 戴至德','韋驤','宋','宋诗','song-poetry','','[]','神翰飛英紀至賢，謂如舟楫濟洪源。',32,'全唐诗/poet.song.41000.json','["神翰飛英紀至賢，謂如舟楫濟洪源。", "偷名豈學劉仁軌，專向朝堂賣主恩。"]'),
('f14fc515-61a3-4735-81c3-8c7e6b0cd59e','詠唐史 魏鄭公','韋驤','宋','宋诗','song-poetry','','[]','東宫嘗吠非其主，貞觀終高獻納臣。',32,'全唐诗/poet.song.41000.json','["東宫嘗吠非其主，貞觀終高獻納臣。", "不獨齊桓忘射带，太宗當日最知人。"]'),
('5a602307-0f85-4abc-91f4-0f730a438196','詠唐史 虞世南','韋驤','宋','宋诗','song-poetry','','[]','太宗寵異號名臣，五絕當年賜目新。',32,'全唐诗/poet.song.41000.json','["太宗寵異號名臣，五絕當年賜目新。", "亡也重嗟文物去，石渠東觀謂無人。"]'),
('822f0928-eba2-4bf9-b2de-55811285be77','詠唐史 韋見素','韋驤','宋','宋诗','song-poetry','','[]','入相年餘值狂寇，獨隨車駕豈非忠。',32,'全唐诗/poet.song.41000.json','["入相年餘值狂寇，獨隨車駕豈非忠。", "凶胡萌禍根荄遠，史筆如何罪及公。"]'),
('cdd51198-b4fd-4726-96c3-0708b97e00f1','詠唐史 契苾何力','韋驤','宋','宋诗','song-poetry','','[]','自稱烈士受唐恩，寧死延陀不屈身。',32,'全唐诗/poet.song.41000.json','["自稱烈士受唐恩，寧死延陀不屈身。", "莫陋将軍本蕃種，中朝似此幾何人。"]'),
('ea211eb4-2d0a-4579-8884-5d73df92849d','詠唐史 李光弼','韋驤','宋','宋诗','song-poetry','','[]','閫外分憂屢積勳，間言幾欲變深恩。',32,'全唐诗/poet.song.41000.json','["閫外分憂屢積勳，間言幾欲變深恩。", "十年三覲勞方面，榮耀雙旌並在門。"]'),
('c7d2782c-06dd-460b-a9fa-b7c8399a8ac0','詠唐史 鄧景山','韋驤','宋','宋诗','song-poetry','','[]','并門雄鎮軍權重，斂怨殘軀不足傷。',32,'全唐诗/poet.song.41000.json','["并門雄鎮軍權重，斂怨殘軀不足傷。", "偏将贖身由納馬，賤人貴畜自爲殃。"]'),
('8493f1ba-46cd-45e6-b207-51c1a764adcd','詠唐史 韋堅','韋驤','宋','宋诗','song-poetry','','[]','勿詫崔生得體歌，運潭聚斂一何多。',32,'全唐诗/poet.song.41000.json','["勿詫崔生得體歌，運潭聚斂一何多。", "術雖可鄙非其死，甚矣姦臣恣網羅。"]'),
('984eb6f4-4843-4e65-90bb-239da08f3027','詠唐史 房琯','韋驤','宋','宋诗','song-poetry','','[]','蜀途赴難忠雖固，車戰亡師咎已深。',32,'全唐诗/poet.song.41000.json','["蜀途赴難忠雖固，車戰亡師咎已深。", "天子未歸京未復，不知何暇有琴心。"]'),
('e9622b5a-884c-4eb8-b15e-6d59e594c2da','詠唐史 崔蕘','韋驤','宋','宋诗','song-poetry','','[]','大臣許國當由道，執政如何事佛淫。',32,'全唐诗/poet.song.41000.json','["大臣許國當由道，執政如何事佛淫。", "身附姦邪不知禍，却談報應感君心。"]'),
('aaa94951-8a5c-46bd-a64d-1bfe15c6a3b8','詠唐史 楊綰','韋驤','宋','宋诗','song-poetry','','[]','總政中書月未期，郭崔奢侈遽中移。',32,'全唐诗/poet.song.41000.json','["總政中書月未期，郭崔奢侈遽中移。", "代宗勿嘆天亡早，用相斯人已後時。"]'),
('cb937878-596a-4e99-96f9-9b0f665cbdd1','詠唐史 郭子儀','韋驤','宋','宋诗','song-poetry','','[]','凌烟閣上中興後，勳德光全屬令公。',32,'全唐诗/poet.song.41000.json','["凌烟閣上中興後，勳德光全屬令公。", "魚輩也知深用力，其如謙巽悟宸衷。"]'),
('3cd18aa8-50e9-48d0-85cc-c4134767b913','詠唐史 蕭復','韋驤','宋','宋诗','song-poetry','','[]','面排盧杞興言佞，背沮劉公受旨私。',32,'全唐诗/poet.song.41000.json','["面排盧杞興言佞，背沮劉公受旨私。", "真相不知知彼相，便容辭疾守閒司。"]'),
('ff4073f5-a72e-426f-a0f0-29e17926d9cd','詠唐史 柳渾','韋驤','宋','宋诗','song-poetry','','[]','刑寛毁玉回天怒，智料渝盟識虜情。',32,'全唐诗/poet.song.41000.json','["刑寛毁玉回天怒，智料渝盟識虜情。", "延賞見躋終不愠，陶陶誰似柳宜城。"]'),
('de846acb-4c47-42a8-b3ea-fd5b7ae2a118','詠唐史 李揆','韋驤','宋','宋诗','song-poetry','','[]','獻替初雖有可賢，忌能遭貶是誰愆。',32,'全唐诗/poet.song.41000.json','["獻替初雖有可賢，忌能遭貶是誰愆。", "獐頭鼠目言何易，重困江湖十五年。"]'),
('6fef65db-4c48-4f02-9f55-ecb20d1eca4b','憶雙栟櫚','韋驤','宋','宋诗','song-poetry','','[]','憶昔厚栽培，憐雙異衆材。',48,'全唐诗/poet.song.41000.json','["憶昔厚栽培，憐雙異衆材。", "青青江外色，往往夢中來。", "未得甘棠比，寧隨弱柳衰。", "春華攄勁質，冷淡爲誰開。"]'),
('af960e46-5466-40c7-b772-55aa834a8e65','送劉誠夫江陰獄掾','韋驤','宋','宋诗','song-poetry','','[]','學老才優底裏精，青衫今始掾江城。',64,'全唐诗/poet.song.41000.json','["學老才優底裏精，青衫今始掾江城。", "高門積德功須倍，三尺持平道可行。", "聽决即能誠吏俗，名聲安用勢公卿。", "相逢未幾還相去，贈别非言豈慰情。"]'),
('bc8d58fa-bd60-49b9-bb0f-0747b6b9c9c1','石龜','韋驤','宋','宋诗','song-poetry','','[]','磨琢成龜智不虛，天然體理盡難如。',64,'全唐诗/poet.song.41000.json','["磨琢成龜智不虛，天然體理盡難如。", "世珍未許論荆璞，神跡當曾負洛書。", "山澤秘奇西蜀遠，星辰分氣北方餘。", "堅完自得靈身計，安用區區免豫且。"]'),
('9a8a3b8f-6fb9-41e3-be9a-204d4dae5df1','縣齋即事','韋驤','宋','宋诗','song-poetry','','[]','作邑慚無術，懷民賴有年。',48,'全唐诗/poet.song.41000.json','["作邑慚無術，懷民賴有年。", "訟筒消不逞，賓席汰非賢。", "奉養庭闈穩，論求典冊全。", "誰言非吏隱，山水匝城堧。"]'),
('43e6ab2a-12cb-4b8d-b773-033325ccf6ba','喜德甫彦文至','韋驤','宋','宋诗','song-poetry','','[]','昏昏山雨鎖春暉，褊邑蕭條客至稀。',64,'全唐诗/poet.song.41000.json','["昏昏山雨鎖春暉，褊邑蕭條客至稀。", "憐子遠來求所益，愧予無術慰焉依。", "文章未易論高出，行誼當須及庶幾。", "幽閣羣書足游意，聖賢雖邈欲誰歸。"]'),
('d20fd759-0a33-434b-8c58-29bff13453c2','雨池荷花','韋驤','宋','宋诗','song-poetry','','[]','雲翳前山雨脚長，灑然清氣動蓮塘。',64,'全唐诗/poet.song.41000.json','["雲翳前山雨脚長，灑然清氣動蓮塘。", "花中潤色添來美，葉上繁聲過去忙。", "紅面渾羞泣珠淚，翠盤微重瀉瓊漿。", "蕭蕭古縣無公事，贏得澄神坐冷床。"]'),
('307fad29-12df-42be-b246-1d060aa4b6db','金華按覆回止普净','韋驤','宋','宋诗','song-poetry','','[]','雨止山路滑，肩輿進亦難。',48,'全唐诗/poet.song.41000.json','["雨止山路滑，肩輿進亦難。", "官拘當勉力，室處豈非安。", "淺澗流還急，鳴禽意自寛。", "來歸雖薄暮，古寺且盤桓。"]'),
('fcf526d6-85c3-4a9a-9942-544d48c43a92','登樓','韋驤','宋','宋诗','song-poetry','','[]','邑落皆山水，登樓遠目通。',48,'全唐诗/poet.song.41000.json','["邑落皆山水，登樓遠目通。", "從容民事外，游息聖經中。", "畫餅羞虚譽，持衡尚至公。", "此心難語俗，舉袂挹松風。"]'),
('febcd8d5-2333-40fa-be82-ac623513ba9b','離邑之衢按獄','韋驤','宋','宋诗','song-poetry','','[]','出野暴雨作，遲晴方戒行。',48,'全唐诗/poet.song.41000.json','["出野暴雨作，遲晴方戒行。", "溪山百里秀，氣象一番清。", "于役途雖遠，祛慮意自平。", "民田况交隸，足以慰予情。"]'),
('400ece89-b412-41fd-813d-83a7ad1c8b29','野塘白蓮','韋驤','宋','宋诗','song-poetry','','[]','路轉方塘口，塘蓮雲不如。',48,'全唐诗/poet.song.41000.json','["路轉方塘口，塘蓮雲不如。", "孤芳已難值，秀色况非餘。", "及鑒波平後，飄香雨過初。", "泥途憂濺污，頑鶩仗誰祛。"]'),
('59b70a0f-e2d0-486a-8a3e-6b8b228e4d3b','石龍','韋驤','宋','宋诗','song-poetry','','[]','隱隱蒼山壁，蜿蜒此蟄身。',48,'全唐诗/poet.song.41000.json','["隱隱蒼山壁，蜿蜒此蟄身。", "物生多有象，人附即爲神。", "頭角千年古，威靈一境伸。", "確然難以詰，立馬爲逡巡。"]'),
('f8b66a33-26cc-4ea5-949d-f78e09c7dd30','還邑遇雨','韋驤','宋','宋诗','song-poetry','','[]','一陣陰雲一雨來，驅除煩暑灑塵埃。',32,'全唐诗/poet.song.41000.json','["一陣陰雲一雨來，驅除煩暑灑塵埃。", "山川固不爲迎合，豈是先知地主迴。"]'),
('2b0ff740-59aa-42dd-8003-e2e9e17fd49b','聞國哀','韋驤','宋','宋诗','song-poetry','','[]','欲及乾元節，登遐詔忽翻。',48,'全唐诗/poet.song.41000.json','["欲及乾元節，登遐詔忽翻。", "萬方鈞疾痛，三紀被仁恩。", "氣象河山慘，光華日月昏。", "小臣忠未效，飲泣望崑崙。"]'),
('346f7bc4-8395-455f-961a-5d3bd332c9db','縣圃刈禾','韋驤','宋','宋诗','song-poetry','','[]','林下圭田一畝餘，春耕秋斂亦勤渠。',64,'全唐诗/poet.song.41000.json','["林下圭田一畝餘，春耕秋斂亦勤渠。", "年豐獨喜能鈞衆，月給誰咍薄助吾。", "已愧拔葵賢魯相，更羞塵甑誦萊蕪。", "字民固合知民事，稼穡艱難坐可圖。"]'),
('0a38971a-eb67-4a6d-a5a6-f84bb373e2ed','答吕秀才','韋驤','宋','宋诗','song-poetry','','[]','惻微賙急意雖完，勢力錙銖豈自安。',64,'全唐诗/poet.song.41000.json','["惻微賙急意雖完，勢力錙銖豈自安。", "畎畝君憂家計迫，風波我畏宦途難。", "敝衣非不憐原憲，塵甑其如類范丹。", "情禮甚勤無以謝，愧将珉石報琅玕。"]'),
('075dd3b0-ca93-4bd0-932f-a6916ba2fcf0','答顔長道見寄','韋驤','宋','宋诗','song-poetry','','[]','花溪前日還轅處，惆悵高賢又阻陪。',64,'全唐诗/poet.song.41000.json','["花溪前日還轅處，惆悵高賢又阻陪。", "山雨在雲方慘淡，野烟籠水正低徊。", "别離輕似風飄絮，遲想多於渴望梅。", "胸腹殷勤豈無感，果然緘寄好詩來。"]'),
('1241cf40-6fe4-462e-a6f0-17a76ca8ea2a','同邑簿檢視堤柳乘興游保壽僧舍','韋驤','宋','宋诗','song-poetry','','[]','撥置簿書看種柳，等閒聯轡入雲岐。',32,'全唐诗/poet.song.41000.json','["撥置簿書看種柳，等閒聯轡入雲岐。", "山僧莫道疏迎候，我輩行行不自知。"]'),
('0d2dd9c0-1730-48d5-9678-7a1f92562bcc','過紫霄宫','韋驤','宋','宋诗','song-poetry','','[]','先春曾宿紫霄宫，今日重遊春正融。',32,'全唐诗/poet.song.41000.json','["先春曾宿紫霄宫，今日重遊春正融。", "誰道居官便跧縮，也能偷暇向忙中。"]'),
('2e403612-306a-4b00-bbc5-1a01c1ad3622','遊壽山','韋驤','宋','宋诗','song-poetry','','[]','暫離簿領來鄰邑，旋訪靈蹤到壽山。',32,'全唐诗/poet.song.41000.json','["暫離簿領來鄰邑，旋訪靈蹤到壽山。", "乘閑一遊真未易，豈論身寄此中閒。"]'),
('ad2b3730-027d-4772-8275-d9701631dd71','下山復題二首  其一','韋驤','宋','宋诗','song-poetry','','[]','頫望羣峰目已驚，山僧更解說山情。',32,'全唐诗/poet.song.41000.json','["頫望羣峰目已驚，山僧更解說山情。", "夕陽歸去心難足，未聽飛泉雨後聲。"]'),
('b193fe39-b3e5-42d3-b651-675fbcb6cb6b','下山復題二首  其二','韋驤','宋','宋诗','song-poetry','','[]','宛轉松蹊入五峰，更臨危閣半晴空。',32,'全唐诗/poet.song.41000.json','["宛轉松蹊入五峰，更臨危閣半晴空。", "山花鳥語皆真趣，誰是韜光傲世翁。"]'),
('64049bca-afab-457d-93b1-7ad9ce17b729','望方巖','韋驤','宋','宋诗','song-poetry','','[]','路過方巖未及遊，肩輿回首興難收。',32,'全唐诗/poet.song.41000.json','["路過方巖未及遊，肩輿回首興難收。", "野桃带日遙相笑，笑我山情不自由。"]'),
('4e19abb0-0198-4d42-b35b-3627e5f3bd33','宿靈巖  其一','韋驤','宋','宋诗','song-poetry','','[]','坐邑傳聞此巖好，心疑好事張浮辭。',64,'全唐诗/poet.song.41000.json','["坐邑傳聞此巖好，心疑好事張浮辭。", "及來勝境窮遊覽，却悟前言有漏遺。", "觸石烟雲如障俗，倚崖殿閣半乘危。", "自嗟吏治多牽制，祇作清虚一宿期。"]'),
('6207df2e-96dc-4b06-be19-789b8a04920a','宿靈巖  其二','韋驤','宋','宋诗','song-poetry','','[]','百丈蒼巖入杳冥，高低氣象本天成。',64,'全唐诗/poet.song.41000.json','["百丈蒼巖入杳冥，高低氣象本天成。", "藤蟠翠壁龍蛇動，澗瀉斷崖風雨聲。", "不許畫工爲潤色，祇應詩伯長餘情。", "栖鴉亂墨題僧室，車馬何時再此行。"]'),
('2aa0c938-03a8-4562-84ac-d2c4387ca10a','自靈巖回途中寄顔令','韋驤','宋','宋诗','song-poetry','','[]','吏役誰嬰繞，尋幽得二三。',48,'全唐诗/poet.song.41000.json','["吏役誰嬰繞，尋幽得二三。", "穿雲離古觀，冒月宿靈巖。", "乘興詩何擇，孤遊語自緘。", "寄言酬地主，清賞可無慚。"]'),
('7e8a9168-c008-4171-bb4b-475541e9533b','冒雨遊石室','韋驤','宋','宋诗','song-poetry','','[]','陟磴苔痕滑，穿巖雨脚收。',24,'全唐诗/poet.song.41000.json','["陟磴苔痕滑，穿巖雨脚收。", "愛山鄰邑令，來作雨中遊。"]'),
('a90ab0a3-6c72-4f2c-acdb-7b7528ef40bf','雞人峰','韋驤','宋','宋诗','song-poetry','','[]','石室前頭一片春，天然形象附嶙峋。',32,'全唐诗/poet.song.41000.json','["石室前頭一片春，天然形象附嶙峋。", "山家况味無晨夕，安用雞人賦此身。"]'),
('eb73c2a6-21da-41f6-bf96-3b74175c8e0b','雨止','韋驤','宋','宋诗','song-poetry','','[]','雨止單蹊步可通，尋春天氣似迎逢。',64,'全唐诗/poet.song.41000.json','["雨止單蹊步可通，尋春天氣似迎逢。", "山花有意飄行蓋，野水無情照瘦容。", "挈榼竟難成獨飲，抽毫猶得當朋從。", "逡巡且盡今朝興，數闔歸來趁暮鐘。"]'),
('2153e8c1-c1a3-4dd9-93aa-98df9157a8db','曉霽歸邑','韋驤','宋','宋诗','song-poetry','','[]','夜枕輕寒睡思衰，遲明方霽促歸來。',64,'全唐诗/poet.song.41000.json','["夜枕輕寒睡思衰，遲明方霽促歸來。", "車徒雖患泥行蹇，林麓還逢秀色迴。", "山雨定非天意足，溪雲應爲主人開。", "野花零亂春禽閙，此興何如鼓吹陪。"]'),
('b5578618-5a0f-48aa-940d-c1b36b79d23c','戲别顔令','韋驤','宋','宋诗','song-poetry','','[]','趣馭不遑辭地主，趁晴唯且荷天公。',32,'全唐诗/poet.song.41000.json','["趣馭不遑辭地主，趁晴唯且荷天公。", "縣楼歸去勞東望，早就新篇寄好風。"]'),
('66237bb7-f0af-4260-99ac-f207b8216f35','將及熟溪','韋驤','宋','宋诗','song-poetry','','[]','東風吹散黑雲輕，漸望吾疆野色青。',32,'全唐诗/poet.song.41000.json','["東風吹散黑雲輕，漸望吾疆野色青。", "料得熟溪灘響急，到時聊爲駐軒聽。"]'),
('1de3e5eb-ed52-4d24-aeb6-601e6ea61ff3','村落','韋驤','宋','宋诗','song-poetry','','[]','輕寒切切戰春陽，村落人家意自遑。',64,'全唐诗/poet.song.41000.json','["輕寒切切戰春陽，村落人家意自遑。", "老婦畫眉窺止水，癡兒曝背坐頹墻。", "牛歸小徑蹄痕疊，犬吠空山響答長。", "夏賦未來秋賦了，片時優佚勝膏梁。"]');
